import React, { useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, Legend, ReferenceLine } from 'recharts';
import { Employee, TrainingRecord } from '../types';
import { getDeptColor, NR_COURSES } from '../constants';
import { getDaysRemaining } from '../utils/calculations';

interface DashboardProps {
  employees: Employee[];
  onRefresh?: () => void;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-gray-100 min-w-[220px] animate-fadeIn">
        <p className="font-black text-gray-900 mb-3 border-b border-gray-100 pb-2 text-xs uppercase tracking-wider">{label}</p>
        <div className="space-y-2">
          {payload.map((entry: any, index: number) => (
            <div key={index} className="flex justify-between items-center gap-4">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full shadow-sm" style={{ backgroundColor: entry.color }}></div>
                <span className="font-bold text-gray-500 text-[10px] uppercase tracking-tight">{entry.name}</span>
              </div>
              <span className="font-black text-gray-900 text-sm">{entry.value}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees }) => {
  const stats = useMemo(() => {
    const s = { trained: 0, expiring: 0, expired: 0, none: 0 };
    const deptStats: Record<string, { total: number, valid: number, expiring: number, expired: number }> = {};
    const courseStats: Record<string, { valid: number, expiring: number, expired: number, total: number }> = {};
    const alert15: any[] = [];
    const alert30: any[] = [];
    const alert60: any[] = [];

    // Inicializar stats de cursos
    NR_COURSES.forEach(c => {
      courseStats[c.id] = { valid: 0, expiring: 0, expired: 0, total: 0 };
    });

    employees.forEach(emp => {
      const dept = emp.department || 'Não Definido';
      if (!deptStats[dept]) {
        deptStats[dept] = { total: 0, valid: 0, expiring: 0, expired: 0 };
      }
      deptStats[dept].total++;

      Object.entries(emp.trainings).forEach(([cid, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (!courseStats[cid]) return;
        courseStats[cid].total++;

        if (record.status === 'VALID') { 
          s.trained++; 
          deptStats[dept].valid++; 
          courseStats[cid].valid++;
        }
        else if (record.status === 'EXPIRING') { 
          s.expiring++; 
          deptStats[dept].expiring++;
          courseStats[cid].expiring++;
          const alertObj = { emp, cid, days, expiryDate: record.expiryDate };
          if (days !== null && days <= 15) alert15.push(alertObj);
          else if (days !== null && days <= 30) alert30.push(alertObj);
          else alert60.push(alertObj);
        }
        else if (record.status === 'EXPIRED') { 
          s.expired++; 
          deptStats[dept].expired++; 
          courseStats[cid].expired++;
        }
        else {
          s.none++;
        }
      });
    });

    return { s, deptStats, courseStats, alerts: { a15: alert15, a30: alert30, a60: alert60 } };
  }, [employees]);

  const chartData = Object.entries(stats.deptStats).map(([name, data]: [string, any]) => ({
    name,
    Válidos: data.valid,
    Vencendo: data.expiring,
    Vencidos: data.expired,
    Total: data.total,
    fill: getDeptColor(name)
  }));

  const courseData = Object.entries(stats.courseStats)
    .filter(([_, data]) => data.total > 0)
    .map(([id, data]) => ({
      id,
      ...data,
      percentValid: Math.round((data.valid / data.total) * 100)
    }))
    .sort((a, b) => a.percentValid - b.percentValid);

  return (
    <div className="space-y-10 pb-20 animate-fadeIn">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tighter italic">
            Dashboard <span className="text-green-600">SST Intel</span>
          </h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.2em] mt-1">Análise de Performance e Conformidade Normativa</p>
        </div>
      </header>

      {/* Indicadores Principais */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cursos Válidos', val: stats.s.trained, color: 'text-green-600', bg: 'bg-green-50', icon: '🛡️' },
          { label: 'Em Reciclagem', val: stats.s.expiring, color: 'text-amber-500', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Cursos Vencidos', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Equipe Ativa', val: employees.length, color: 'text-blue-600', bg: 'bg-blue-50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 hover:shadow-xl hover:shadow-gray-200/50 transition-all duration-500">
            <div className="flex justify-between items-start">
              <span className={`text-2xl p-4 rounded-2xl ${item.bg}`}>{item.icon}</span>
              <span className={`text-5xl font-black tracking-tighter ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">{item.label}</p>
          </div>
        ))}
      </div>

      {/* Seção Gráficos Principais */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-gray-100 group">
          <div className="flex justify-between items-end mb-10">
            <div>
              <h3 className="text-xl font-black text-gray-800">Censo por Departamento</h3>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Volume de colaboradores por área</p>
            </div>
            <div className="text-right">
              <span className="text-xs font-black text-green-600 bg-green-50 px-3 py-1 rounded-full uppercase">Top Área</span>
            </div>
          </div>
          <div className="h-[400px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 0, right: 10, left: -20, bottom: 60 }}>
                <CartesianGrid strokeDasharray="8 8" vertical={false} stroke="#f8fafc" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#64748b', fontSize: 9, fontWeight: 800}}
                  angle={-30}
                  textAnchor="end"
                  interval={0}
                />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <Tooltip cursor={{fill: '#f1f5f9', radius: 10}} content={<CustomTooltip />} />
                <Bar 
                  dataKey="Total" 
                  radius={[12, 12, 12, 12]} 
                  barSize={32}
                  isAnimationActive={true}
                  animationDuration={1800}
                >
                  {chartData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.fill} fillOpacity={0.9} />
                  ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-gray-100">
          <div className="flex justify-between items-end mb-10">
            <div>
              <h3 className="text-xl font-black text-gray-800">Conformidade Operacional</h3>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Status de Treinamentos Agrupado</p>
            </div>
          </div>
          <div className="h-[400px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} margin={{ top: 0, right: 10, left: -20, bottom: 60 }}>
                <CartesianGrid strokeDasharray="8 8" vertical={false} stroke="#f8fafc" />
                <XAxis 
                  dataKey="name" 
                  axisLine={false} 
                  tickLine={false} 
                  tick={{fill: '#64748b', fontSize: 9, fontWeight: 800}}
                  angle={-30}
                  textAnchor="end"
                  interval={0}
                />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10}} />
                <Tooltip cursor={{fill: '#f1f5f9', radius: 10}} content={<CustomTooltip />} />
                <Legend verticalAlign="top" align="right" height={40} iconType="circle" wrapperStyle={{fontSize: '9px', fontWeight: '900', textTransform: 'uppercase', paddingBottom: '20px'}} />
                <Bar dataKey="Válidos" stackId="a" fill="#10B981" barSize={32} radius={[0, 0, 0, 0]} />
                <Bar dataKey="Vencendo" stackId="a" fill="#F59E0B" />
                <Bar dataKey="Vencidos" stackId="a" fill="#EF4444" radius={[12, 12, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      {/* NOVA SEÇÃO: Status Geral por Curso */}
      <div className="bg-white p-10 rounded-[3.5rem] shadow-sm border border-gray-100">
        <div className="mb-10">
          <h3 className="text-2xl font-black text-gray-800">Raio-X por Norma (NR)</h3>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Visão holística da saúde de cada treinamento</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {courseData.map((course) => (
            <div key={course.id} className="bg-gray-50/50 p-5 rounded-3xl border border-gray-100 hover:bg-white hover:shadow-lg transition-all duration-300 group">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="font-black text-gray-800 text-sm group-hover:text-green-700 transition-colors">{course.id}</h4>
                  <p className="text-[9px] font-bold text-gray-400 uppercase tracking-tight">Total: {course.total} Capacitados</p>
                </div>
                <div className="text-right">
                  <span className={`text-xs font-black ${course.percentValid > 80 ? 'text-green-600' : course.percentValid > 50 ? 'text-amber-600' : 'text-red-600'}`}>
                    {course.percentValid}%
                  </span>
                </div>
              </div>

              <div className="flex gap-1 h-2 w-full bg-gray-200 rounded-full overflow-hidden mb-3">
                <div style={{ width: `${(course.valid / course.total) * 100}%` }} className="bg-green-500 h-full"></div>
                <div style={{ width: `${(course.expiring / course.total) * 100}%` }} className="bg-amber-400 h-full"></div>
                <div style={{ width: `${(course.expired / course.total) * 100}%` }} className="bg-red-500 h-full"></div>
              </div>

              <div className="flex justify-between text-[8px] font-black uppercase tracking-widest text-gray-400">
                <span className="text-green-600">{course.valid} OK</span>
                <span className="text-amber-600">{course.expiring} VENCENDO</span>
                <span className="text-red-600">{course.expired} VENCIDOS</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Alertas */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {[
          { title: 'Janela Crítica (15 dias)', data: stats.alerts.a15, color: 'border-red-500', bg: 'bg-red-500', text: 'text-red-700' },
          { title: 'Reciclagem Urgente (30 dias)', data: stats.alerts.a30, color: 'border-amber-500', bg: 'bg-amber-500', text: 'text-amber-700' },
          { title: 'Plano de Ação (60 dias)', data: stats.alerts.a60, color: 'border-blue-500', bg: 'bg-blue-500', text: 'text-blue-700' },
        ].map((alert, idx) => (
          <div key={idx} className={`bg-white rounded-[2.5rem] border-l-[10px] ${alert.color} shadow-sm overflow-hidden hover:shadow-lg transition-all`}>
            <div className={`p-5 ${alert.bg} text-white font-black text-[10px] uppercase tracking-widest flex justify-between items-center`}>
               {alert.title}
               <span className="bg-white/30 backdrop-blur-md px-3 py-1 rounded-full text-[11px]">{alert.data.length}</span>
            </div>
            <div className="p-5 space-y-4 max-h-72 overflow-y-auto custom-scrollbar">
              {alert.data.length === 0 ? (
                <div className="flex flex-col items-center py-8 opacity-20">
                  <span className="text-3xl mb-2">✅</span>
                  <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Tudo em conformidade</p>
                </div>
              ) : (
                alert.data.map((item, i) => (
                  <div key={i} className="flex justify-between items-start border-b border-gray-50 pb-3 group">
