                      <p className="text-[9px] font-bold text-gray-400 uppercase">{item.cid} • {item.emp.department}</p>
                    </div>
                    <div className="text-right">
                      <p className={`text-[11px] font-black ${alert.text}`}>{item.days}D</p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ))}
