            <div>
              <h3 className="text-xl font-black text-gray-800">Conformidade Operacional</h3>
              <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Status de Treinamentos Agrupado</p>
            </div>
          </div>
          <div className="h-[400px]">
