  const days = getDaysRemaining(record.expiryDate);

  const formatDate = (date?: string) => {
    if (!date) return 'Não definida';
    return new Date(date).toLocaleDateString('pt-BR');
  };

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className={`px-4 py-2 rounded-xl text-[10px] font-black border flex items-center gap-2 cursor-help transition-all duration-300 ${cfg.bg} ${cfg.text} border-black/5 hover:scale-105 hover:shadow-md`}>
        <span className={`w-2 h-2 rounded-full shadow-sm ${cfg.color}`}></span>
        {courseId}
      </div>

      {isHovered && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 z-[60] w-64 p-5 bg-gray-900 text-white rounded-[1.5rem] shadow-2xl animate-fadeIn border border-white/10">
