            <header className="flex justify-between items-center border-b border-white/10 pb-2 mb-2">
              <span className="text-[9px] font-black text-green-400 uppercase tracking-widest">{courseId}</span>
              <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${cfg.bg} ${cfg.text}`}>
                {cfg.label}
              </span>
            </header>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-[8px] text-gray-400 font-bold uppercase mb-1">Conclusão</p>
                <p className="text-[10px] font-black">{formatDate(record.completionDate)}</p>
              </div>
              <div>
                <p className="text-[8px] text-gray-400 font-bold uppercase mb-1">Vencimento</p>
                <p className="text-[10px] font-black">{formatDate(record.expiryDate)}</p>
              </div>
            </div>

            {record.expiryDate && (
              <div className="bg-white/5 p-2.5 rounded-xl border border-white/5">
                <p className={`text-[10px] font-black uppercase text-center ${days !== null && days < 0 ? 'text-red-400' : 'text-amber-400'}`}>
                  {days !== null ? (
                    days < 0 ? `Vencido há ${Math.abs(days)} dias` : `Vence em ${days} dias`
                  ) : 'Sem expiração'}
                </p>
              </div>
            )}
          </div>
          {/* Arrow */}
          <div className="absolute top-full left-1/2 -translate-x-1/2 w-3 h-3 bg-gray-900 rotate-45 -mt-1.5 border-r border-b border-white/10"></div>
        </div>
      )}
    </div>
  );
};

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDept, setSelectedDept] = useState('Todos');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const departments = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => e.department)))], [employees]);

  const filtered = employees.filter(e => {
    const matchesSearch = e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.registration.includes(searchTerm);
    const matchesDept = selectedDept === 'Todos' || e.department === selectedDept;
    return matchesSearch && matchesDept;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp) return;
    await StorageService.updateEmployee(editingEmp);
    setEditingEmp(null);
    onUpdate();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este funcionário?')) {
      await StorageService.deleteEmployee(id);
      onUpdate();
    }
  };

  const createNewEmployee = () => {
    const newEmp: Employee = {
      id: `emp-${Date.now()}`,
      name: '',
      registration: '',
      role: '',
      department: '',
      trainings: {}
    };
    setEditingEmp(newEmp);
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;

    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);

    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };

    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn">
      {/* Cabeçalho de Ações */}
