const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-gray-100 min-w-[220px] animate-fadeIn z-[100]">
        <p className="font-black text-gray-900 mb-3 border-b border-gray-100 pb-2 text-xs uppercase tracking-wider">{label}</p>
        <div className="space-y-2">
          {payload.map((entry: any, index: number) => (
            <div key={index} className="flex justify-between items-center gap-4">
              <div className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full shadow-sm" style={{ backgroundColor: entry.color }}></div>
                <span className="font-bold text-gray-500 text-[10px] uppercase tracking-tight">{entry.name}</span>
              </div>
              <span className="font-black text-gray-900 text-sm">{entry.value}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees }) => {
  const stats = useMemo(() => {
    const s = { trained: 0, expiring: 0, expired: 0, none: 0 };
    const deptStats: Record<string, { total: number, valid: number, expiring: number, expired: number }> = {};
    const courseStats: Record<string, { valid: number, expiring: number, expired: number, total: number }> = {};
    const alert15: any[] = [];
    const alert30: any[] = [];
    const alert60: any[] = [];

    NR_COURSES.forEach(c => {
      courseStats[c.id] = { valid: 0, expiring: 0, expired: 0, total: 0 };
    });

    employees.forEach(emp => {
      const dept = emp.department || 'Não Definido';
      if (!deptStats[dept]) {
        deptStats[dept] = { total: 0, valid: 0, expiring: 0, expired: 0 };
      }
      deptStats[dept].total++;

      Object.entries(emp.trainings).forEach(([cid, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (!courseStats[cid]) return;
        courseStats[cid].total++;

        if (record.status === 'VALID') { 
          s.trained++; 
          deptStats[dept].valid++; 
          courseStats[cid].valid++;
        }
        else if (record.status === 'EXPIRING') { 
          s.expiring++; 
          deptStats[dept].expiring++;
          courseStats[cid].expiring++;
          const alertObj = { emp, cid, days, expiryDate: record.expiryDate };
          if (days !== null && days <= 15) alert15.push(alertObj);
          else if (days !== null && days <= 30) alert30.push(alertObj);
          else alert60.push(alertObj);
        }
        else if (record.status === 'EXPIRED') { 
          s.expired++; 
          deptStats[dept].expired++; 
          courseStats[cid].expired++;
        }
        else {
          s.none++;
        }
      });
    });

    return { s, deptStats, courseStats, alerts: { a15: alert15, a30: alert30, a60: alert60 } };
  }, [employees]);

  const chartData = Object.entries(stats.deptStats).map(([name, data]: [string, any]) => ({
    name,
    Válidos: data.valid,
    Vencendo: data.expiring,
    Vencidos: data.expired,
    Total: data.total,
    fill: getDeptColor(name)
  })).sort((a, b) => b.Total - a.Total);

  const courseData = (Object.entries(stats.courseStats) as [string, any][])
    .filter(([_, data]) => data.total > 0)
    .map(([id, data]) => ({
      id,
      ...data,
      percentValid: Math.round((data.valid / data.total) * 100)
    }))
    .sort((a, b) => a.percentValid - b.percentValid);

