          </div>
        </div>
      </div>

      <div className="bg-white p-10 rounded-[3.5rem] shadow-sm border border-gray-100">
        <div className="mb-10">
          <h3 className="text-2xl font-black text-gray-800">Raio-X por Norma (NR)</h3>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Visão holística da saúde de cada treinamento</p>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {courseData.map((course) => (
            <div key={course.id} className="bg-gray-50/50 p-5 rounded-3xl border border-gray-100 hover:bg-white hover:shadow-lg transition-all duration-300 group">
              <div className="flex justify-between items-start mb-4">
                <div>
                  <h4 className="font-black text-gray-800 text-sm group-hover:text-green-700 transition-colors">{course.id}</h4>
                  <p className="text-[9px] font-bold text-gray-400 uppercase tracking-tight">Total: {course.total} funcionários</p>
                </div>
                <div className="text-right">
                  <span className={`text-xs font-black ${course.percentValid > 80 ? 'text-green-600' : course.percentValid > 50 ? 'text-amber-600' : 'text-red-600'}`}>
                    {course.percentValid}%
                  </span>
                </div>
              </div>

              <div className="flex gap-1 h-2 w-full bg-gray-200 rounded-full overflow-hidden mb-3">
                <div style={{ width: `${(course.valid / course.total) * 100}%` }} className="bg-green-500 h-full"></div>
                <div style={{ width: `${(course.expiring / course.total) * 100}%` }} className="bg-amber-400 h-full"></div>
                <div style={{ width: `${(course.expired / course.total) * 100}%` }} className="bg-red-500 h-full"></div>
              </div>

              <div className="flex justify-between text-[8px] font-black uppercase tracking-widest text-gray-400">
                <span className="text-green-600">{course.valid} OK</span>
                <span className="text-amber-600">{course.expiring} VENCENDO</span>
                <span className="text-red-600">{course.expired} VENCIDOS</span>
              </div>
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        {[
          { title: 'Janela Crítica (15 dias)', data: stats.alerts.a15, color: 'border-red-500', bg: 'bg-red-500', text: 'text-red-700' },
          { title: 'Reciclagem Urgente (30 dias)', data: stats.alerts.a30, color: 'border-amber-500', bg: 'bg-amber-500', text: 'text-amber-700' },
          { title: 'Plano de Ação (60 dias)', data: stats.alerts.a60, color: 'border-blue-500', bg: 'bg-blue-50', text: 'text-blue-700' },
        ].map((alert, idx) => (
          <div key={idx} className={`bg-white rounded-[2.5rem] border-l-[10px] ${alert.color} shadow-sm overflow-hidden hover:shadow-lg transition-all`}>
            <div className={`p-5 ${alert.bg} text-white font-black text-[10px] uppercase tracking-widest flex justify-between items-center`}>
               {alert.title}
               <span className="bg-white/30 backdrop-blur-md px-3 py-1 rounded-full text-[11px]">{alert.data.length}</span>
            </div>
            <div className="p-5 space-y-4 max-h-72 overflow-y-auto custom-scrollbar">
              {alert.data.length === 0 ? (
                <div className="flex flex-col items-center py-8 opacity-20">
                  <span className="text-3xl mb-2">✅</span>
                  <p className="text-[10px] font-black uppercase tracking-widest text-gray-400">Tudo em conformidade</p>
                </div>
              ) : (
                alert.data.map((item, i) => (
                  <div key={i} className="flex justify-between items-start border-b border-gray-50 pb-3 group">
                    <div>
                      <p className="text-[11px] font-black text-gray-800 group-hover:text-green-700 transition-colors">{item.emp.name}</p>
                      <p className="text-[9px] font-bold text-gray-400 uppercase">{item.cid} • {item.emp.department}</p>
                    </div>
                    <div className="text-right">
                      <p className={`text-[11px] font-black ${alert.text}`}>{item.days}D</p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee, TrainingRecord } from '../types';
import { STATUS_CONFIG, NR_COURSES, getDeptColor } from '../constants';
import { getDaysRemaining, calculateTrainingStatus, getExpiryDate } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
}

const NRBadge: React.FC<{ courseId: string; record: TrainingRecord }> = ({ courseId, record }) => {
  const [isHovered, setIsHovered] = useState(false);
  const cfg = STATUS_CONFIG[record.status];
  const days = getDaysRemaining(record.expiryDate);

  const formatDate = (date?: string) => {
    if (!date) return 'Não definida';
    return new Date(date).toLocaleDateString('pt-BR');
  };

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className={`px-4 py-2 rounded-xl text-[10px] font-black border flex items-center gap-2 cursor-help transition-all duration-300 ${cfg.bg} ${cfg.text} border-black/5 hover:scale-105 hover:shadow-md`}>
        <span className={`w-2 h-2 rounded-full shadow-sm ${cfg.color}`}></span>
        {courseId}
      </div>

      {isHovered && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 z-[100] w-64 p-5 bg-gray-900 text-white rounded-[1.5rem] shadow-2xl animate-fadeIn border border-white/10">
          <div className="space-y-3">
            <header className="flex justify-between items-center border-b border-white/10 pb-2 mb-2">
              <span className="text-[9px] font-black text-green-400 uppercase tracking-widest">{courseId}</span>
              <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${cfg.bg} ${cfg.text}`}>
                {cfg.label}
              </span>
            </header>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-[8px] text-gray-400 font-bold uppercase mb-1">Conclusão</p>
                <p className="text-[10px] font-black">{formatDate(record.completionDate)}</p>
              </div>
              <div>
                <p className="text-[8px] text-gray-400 font-bold uppercase mb-1">Vencimento</p>
                <p className="text-[10px] font-black">{formatDate(record.expiryDate)}</p>
              </div>
            </div>

            {record.expiryDate && (
              <div className="bg-white/5 p-2.5 rounded-xl border border-white/5">
                <p className={`text-[10px] font-black uppercase text-center ${days !== null && days < 0 ? 'text-red-400' : 'text-amber-400'}`}>
                  {days !== null ? (
                    days < 0 ? `Vencido há ${Math.abs(days)} dias` : `Vence em ${days} dias`
                  ) : 'Sem expiração'}
                </p>
              </div>
            )}
          </div>
          <div className="absolute top-full left-1/2 -translate-x-1/2 w-3 h-3 bg-gray-900 rotate-45 -mt-1.5 border-r border-b border-white/10"></div>
        </div>
      )}
    </div>
  );
};

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDept, setSelectedDept] = useState('Todos');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const departments = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => e.department)))], [employees]);

  const filtered = employees.filter(e => {
    const matchesSearch = e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.registration.includes(searchTerm);
    const matchesDept = selectedDept === 'Todos' || e.department === selectedDept;
    return matchesSearch && matchesDept;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp) return;
    await StorageService.updateEmployee(editingEmp);
    setEditingEmp(null);
    onUpdate();
  };

  const handleDelete = async (id: string) => {
    if (window.confirm('Tem certeza que deseja excluir este funcionário?')) {
      await StorageService.deleteEmployee(id);
      onUpdate();
    }
  };

  const createNewEmployee = () => {
    const newEmp: Employee = {
      id: `emp-${Date.now()}`,
      name: '',
      registration: '',
      role: '',
      department: '',
      trainings: {}
    };
    setEditingEmp(newEmp);
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;

    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);

    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };

    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800">Gestão de <span className="text-green-600 italic">Equipe</span></h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mt-1">Controle Individual de Proficiências</p>
        </div>
        <button 
          onClick={createNewEmployee}
          className="bg-[#064E3B] text-white px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-green-900/20 hover:scale-105 transition-all flex items-center gap-3"
        >
          <span>➕ Cadastrar Integrante</span>
        </button>
      </div>

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-6 rounded-[2.5rem] border border-gray-100 shadow-sm">
        <div className="flex flex-wrap items-center gap-6 flex-1">
          <div className="flex flex-col min-w-[150px]">
            <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 tracking-widest italic">Departamento</label>
            <select 
              value={selectedDept}
              onChange={(e) => setSelectedDept(e.target.value)}
              className="bg-gray-50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-gray-700 outline-none focus:bg-white focus:border-green-500 transition-all shadow-inner"
            >
              {departments.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
          </div>
          <div className="flex flex-col flex-1 min-w-[250px]">
            <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 tracking-widest italic">Filtro Rápido</label>
            <input 
              type="text" 
              placeholder="Pesquisar por nome, CPF ou matrícula..." 
              className="w-full px-5 py-3 bg-gray-50 border-2 border-transparent rounded-2xl text-xs font-bold focus:bg-white focus:border-green-500 outline-none transition-all shadow-inner"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-5">
        {filtered.map(emp => (
          <div key={emp.id} className="bg-white rounded-[2.5rem] border border-gray-100 hover:border-green-300 transition-all shadow-sm group">
            <div className="p-6 flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div className="flex items-center gap-5">
                <div className="w-16 h-16 text-white rounded-[1.8rem] flex items-center justify-center font-black text-xl shadow-lg relative overflow-hidden bg-gray-100" style={!emp.photoUrl ? { backgroundColor: getDeptColor(emp.department) } : {}}>
                  {!emp.photoUrl ? (
                    <>
                      <div className="absolute inset-0 bg-black/10"></div>
                      <span className="relative z-10">{emp.name.charAt(0) || '?'}</span>
                    </>
                  ) : (
                    <img src={emp.photoUrl} alt={emp.name} className="w-full h-full object-cover" onError={(e) => { (e.target as any).style.display = 'none' }} />
                  )}
                </div>
                <div>
                  <h3 className="text-lg font-black text-gray-800 leading-none mb-1 uppercase tracking-tight">{emp.name || 'Sem Identificação'}</h3>
                  <p className="text-[10px] text-gray-500 font-bold uppercase tracking-tight">
                    MAT: {emp.registration} • {emp.role} • <span className="font-black px-2 py-0.5 rounded-full bg-gray-50" style={{ color: getDeptColor(emp.department) }}>{emp.department}</span>
                  </p>
                </div>
              </div>

              <div className="flex gap-3">
                <button 
                  onClick={() => setEditingEmp(emp)}
                  className="bg-green-50 text-green-700 px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-[0.1em] hover:bg-green-600 hover:text-white transition-all duration-300 shadow-sm"
                >
                  Editar Cadastro 📝
                </button>
                <button 
                  onClick={() => handleDelete(emp.id)}
                  className="bg-red-50 text-red-600 px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-[0.1em] hover:bg-red-500 hover:text-white transition-all duration-300"
                >
                  Remover 🗑️
                </button>
              </div>
            </div>

            <div className="px-6 pb-6 flex flex-wrap gap-3 border-t border-gray-50 pt-5">
              {NR_COURSES.map(course => {
                const t = emp.trainings[course.id];
                if (!t || t.status === 'NOT_TRAINED') return null;
                return (
                  <NRBadge key={course.id} courseId={course.id} record={t} />
                );
              })}
              {Object.values(emp.trainings).every((t: any) => t.status === 'NOT_TRAINED') && (
                <p className="text-[9px] text-gray-300 font-black uppercase italic tracking-widest py-2">Nenhum treinamento vinculado</p>
              )}
            </div>
          </div>
        ))}
      </div>

      {editingEmp && (
        <div className="fixed inset-0 bg-black/70 backdrop-blur-md z-[1000] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl max-h-[92vh] rounded-[3.5rem] shadow-2xl overflow-hidden flex flex-col animate-fadeIn border border-white/20">
            <header className="p-10 border-b flex justify-between items-center bg-gray-50/50">
              <div>
                <h3 className="text-2xl font-black text-gray-800">Formulário de <span className="text-green-600 italic">SST</span></h3>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Configuração de Perfil e Treinamentos</p>
              </div>
              <button onClick={() => setEditingEmp(null)} className="w-12 h-12 flex items-center justify-center bg-gray-100 rounded-full hover:bg-red-50 hover:text-red-500 transition-all font-black">✕</button>
            </header>

            <form onSubmit={handleSaveEdit} className="flex-1 overflow-y-auto p-10 space-y-10 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2 italic">Nome do Funcionário</label>
                  <input required type="text" className="w-full bg-gray-50 border-2 border-gray-100 rounded-[1.5rem] p-4 font-black text-sm focus:border-green-500 focus:bg-white outline-none transition-all shadow-inner" value={editingEmp.name} onChange={e => setEditingEmp({...editingEmp, name: e.target.value})} />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2 italic">URL da Foto</label>
                  <input type="text" className="w-full bg-gray-50 border-2 border-gray-100 rounded-[1.5rem] p-4 font-black text-sm focus:border-green-500 focus:bg-white outline-none transition-all shadow-inner" placeholder="Link da imagem (opcional)" value={editingEmp.photoUrl || ''} onChange={e => setEditingEmp({...editingEmp, photoUrl: e.target.value})} />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2 italic">Nº Matrícula / RE</label>
                  <input required type="text" className="w-full bg-gray-50 border-2 border-gray-100 rounded-[1.5rem] p-4 font-black text-sm focus:border-green-500 focus:bg-white outline-none transition-all shadow-inner" value={editingEmp.registration} onChange={e => setEditingEmp({...editingEmp, registration: e.target.value})} />
                </div>
                <div className="space-y-3">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2 italic">Cargo Ocupacional</label>
                  <input required type="text" className="w-full bg-gray-50 border-2 border-gray-100 rounded-[1.5rem] p-4 font-black text-sm focus:border-green-500 focus:bg-white outline-none transition-all shadow-inner" value={editingEmp.role} onChange={e => setEditingEmp({...editingEmp, role: e.target.value})} />
                </div>
                <div className="md:col-span-2 space-y-3">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2 italic">Setor Operacional</label>
                  <input required type="text" className="w-full bg-gray-50 border-2 border-gray-100 rounded-[1.5rem] p-4 font-black text-sm focus:border-green-500 focus:bg-white outline-none transition-all shadow-inner" value={editingEmp.department} onChange={e => setEditingEmp({...editingEmp, department: e.target.value})} />
                </div>
              </div>

              <div className="pt-10 border-t border-gray-100">
                <div className="mb-8">
                  <h4 className="text-sm font-black text-gray-800 uppercase tracking-[0.3em] italic">Matriz de Treinamentos (NRs)</h4>
                  <p className="text-[9px] font-bold text-gray-400 mt-1 uppercase tracking-widest">Insira a data do certificado mais recente</p>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {NR_COURSES.map(course => (
                    <div key={course.id} className="bg-gray-50/50 p-5 rounded-[2rem] border border-gray-100 hover:border-green-200 transition-all">
                      <label className="block text-[9px] font-black text-gray-500 uppercase mb-3 tracking-wider">{course.name}</label>
                      <input type="date" className="w-full bg-white border-2 border-gray-200 rounded-xl p-3 text-xs font-black outline-none focus:border-green-500 shadow-sm" value={editingEmp.trainings[course.id]?.completionDate || ''} onChange={e => updateTrainingDate(course.id, e.target.value)} />
                    </div>
                  ))}
                </div>
              </div>
            </form>

            <footer className="p-10 border-t bg-gray-50/50 flex gap-6">
              <button type="button" onClick={() => setEditingEmp(null)} className="flex-1 py-5 text-gray-400 font-black uppercase text-[10px] tracking-widest hover:text-gray-600 transition-colors">Descartar</button>
              <button onClick={handleSaveEdit} className="flex-[2] py-5 bg-[#064E3B] text-green-400 rounded-[1.5rem] font-black text-[10px] uppercase tracking-[0.3em] shadow-2xl shadow-green-900/30 hover:scale-[1.02] transition-all">AUTORIZAR E SALVAR 💾</button>
            </footer>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeView;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import ImportData from './components/ImportData';
import ConfigView from './components/ConfigView';
import { Employee } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [userRole, setUserRole] = useState<'admin' | 'user'>('user'); // Default to user

  const isAdmin = userRole === 'admin';

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const handleImport = async (data: Employee[]) => {
    if (!isAdmin) return;
    setIsLoading(true);
    try {
      const updated = await StorageService.addEmployees(data);
      setEmployees(updated);
      setActiveTab('dashboard');
    } catch (error) {
      alert("Erro ao salvar dados.");
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4">
          <div className="w-12 h-12 border-4 border-green-100 border-t-green-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">Carregando Banco SST...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} />;
      case 'employees': return <EmployeeView employees={employees} onUpdate={loadData} isAdmin={isAdmin} />;
      case 'reports': return <Reports employees={employees} />;
      case 'import': return isAdmin ? (
        <div className="space-y-10">
           <ImportData onImport={handleImport} />
           <div className="max-w-6xl mx-auto bg-white p-8 rounded-[2.5rem] border border-gray-100 flex items-center justify-between shadow-sm">
             <div>
                <h4 className="font-black text-gray-800">Cópia de Segurança (Backup)</h4>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Baixe todos os dados para o seu computador</p>
             </div>
             <button 
                onClick={() => StorageService.downloadBackup()}
                className="bg-blue-50 text-blue-600 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-100 transition-all"
             >
                Baixar Arquivo .JSON 💾
             </button>
           </div>
        </div>
      ) : null;
      case 'config': return isAdmin ? <ConfigView onUpdate={loadData} /> : null;
      default: return <Dashboard employees={employees} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={userRole} 
      setUserRole={setUserRole}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React from 'react';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: 'admin' | 'user';
  setUserRole: (role: 'admin' | 'user') => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, setUserRole }) => {
  const isAdmin = userRole === 'admin';

  const allTabs = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', adminOnly: false },
    { id: 'employees', label: 'Funcionários', icon: '👷', adminOnly: false },
    { id: 'reports', label: 'Relatórios', icon: '📋', adminOnly: false },
    { id: 'import', label: 'Importação', icon: '📥', adminOnly: true },
    { id: 'config', label: 'Configuração', icon: '⚙️', adminOnly: true },
  ];

  const visibleTabs = allTabs.filter(tab => !tab.adminOnly || isAdmin);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#FDFDFD]">
