import React, { useState, useMemo } from 'react';
import { Employee, TrainingRecord } from '../types';
import { STATUS_CONFIG, NR_COURSES, getDeptColor } from '../constants';
import { getDaysRemaining, calculateTrainingStatus, getExpiryDate } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const NRBadge: React.FC<{ courseId: string; record: TrainingRecord }> = ({ courseId, record }) => {
  const [isHovered, setIsHovered] = useState(false);
  const cfg = STATUS_CONFIG[record.status];
  const days = getDaysRemaining(record.expiryDate);

  const formatDate = (date?: string) => {
    if (!date) return 'Não definida';
    return new Date(date).toLocaleDateString('pt-BR');
  };

  return (
    <div 
      className="relative"
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
    >
      <div className={`px-4 py-2 rounded-xl text-[10px] font-black border flex items-center gap-2 cursor-help transition-all duration-300 ${cfg.bg} ${cfg.text} border-black/5 hover:scale-105 hover:shadow-md`}>
        <span className={`w-2 h-2 rounded-full shadow-sm ${cfg.color}`}></span>
        {courseId}
      </div>

      {isHovered && (
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-3 z-[100] w-64 p-5 bg-gray-900 text-white rounded-[1.5rem] shadow-2xl animate-fadeIn border border-white/10">
          <div className="space-y-3">
            <header className="flex justify-between items-center border-b border-white/10 pb-2 mb-2">
              <span className="text-[9px] font-black text-green-400 uppercase tracking-widest">{courseId}</span>
              <span className={`text-[8px] font-black px-2 py-0.5 rounded-full uppercase ${cfg.bg} ${cfg.text}`}>
                {cfg.label}
              </span>
            </header>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <p className="text-[8px] text-gray-400 font-bold uppercase mb-1">Conclusão</p>
                <p className="text-[10px] font-black">{formatDate(record.completionDate)}</p>
              </div>
              <div>
                <p className="text-[8px] text-gray-400 font-bold uppercase mb-1">Vencimento</p>
                <p className="text-[10px] font-black">{formatDate(record.expiryDate)}</p>
              </div>
            </div>

            {record.expiryDate && (
              <div className="bg-white/5 p-2.5 rounded-xl border border-white/5">
                <p className={`text-[10px] font-black uppercase text-center ${days !== null && days < 0 ? 'text-red-400' : 'text-amber-400'}`}>
                  {days !== null ? (
                    days < 0 ? `Vencido há ${Math.abs(days)} dias` : `Vence em ${days} dias`
                  ) : 'Sem expiração'}
                </p>
              </div>
            )}
          </div>
          <div className="absolute top-full left-1/2 -translate-x-1/2 w-3 h-3 bg-gray-900 rotate-45 -mt-1.5 border-r border-b border-white/10"></div>
        </div>
      )}
    </div>
  );
};

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDept, setSelectedDept] = useState('Todos');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const departments = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => e.department)))], [employees]);

  const filtered = employees.filter(e => {
    const matchesSearch = e.name.toLowerCase().includes(searchTerm.toLowerCase()) || e.registration.includes(searchTerm);
    const matchesDept = selectedDept === 'Todos' || e.department === selectedDept;
    return matchesSearch && matchesDept;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    await StorageService.updateEmployee(editingEmp);
    setEditingEmp(null);
    onUpdate();
  };

  const handleDelete = async (id: string) => {
    if (!isAdmin) return;
    if (window.confirm('Tem certeza que deseja excluir este funcionário?')) {
      await StorageService.deleteEmployee(id);
      onUpdate();
    }
  };

  const createNewEmployee = () => {
    if (!isAdmin) return;
    const newEmp: Employee = {
      id: `emp-${Date.now()}`,
      name: '',
      registration: '',
      role: '',
      department: '',
      trainings: {}
    };
    setEditingEmp(newEmp);
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;

    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);

    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };

    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800 italic tracking-tighter">Gestão de <span className="text-green-600">Equipe</span></h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mt-1 italic">Matriz de Competências e Fotos</p>
        </div>
        {isAdmin && (
          <button 
            onClick={createNewEmployee}
            className="bg-[#064E3B] text-white px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-green-900/20 hover:scale-105 transition-all flex items-center gap-3"
          >
            <span>➕ Cadastrar Integrante</span>
          </button>
        )}
      </div>

      <div className="flex flex-col md:flex-row md:items-center justify-between gap-6 bg-white p-6 rounded-[2.5rem] border border-gray-100 shadow-sm">
        <div className="flex flex-wrap items-center gap-6 flex-1">
          <div className="flex flex-col min-w-[150px]">
            <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 tracking-widest italic">Departamento</label>
            <select 
              value={selectedDept}
              onChange={(e) => setSelectedDept(e.target.value)}
              className="bg-gray-50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-gray-700 outline-none focus:bg-white focus:border-green-500 transition-all shadow-inner"
            >
              {departments.map(d => <option key={d} value={d}>{d}</option>)}
            </select>
