import { Employee, AdminProfile, CompanyProfile } from '../types';

const STORAGE_KEY = 'sst_management_data';
const SHEETS_URL_KEY = 'sst_sheets_url';
const ADMIN_KEY = 'sst_admin_profile';
const COMPANY_KEY = 'sst_company_profile';

const DEFAULT_ADMIN: AdminProfile = {
  username: 'Bruno',
  password: '#Bruno91218175',
  email: 'bruno@sst.com.br',
  icon: '👨‍💼'
};

const DEFAULT_COMPANY: CompanyProfile = {
  name: 'SST INTEL SOLUÇÕES',
  cnpj: '00.000.000/0001-00',
  logoUrl: '',
  footerText: 'Relatório Gerencial de Conformidade Normativa'
};

export const StorageService = {
  getAdminProfile(): AdminProfile {
    const data = localStorage.getItem(ADMIN_KEY);
    return data ? JSON.parse(data) : DEFAULT_ADMIN;
  },

  updateAdminProfile(profile: AdminProfile): void {
    localStorage.setItem(ADMIN_KEY, JSON.stringify(profile));
  },

  getCompanyProfile(): CompanyProfile {
    const data = localStorage.getItem(COMPANY_KEY);
    return data ? JSON.parse(data) : DEFAULT_COMPANY;
  },

  updateCompanyProfile(profile: CompanyProfile): void {
    localStorage.setItem(COMPANY_KEY, JSON.stringify(profile));
  },

  getSheetsUrl(): string | null {
    return localStorage.getItem(SHEETS_URL_KEY);
  },

  saveSheetsUrl(url: string): void {
    localStorage.setItem(SHEETS_URL_KEY, url);
  },

  async getEmployees(): Promise<Employee[]> {
    const localData = localStorage.getItem(STORAGE_KEY);
    return localData ? JSON.parse(localData) : [];
  },

  async saveEmployees(employees: Employee[]): Promise<void> {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(employees));
  },

  async addEmployees(newEmployees: Employee[]): Promise<Employee[]> {
    const current = await this.getEmployees();
    const merged = [...current];

    newEmployees.forEach(newEmp => {
      const index = merged.findIndex(e => 
        (e.registration !== '-' && e.registration === newEmp.registration) || 
        (e.id === newEmp.id)
      );

      if (index !== -1) {
        merged[index] = { ...merged[index], ...newEmp };
      } else {
        merged.push(newEmp);
      }
    });

    await this.saveEmployees(merged);
    return merged;
  },

  async updateEmployee(updatedEmp: Employee): Promise<Employee[]> {
    const employees = await this.getEmployees();
    const index = employees.findIndex(e => e.id === updatedEmp.id);
    if (index !== -1) {
      employees[index] = updatedEmp;
    } else {
      employees.push(updatedEmp);
    }
    await this.saveEmployees(employees);
    return employees;
  },

  async deleteEmployee(id: string): Promise<Employee[]> {
    const employees = await this.getEmployees();
    const filtered = employees.filter(e => e.id !== id);
    await this.saveEmployees(filtered);
    return filtered;
  },

  downloadBackup() {
    const data = localStorage.getItem(STORAGE_KEY);
    if (!data) return;
    const blob = new Blob([data], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `backup_sst_${new Date().toISOString().split('T')[0]}.json`;
    a.click();
  }
};

