import { getDaysRemaining } from '../utils/calculations';

interface DashboardProps {
  employees: Employee[];
}

const CustomTooltip = ({ active, payload }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-gray-100 min-w-[180px] animate-fadeIn">
        <p className="font-black text-gray-900 mb-2 text-[10px] uppercase tracking-wider">{payload[0].name}</p>
        <div className="flex justify-between items-center">
          <span className="font-bold text-gray-500 text-[10px] uppercase">Quantidade</span>
          <span className="font-black text-emerald-600 text-lg">{payload[0].value}</span>
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees }) => {
  const [selectedCompany, setSelectedCompany] = useState<string>('Todas');

  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  const filteredEmployees = useMemo(() => {
    return selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);
  }, [employees, selectedCompany]);

  const stats = useMemo(() => {
    const s = { trained: 0, expiring: 0, expired: 0 };
    const deptStats: Record<string, number> = {};
    const alert15: any[] = [];
    const alert60: any[] = [];
    const recent: any[] = [];

    filteredEmployees.forEach(emp => {
      deptStats[emp.department] = (deptStats[emp.department] || 0) + 1;

      Object.entries(emp.trainings).forEach(([cid, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (record.completionDate) {
          recent.push({ emp, cid, date: record.completionDate });
        }

        if (record.status === 'VALID') s.trained++;
        else if (record.status === 'EXPIRING') {
          s.expiring++;
          if (days !== null && days <= 15) alert15.push({ emp, cid, days });
          else if (days !== null && days <= 60) alert60.push({ emp, cid, days });
        }
        else if (record.status === 'EXPIRED') s.expired++;
      });
    });

    recent.sort((a, b) => new Date(b.date).getTime() - new Date(a.date).getTime());

    return { 
      s, 
      deptData: Object.entries(deptStats).map(([name, value]) => ({ name, value })),
      statusData: [
        { name: 'Válidos', value: s.trained, color: '#10B981' },
        { name: 'Vencendo', value: s.expiring, color: '#F59E0B' },
        { name: 'Vencidos', value: s.expired, color: '#EF4444' }
      ],
      alert15,
      alert60,
      recent: recent.slice(0, 6)
    };
  }, [filteredEmployees]);

  return (
    <div className="space-y-10 pb-20 animate-fadeIn">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tighter italic">
            Dashboard <span className="text-emerald-600">Analytics</span>
          </h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.2em] mt-1 italic">Monitoramento Estratégico ControlSST</p>
        </div>

        <div className="bg-white p-2 rounded-2xl border border-gray-100 shadow-sm flex items-center gap-3">
          <span className="text-[9px] font-black text-gray-400 uppercase ml-4 tracking-widest">Empresa:</span>
          <select 
            value={selectedCompany}
            onChange={(e) => setSelectedCompany(e.target.value)}
            className="bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-xs font-black outline-none border-none cursor-pointer"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </header>

      {/* Cards de Resumo */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cursos Válidos', val: stats.s.trained, color: 'text-emerald-600', bg: 'bg-emerald-50', icon: '🛡️' },
          { label: 'Em Reciclagem', val: stats.s.expiring, color: 'text-amber-500', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Cursos Vencidos', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Colaboradores Ativos', val: filteredEmployees.length, color: 'text-blue-600', bg: 'bg-blue-50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 hover:shadow-xl transition-all">
            <div className="flex justify-between items-start">
              <span className={`text-2xl p-4 rounded-2xl ${item.bg}`}>{item.icon}</span>
              <span className={`text-5xl font-black tracking-tighter ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">{item.label}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-gray-100">
          <div className="mb-6">
            <h3 className="text-xl font-black text-gray-800">Conformidade Operacional</h3>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1 italic">Distribuição de Status de NRs</p>
          </div>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.statusData}
                  cx="50%"
                  cy="50%"
                  innerRadius={80}
                  outerRadius={120}
                  paddingAngle={8}
                  dataKey="value"
                >
                  {stats.statusData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
                <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{fontSize: '10px', fontWeight: '900', textTransform: 'uppercase'}} />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-gray-100">
          <div className="mb-6">
            <h3 className="text-xl font-black text-gray-800">Censo por Departamento</h3>
            <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1 italic">Concentração de Equipe</p>
          </div>
          <div className="h-[350px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={stats.deptData}
                  cx="50%"
                  cy="50%"
                  innerRadius={80}
                  outerRadius={120}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {stats.deptData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={getDeptColor(entry.name)} />
                  ))}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-red-100">
          <h4 className="text-[10px] font-black uppercase text-red-600 tracking-widest mb-6 flex items-center gap-2">
            <span>🚨</span> Janela Crítica (15 Dias)
          </h4>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-4">
            {stats.alert15.map((a, i) => (
              <div key={i} className="flex justify-between items-center border-b border-red-50 pb-3">
                <div>
                  <p className="text-xs font-black text-gray-800 uppercase">{a.emp.name}</p>
                  <p className="text-[9px] text-gray-400 font-bold">{a.cid} • {a.emp.department}</p>
                </div>
                <span className="bg-red-50 text-red-600 px-3 py-1 rounded-full text-[10px] font-black">{a.days} Dias</span>
              </div>
            ))}
            {stats.alert15.length === 0 && <p className="text-[10px] text-gray-300 font-black italic">Sem alertas de 15 dias.</p>}
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-amber-100">
          <h4 className="text-[10px] font-black uppercase text-amber-600 tracking-widest mb-6 flex items-center gap-2">
            <span>⏳</span> Próximos 60 Dias
          </h4>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-4">
            {stats.alert60.map((a, i) => (
              <div key={i} className="flex justify-between items-center border-b border-amber-50 pb-3">
                <div>
                  <p className="text-xs font-black text-gray-800 uppercase">{a.emp.name}</p>
                  <p className="text-[9px] text-gray-400 font-bold">{a.cid} • {a.emp.department}</p>
                </div>
                <span className="bg-amber-50 text-amber-600 px-3 py-1 rounded-full text-[10px] font-black">{a.days} Dias</span>
              </div>
            ))}
            {stats.alert60.length === 0 && <p className="text-[10px] text-gray-300 font-black italic">Sem alertas de 60 dias.</p>}
          </div>
        </div>

        <div className="bg-white p-8 rounded-[3rem] shadow-sm border border-emerald-100">
          <h4 className="text-[10px] font-black uppercase text-emerald-600 tracking-widest mb-6 flex items-center gap-2">
            <span>✅</span> Últimas Certificações
          </h4>
          <div className="space-y-4 max-h-60 overflow-y-auto custom-scrollbar pr-4">
            {stats.recent.map((r, i) => (
              <div key={i} className="flex justify-between items-center border-b border-emerald-50 pb-3">
                <div>
                  <p className="text-xs font-black text-gray-800 uppercase">{r.emp.name}</p>
                  <p className="text-[9px] text-gray-400 font-bold">{r.cid} • {r.emp.department}</p>
                </div>
                <span className="text-[10px] font-black text-emerald-600">{new Date(r.date).toLocaleDateString('pt-BR')}</span>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

