  const reportData = useMemo(() => {
    let result: any[] = [];
    employees.forEach(emp => {
      Object.entries(emp.trainings).forEach(([cid, record]) => {
        const t = record as TrainingRecord;
        const days = getDaysRemaining(t.expiryDate);

