                    <span className={`px-4 py-2 rounded-xl text-[8px] font-black uppercase tracking-widest ${STATUS_CONFIG[item.record.status].bg} ${STATUS_CONFIG[item.record.status].text}`}>
                      {STATUS_CONFIG[item.record.status].label}
                    </span>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default Reports;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import Reports from './components/Reports';
import MatrixView from './components/MatrixView';
import ImportData from './components/ImportData';
import ConfigView from './components/ConfigView';
import AuthView from './components/AuthView';
import { Employee, UserRole } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [userRole, setUserRole] = useState<UserRole>(null); 

  const isAdmin = userRole === 'admin';

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (userRole) {
      loadData();
    }
  }, [userRole]);

  const handleImport = async (data: Employee[]) => {
    if (!isAdmin) return;
    setIsLoading(true);
    try {
      const updated = await StorageService.addEmployees(data);
      setEmployees(updated);
      setActiveTab('dashboard');
    } catch (error) {
      alert("Erro ao salvar dados.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!userRole) {
    return <AuthView onLogin={(role) => setUserRole(role)} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4">
          <div className="w-12 h-12 border-4 border-green-100 border-t-green-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest">Carregando Banco SST...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} />;
      case 'employees': return <EmployeeView employees={employees} onUpdate={loadData} isAdmin={isAdmin} />;
      case 'reports': return <Reports employees={employees} />;
      case 'matrix': return <MatrixView />;
      case 'import': return isAdmin ? (
        <div className="space-y-10">
           <ImportData onImport={handleImport} />
           <div className="max-w-6xl mx-auto bg-white p-8 rounded-[2.5rem] border border-gray-100 flex items-center justify-between shadow-sm">
             <div>
                <h4 className="font-black text-gray-800">Cópia de Segurança (Backup)</h4>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Baixe todos os dados para o seu computador</p>
             </div>
             <button 
                onClick={() => StorageService.downloadBackup()}
                className="bg-blue-50 text-blue-600 px-8 py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-blue-100 transition-all"
             >
                Baixar Arquivo .JSON 💾
             </button>
           </div>
        </div>
      ) : null;
      case 'config': return isAdmin ? <ConfigView onUpdate={loadData} /> : null;
      default: return <Dashboard employees={employees} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={userRole} 
      onLogout={() => setUserRole(null)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Employee, TrainingRecord } from '../types';
import { STATUS_CONFIG, NR_COURSES, getDeptColor } from '../constants';
import { getDaysRemaining, calculateTrainingStatus, getExpiryDate } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDept, setSelectedDept] = useState('Todos');
  const [selectedCompany, setSelectedCompany] = useState('Todas');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const departments = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => e.department)))], [employees]);
  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  const filtered = employees.filter(e => {
    const matchesSearch = e.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         e.registration.includes(searchTerm) ||
                         e.role.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesDept = selectedDept === 'Todos' || e.department === selectedDept;
    const matchesCompany = selectedCompany === 'Todas' || e.company === selectedCompany;
    return matchesSearch && matchesDept && matchesCompany;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    await StorageService.updateEmployee(editingEmp);
    setEditingEmp(null);
    onUpdate();
  };

  const createNewEmployee = () => {
    if (!isAdmin) return;
    const newEmp: Employee = {
      id: `emp-${Date.now()}`,
      name: '',
      registration: '',
      role: '',
      department: '',
      company: '',
      trainings: {}
