import React, { useState } from 'react';
import { StorageService } from '../services/storage';
import { UserRole } from '../types';

interface AuthViewProps {
  onLogin: (role: UserRole) => void;
}

const AuthView: React.FC<AuthViewProps> = ({ onLogin }) => {
  const [mode, setMode] = useState<'login' | 'forgot'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const admin = StorageService.getAdminProfile();

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (username === admin.username && password === admin.password) {
      onLogin('admin');
    } else {
      setError('Credenciais incorretas. Verifique usuário e senha.');
      setTimeout(() => setError(''), 3000);
    }
  };

  const handleForgot = (e: React.FormEvent) => {
    e.preventDefault();
    setSuccess(`Um link de recuperação foi enviado para ${admin.email}`);
    setTimeout(() => {
      setSuccess('');
      setMode('login');
    }, 4000);
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex items-center justify-center p-6 font-['Inter']">
      <div className="w-full max-w-md bg-white rounded-[3.5rem] shadow-2xl overflow-hidden border border-gray-100 animate-fadeIn">
        <div className="p-12">
          <header className="text-center mb-10">
            <div className="w-20 h-20 bg-green-600 rounded-3xl flex items-center justify-center text-4xl mx-auto mb-6 shadow-xl shadow-green-900/20 animate-bounce-short">🛡️</div>
            <h1 className="text-3xl font-black text-gray-800 tracking-tighter italic">SST <span className="text-green-600">Intel</span></h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-[0.2em] mt-2">Plataforma de Gestão Normativa</p>
          </header>

          {mode === 'login' ? (
            <form onSubmit={handleAdminLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Usuário Administrador</label>
                <input 
                  type="text" 
                  className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 font-bold text-sm outline-none focus:bg-white focus:border-green-500 transition-all shadow-inner"
                  placeholder="Nome de usuário"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Senha de Acesso</label>
                <input 
                  type="password" 
                  className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 font-bold text-sm outline-none focus:bg-white focus:border-green-500 transition-all shadow-inner"
                  placeholder="••••••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>

              {error && <p className="text-red-500 text-[10px] font-black uppercase text-center animate-pulse">{error}</p>}

              <button 
                type="submit"
                className="w-full py-5 bg-[#064E3B] text-green-400 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-green-900/20 hover:scale-[1.02] transition-all"
              >
                Entrar no Sistema
              </button>

              <div className="flex flex-col gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setMode('forgot')}
                  className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-green-600 transition-colors"
                >
                  Esqueci minha senha
                </button>

                <div className="relative py-2">
                  <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-gray-100"></span></div>
                  <div className="relative flex justify-center"><span className="bg-white px-4 text-[9px] font-black text-gray-300 uppercase italic">Ou</span></div>
                </div>

                <button 
                  type="button"
                  onClick={() => onLogin('visitor')}
                  className="w-full py-5 bg-gray-50 text-gray-500 rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-gray-100 transition-all border border-gray-100"
                >
                  Acesso de Consulta
                </button>
              </div>
            </form>
          ) : (
            <form onSubmit={handleForgot} className="space-y-6 animate-fadeIn">
              <div className="text-center mb-6">
                <h3 className="text-lg font-black text-gray-800">Recuperar Acesso</h3>
                <p className="text-[11px] text-gray-500 font-medium">As instruções serão enviadas para o e-mail cadastrado.</p>
              </div>

              {success ? (
                <div className="bg-green-50 p-6 rounded-3xl border border-green-100 text-center">
                   <p className="text-green-700 font-black text-[10px] uppercase">{success}</p>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">E-mail Administrativo</label>
                    <input 
                      required
                      type="email" 
                      className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 font-bold text-sm outline-none focus:bg-white focus:border-green-500 transition-all shadow-inner"
                      placeholder="seu@email.com.br"
                    />
                  </div>
                  <button 
                    type="submit"
                    className="w-full py-5 bg-green-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-green-900/20"
                  >
                    Enviar Link de Resgate
                  </button>
                  <button 
                    type="button"
                    onClick={() => setMode('login')}
                    className="w-full py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-gray-600"
                  >
                    Voltar para o Login
                  </button>
                </div>
              )}
            </form>
          )}
        </div>
      </div>
      <div className="fixed bottom-8 text-[9px] font-black text-gray-300 uppercase tracking-[0.3em]">
        {new Date().getFullYear()}
      </div>
    </div>
  );
};

export default AuthView;

import React, { useState, useMemo } from 'react';
import { Employee, TrainingRecord } from '../types';
import { STATUS_CONFIG, NR_COURSES, getDeptColor } from '../constants';
import { getDaysRemaining, calculateTrainingStatus, getExpiryDate } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedDept, setSelectedDept] = useState('Todos');
  const [selectedCompany, setSelectedCompany] = useState('Todas');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const departments = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => e.department)))], [employees]);
  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  const filtered = employees.filter(e => {
    const matchesSearch = e.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         e.registration.includes(searchTerm) ||
                         e.role.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesDept = selectedDept === 'Todos' || e.department === selectedDept;
    const matchesCompany = selectedCompany === 'Todas' || e.company === selectedCompany;
    return matchesSearch && matchesDept && matchesCompany;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    await StorageService.updateEmployee(editingEmp);
    setEditingEmp(null);
    onUpdate();
  };

  const createNewEmployee = () => {
    if (!isAdmin) return;
    const newEmp: Employee = {
      id: `emp-${Date.now()}`,
      name: '',
      registration: '',
      role: '',
      department: '',
      company: '',
      trainings: {}
    };
    setEditingEmp(newEmp);
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;
    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);
    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800 italic tracking-tighter">Gestão de <span className="text-emerald-600">Equipe</span></h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mt-1 italic">Controle Multi-Empresa ControlSST</p>
        </div>
        {isAdmin && (
          <button 
            onClick={createNewEmployee}
            className="bg-[#064E3B] text-emerald-400 px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-emerald-900/20 hover:scale-105 transition-all flex items-center gap-3"
          >
            <span>➕ Novo Colaborador</span>
          </button>
        )}
      </div>

      {/* Filtros */}
      <div className="bg-white p-6 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col md:flex-row gap-6">
        <div className="flex-1 min-w-[200px]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Empresa</label>
          <select 
            value={selectedCompany}
            onChange={(e) => setSelectedCompany(e.target.value)}
            className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="flex-1 min-w-[200px]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Departamento</label>
          <select 
            value={selectedDept}
            onChange={(e) => setSelectedDept(e.target.value)}
            className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner"
          >
            {departments.map(d => <option key={d} value={d}>{d}</option>)}
          </select>
        </div>
        <div className="flex-[2] min-w-[300px]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Filtro Rápido</label>
          <input 
            type="text" 
            placeholder="Nome, RE ou Função..." 
            className="w-full px-5 py-3 bg-emerald-50/50 border-2 border-transparent rounded-2xl text-xs font-bold focus:bg-white focus:border-emerald-500 outline-none transition-all shadow-inner"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>
