                    className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 pl-12 font-bold text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner"
                    placeholder="••••••••••••"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                  />
                </div>
              </div>

              {error && <p className="text-red-500 text-[10px] font-black uppercase text-center animate-pulse bg-red-50 py-2 rounded-xl border border-red-100">{error}</p>}

              <button 
                type="submit"
                className="w-full py-5 bg-[#064E3B] text-emerald-400 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl shadow-emerald-900/20 hover:scale-[1.02] transition-all flex items-center justify-center gap-3"
              >
                Entrar no Sistema ⚡
              </button>

              <div className="flex flex-col gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setMode('forgot')}
                  className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-emerald-600 transition-colors"
                >
                  Esqueci minha senha
                </button>

                <div className="relative py-2">
                  <div className="absolute inset-0 flex items-center"><span className="w-full border-t border-gray-100"></span></div>
                  <div className="relative flex justify-center"><span className="bg-white px-4 text-[9px] font-black text-gray-300 uppercase italic">Acesso Rápido</span></div>
                </div>

                <button 
                  type="button"
                  onClick={() => onLogin('visitor')}
                  className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-orange-600 shadow-xl shadow-orange-900/20 hover:scale-[1.02] transition-all border-none"
                >
                  Acesso de Consulta 👁️
                </button>
              </div>
            </form>
          ) : (
            <form onSubmit={handleForgot} className="space-y-6 animate-fadeIn">
              <div className="text-center mb-6">
                <h3 className="text-lg font-black text-gray-800 tracking-tight">Recuperar Acesso</h3>
                <p className="text-[11px] text-gray-500 font-medium italic">As instruções serão enviadas para o e-mail cadastrado.</p>
              </div>

              {success ? (
                <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100 text-center">
                   <p className="text-emerald-700 font-black text-[10px] uppercase">{success}</p>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">E-mail Administrativo</label>
                    <input 
                      required
                      type="email" 
                      className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 font-bold text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner"
                      placeholder="seu@email.com.br"
                    />
                  </div>
                  <button 
                    type="submit"
                    className="w-full py-5 bg-[#064E3B] text-emerald-400 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-emerald-900/20"
                  >
                    Enviar Link de Resgate
                  </button>
                  <button 
                    type="button"
                    onClick={() => setMode('login')}
                    className="w-full py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-gray-600"
                  >
                    Voltar para o Login
                  </button>
                </div>
              )}
            </form>
          )}
        </div>
      </div>
      <div className="fixed bottom-8 text-[9px] font-black text-gray-300 uppercase tracking-[0.3em]">
        {new Date().getFullYear()}
      </div>
    </div>
  );
};

