import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storage';
import { UserRole, CompanyProfile, AdminProfile } from '../types';

interface AuthViewProps {
  onLogin: (role: UserRole) => void;
}

const AuthView: React.FC<AuthViewProps> = ({ onLogin }) => {
  const [mode, setMode] = useState<'login' | 'forgot'>('login');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const [appConfig, setAppConfig] = useState<{company: CompanyProfile, admin: AdminProfile} | null>(null);

  useEffect(() => {
    StorageService.getAppSettings().then(config => {
      setAppConfig(config);
    });
  }, []);

  const handleAdminLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appConfig) return;

    if (username === appConfig.admin.username && password === appConfig.admin.password) {
      onLogin('admin');
    } else {
      setError('Credenciais incorretas. Verifique usuário e senha.');
      setTimeout(() => setError(''), 3000);
    }
  };

  const handleForgot = (e: React.FormEvent) => {
    e.preventDefault();
    setSuccess(`Um link de recuperação foi enviado para brunosilva1232014@gmail.com`);
    setTimeout(() => {
      setSuccess('');
      setMode('login');
    }, 4000);
  };

  if (!appConfig) return null;

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex items-center justify-center p-6 font-['Inter']">
      <div className="w-full max-w-md bg-white rounded-[3.5rem] shadow-2xl overflow-hidden border border-gray-100 animate-fadeIn relative">

        <div className="p-12">
          <header className="text-center mb-10">
            <div className="relative w-24 h-24 mx-auto mb-6">
              <div className="absolute inset-0 bg-orange-500 rounded-3xl shadow-xl shadow-orange-900/20 rotate-3 animate-pulse opacity-20"></div>
              <div className="relative w-24 h-24 bg-gradient-to-br from-orange-400 to-amber-500 rounded-3xl flex items-center justify-center text-5xl shadow-xl shadow-orange-900/40 animate-bounce-short z-10 border-b-4 border-orange-600 overflow-hidden">
                <span className="drop-shadow-lg">⛑️</span>
              </div>
            </div>

            <h1 className="text-5xl font-black tracking-tighter leading-none italic">
              <span className="text-[#064E3B]">Control</span>
              <span className="text-emerald-500">SST</span>
            </h1>
            <p className="text-[10px] text-gray-400 font-black uppercase tracking-[0.25em] mt-3">Gestão Profissional de SST</p>
          </header>

          {mode === 'login' ? (
            <form onSubmit={handleAdminLogin} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Usuário Administrador</label>
                <input 
                  type="text" 
                  className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 pl-6 font-bold text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner"
                  placeholder="Nome de usuário"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                />
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">Senha de Acesso</label>
                <input 
                  type="password" 
                  className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 pl-6 font-bold text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner"
                  placeholder="••••••••••••"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                />
              </div>

              {error && <p className="text-red-500 text-[10px] font-black uppercase text-center animate-pulse">{error}</p>}

              <button 
                type="submit"
                className="w-full py-5 bg-[#064E3B] text-emerald-400 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:scale-[1.02] transition-all"
              >
                Acessar Painel ⚡
              </button>

              <div className="flex flex-col gap-4 pt-4">
                <button 
                  type="button"
                  onClick={() => setMode('forgot')}
                  className="text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-emerald-600 transition-colors"
                >
                  Esqueci minha senha
                </button>
                <button 
                  type="button"
                  onClick={() => onLogin('visitor')}
                  className="w-full py-5 bg-orange-500 text-white rounded-2xl font-black text-xs uppercase tracking-[0.2em] hover:bg-orange-600 shadow-xl"
                >
                  Acesso de Consulta 👁️
                </button>
              </div>
            </form>
          ) : (
            <form onSubmit={handleForgot} className="space-y-6 animate-fadeIn">
              <div className="text-center mb-6">
                <h3 className="text-lg font-black text-gray-800 tracking-tight">Recuperar Acesso</h3>
                <p className="text-[11px] text-gray-500 font-medium italic">As instruções serão enviadas para o e-mail de segurança.</p>
              </div>
              {success ? (
                <div className="bg-emerald-50 p-6 rounded-3xl border border-emerald-100 text-center">
                   <p className="text-emerald-700 font-black text-[10px] uppercase">{success}</p>
                </div>
              ) : (
                <div className="space-y-4">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-1">E-mail Administrativo</label>
                    <input 
                      required
                      type="email" 
                      className="w-full bg-gray-50 border-2 border-transparent rounded-2xl p-4 font-bold text-sm outline-none focus:bg-white focus:border-emerald-500"
                      placeholder="brunosilva1232014@gmail.com"
                    />
                  </div>
                  <button 
                    type="submit"
                    className="w-full py-5 bg-[#064E3B] text-emerald-400 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-emerald-900/20"
                  >
                    Enviar Link de Resgate
                  </button>
                  <button 
                    type="button"
                    onClick={() => setMode('login')}
                    className="w-full py-2 text-[10px] font-black text-gray-400 uppercase tracking-widest"
                  >
                    Voltar para o Login
                  </button>
                </div>
              )}
            </form>
          )}
        </div>
      </div>
    </div>
  );
};

export default AuthView;

import React, { useState } from 'react';
import { formatEmployeeData } from '../utils/calculations';
import { Employee } from '../types';

interface ImportDataProps {
  onImport: (data: Employee[]) => void;
}

const ImportData: React.FC<ImportDataProps> = ({ onImport }) => {
  const [inputText, setInputText] = useState('');
  const [error, setError] = useState('');
  const [parsedEmployees, setParsedEmployees] = useState<Employee[]>([]);
  const [isProcessing, setIsProcessing] = useState(false);

  const handleProcess = () => {
    try {
      const trimmedInput = inputText.trim();
      if (!trimmedInput) {
        setError('O campo está vazio. Copie os dados da sua planilha e cole aqui.');
        return;
      }

      const lines = trimmedInput.split(/\r?\n/);
      if (lines.length < 2) {
        setError('Dados insuficientes. Certifique-se de copiar o CABEÇALHO e as LINHAS da planilha.');
        return;
      }

      const firstLine = lines[0];
      let separator = '\t';
      if (!firstLine.includes('\t')) {
        if (firstLine.includes(';')) separator = ';';
        else if (firstLine.includes(',')) separator = ',';
      }

      const headers = lines[0].split(separator).map(h => h.trim());

      const rawData = lines.slice(1).map(line => {
        const values = line.split(separator).map(v => v.trim());
        const obj: any = {};
        headers.forEach((h, i) => {
          const val = values[i];
          obj[h] = (val === '' || val === '-' || val?.toUpperCase() === 'N/A') ? undefined : val;
        });
        return obj;
      });

      const employees = formatEmployeeData(rawData);

      if (employees.length === 0 || employees.every(e => e.name === 'Sem Nome')) {
        setError('Não reconhecemos os nomes das colunas. Verifique se o cabeçalho inclui "Nome", "Matrícula" e as NRs.');
        return;
      }

      setParsedEmployees(employees);
      setError('');
    } catch (err) {
      console.error(err);
      setError('Erro crítico ao processar texto. Verifique se o formato da tabela está correto.');
    }
  };

  const handleSync = async () => {
    if (parsedEmployees.length === 0) return;
    setIsProcessing(true);
    try {
      await onImport(parsedEmployees);
      setParsedEmployees([]);
      setInputText('');
      alert('Sincronização com Supabase concluída com sucesso!');
    } catch (err) {
      setError('Erro ao sincronizar com o banco de dados.');
    } finally {
      setIsProcessing(false);
    }
  };

  const handleClear = () => {
    setInputText('');
    setParsedEmployees([]);
    setError('');
  };

  return (
    <div className="max-w-6xl mx-auto animate-fadeIn space-y-6 pb-20">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl shadow-green-900/5 border border-gray-100">
        <div className="flex justify-between items-start mb-8">
          <div>
            <h2 className="text-3xl font-black text-gray-800 flex items-center gap-3 tracking-tighter">
              <span className="text-4xl">📥</span> Importar <span className="text-emerald-600 italic">Planilha</span>
            </h2>
            <p className="text-gray-400 mt-1 font-bold uppercase text-[10px] tracking-widest italic">Integração Direta com Supabase Cloud</p>
          </div>

          <div className="flex gap-3">
             <button 
                onClick={handleClear}
                className="px-6 py-3 bg-red-50 text-red-500 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-red-500 hover:text-white transition-all"
             >
                Limpar 🗑️
             </button>
             <button 
                onClick={handleProcess}
                className="px-6 py-3 bg-blue-50 text-blue-600 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-blue-600 hover:text-white transition-all"
             >
                Atualizar Prévia 🔄
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-4 gap-4 mb-8">
          {[
            { label: 'Identificação', val: 'Nome, RE, Cargo', icon: '👤' },
            { label: 'Cursos', val: 'NRs em colunas', icon: '📜' },
            { label: 'Datas', val: 'DD/MM/AAAA', icon: '📅' },
            { label: 'Status', val: 'Automático', icon: '⚡' },
          ].map((item, i) => (
            <div key={i} className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100">
              <div className="flex items-center gap-2 mb-1">
                <span className="text-sm">{item.icon}</span>
                <p className="font-black text-[9px] text-emerald-800 uppercase tracking-widest">{item.label}</p>
              </div>
              <p className="text-[10px] text-emerald-600 font-bold">{item.val}</p>
            </div>
          ))}
        </div>

        <div className="relative group">
          <textarea
            className="w-full h-[350px] p-8 bg-gray-50 border-2 border-gray-100 rounded-[2rem] font-mono text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all resize-none shadow-inner"
            placeholder="Selecione os dados no Excel (Ctrl+C) e cole aqui (Ctrl+V)..."
            value={inputText}
            onChange={(e) => {
              setInputText(e.target.value);
              if (error) setError('');
            }}
          />
          {inputText === '' && (
            <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none opacity-10">
              <p className="text-4xl mb-2">📋</p>
              <p className="text-xs font-black uppercase tracking-widest">Área de Colagem</p>
            </div>
          )}
        </div>

        {error && (
          <div className="mt-6 p-4 bg-red-50 border-l-4 border-red-500 text-red-700 rounded-r-xl text-[10px] font-black uppercase flex items-center gap-3 animate-bounce">
