payload.text:
Para resolver o erro de conexão e garantir que o Google envie os dados corretamente para o seu aplicativo, o código no **Google Apps Script** precisa ser robusto e forçar o formato JSON.

Aqui está o código "perfeito" para você copiar e colar no seu script do Google, seguido pelas atualizações no aplicativo para melhorar o diagnóstico.

### 1. Código para o Google Apps Script (Copie e cole lá)

```javascript
/**
 * CÓDIGO PARA O GOOGLE APPS SCRIPT
 * Local: Extensões > Apps Script
 */
function doGet(e) {
  try {
    var ss = SpreadsheetApp.getActiveSpreadsheet();
    var sheet = ss.getSheets()[0]; // Pega a primeira aba da planilha
    var data = sheet.getDataRange().getValues();
    var headers = data[0];
    var jsonArray = [];

    for (var i = 1; i < data.length; i++) {
      var obj = {};
      var hasData = false;

      for (var j = 0; j < headers.length; j++) {
        var header = headers[j].toString().trim();
        var value = data[i][j];

        // Tratamento especial para Datas (converte para AAAA-MM-DD)
        if (value instanceof Date) {
          obj[header] = Utilities.formatDate(value, Session.getScriptTimeZone(), "yyyy-MM-dd");
        } else {
          obj[header] = value;
        }

        if (value !== "") hasData = true;
      }

      // Apenas adiciona se a linha não estiver totalmente vazia
      if (hasData) {
        jsonArray.push(obj);
      }
    }

    // O SEGREDO ESTÁ AQUI: Forçar o MIME Type como JSON para evitar bloqueio CORS
    return ContentService.createTextOutput(JSON.stringify(jsonArray))
      .setMimeType(ContentService.MimeType.JSON);

  } catch (error) {
    return ContentService.createTextOutput(JSON.stringify({ "error": error.toString() }))
      .setMimeType(ContentService.MimeType.JSON);
  }
}
```

