import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storage';
import { CompanyProfile, AdminProfile } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: 'admin' | 'visitor';
  onLogout: () => void;
  onRefreshData?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, onLogout, onRefreshData }) => {
  const isAdmin = userRole === 'admin';
  const [config, setConfig] = useState<{company: CompanyProfile, admin: AdminProfile} | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const hasSheetsUrl = !!StorageService.getSheetsUrl();

  useEffect(() => {
    StorageService.getAppSettings().then(setConfig);
  }, []);

  const handleSync = async () => {
    setIsSyncing(true);
    const success = await StorageService.syncWithSheets();
    if (success && onRefreshData) {
      onRefreshData();
    }
    setIsSyncing(false);
  };

  if (!config) return null;

  const allTabs = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', adminOnly: false },
    { id: 'employees', label: 'Funcionários', icon: '👷', adminOnly: false },
    { id: 'reports', label: 'Relatórios', icon: '📋', adminOnly: false },
    { id: 'matrix', label: 'Matriz de Cursos', icon: '📜', adminOnly: false },
    { id: 'import', label: 'Importação', icon: '📥', adminOnly: true },
    { id: 'config', label: 'Configuração', icon: '⚙️', adminOnly: true },
  ];

  const visibleTabs = allTabs.filter(tab => !tab.adminOnly || isAdmin);

  return (
    <div className="min-h-screen flex flex-col md:flex-row bg-[#FDFDFD]">
      <nav className="w-full md:w-80 bg-[#064E3B] text-white flex flex-col no-print shadow-2xl z-50">
        {/* LOGO IDENTICA AO LOGIN */}
        <div className="p-10 border-b border-green-800/50">
          <header className="flex flex-col items-center md:items-start">
            <div className="relative w-16 h-16 mb-4">
              <div className="absolute inset-0 bg-orange-500 rounded-2xl shadow-lg rotate-3 opacity-20"></div>
              <div className="relative w-16 h-16 bg-gradient-to-br from-orange-400 to-amber-500 rounded-2xl flex items-center justify-center text-3xl shadow-xl border-b-2 border-orange-600">
                <span>⛑️</span>
              </div>
            </div>

            <h1 className="text-3xl font-black tracking-tighter leading-none italic">
              <span className="text-white">Control</span>
              <span className="text-emerald-400">SST</span>
            </h1>
            <p className="text-[8px] text-emerald-300/40 font-black uppercase tracking-[0.2em] mt-2 italic">
              Gestão Profissional de SST
            </p>
          </header>
        </div>

        <div className="flex-1 py-8 px-4 space-y-2 overflow-y-auto">
          {visibleTabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`w-full text-left px-5 py-4 rounded-2xl flex items-center gap-4 transition-all duration-300 group ${
                activeTab === tab.id 
                  ? 'bg-emerald-600 shadow-xl font-bold scale-[1.02]' 
                  : 'hover:bg-emerald-700/40 text-emerald-100/70 hover:text-white'
              }`}
            >
              <span className="text-xl group-hover:scale-125 duration-300">{tab.icon}</span>
              <span className="text-sm tracking-wide uppercase font-black text-[10px]">{tab.label}</span>
            </button>
          ))}

          {isAdmin && hasSheetsUrl && (
            <button
              onClick={handleSync}
              disabled={isSyncing}
              className={`w-full text-left px-5 py-4 mt-8 rounded-2xl flex items-center gap-4 transition-all border-2 border-emerald-500/30 bg-emerald-900/20 hover:bg-emerald-500 hover:text-white ${isSyncing ? 'opacity-50 cursor-not-allowed' : ''}`}
            >
              <span className={`text-xl ${isSyncing ? 'animate-spin' : ''}`}>🔄</span>
              <span className="text-sm tracking-wide uppercase font-black text-[10px]">
                {isSyncing ? 'Sincronizando...' : 'Sincronizar Planilha'}
              </span>
            </button>
          )}
        </div>

        <div className="p-6 border-t border-green-800/50 space-y-4">
          <div className="bg-green-900/40 p-4 rounded-3xl border border-green-700/30 flex items-center gap-4">
            <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-xl">
              {isAdmin ? config.admin.icon : '👀'}
            </div>
            <div className="flex-1 overflow-hidden">
              <p className="text-[10px] font-black uppercase text-emerald-400 truncate tracking-widest">
                {isAdmin ? config.admin.username : 'Visitante'}
              </p>
              <p className="text-[8px] font-bold text-emerald-300/40 uppercase tracking-tighter truncate">
                {isAdmin ? 'Controle Total' : 'Modo Leitura'}
              </p>
            </div>
          </div>

          <button 
            onClick={onLogout} 
            className="w-full py-4 bg-red-500/10 hover:bg-red-50 text-red-500 hover:text-white rounded-2xl text-[9px] font-black uppercase tracking-[0.2em] transition-all border border-red-500/20 flex items-center justify-center gap-2"
          >
            Sair do Painel 🚪
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-y-auto h-screen scroll-smooth flex flex-col bg-[#FDFDFD]">
        <div className="flex-1 p-6 md:p-12 max-w-7xl mx-auto w-full">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useMemo, useState } from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer } from 'recharts';
import { Employee, TrainingRecord } from '../types';
import { getDeptColor } from '../constants';

interface DashboardProps {
  employees: Employee[];
  isAdmin: boolean;
}

const CustomTooltip = ({ active, payload }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-gray-100 min-w-[180px] animate-fadeIn">
        <p className="font-black text-gray-900 mb-2 text-[10px] uppercase tracking-wider">{payload[0].name}</p>
        <div className="flex justify-between items-center">
          <span className="font-bold text-gray-500 text-[10px] uppercase">Total</span>
          <span className="font-black text-emerald-600 text-lg">{payload[0].value}</span>
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees, isAdmin }) => {
  const [selectedCompany, setSelectedCompany] = useState<string>('Todas');

  const stats = useMemo(() => {
    const s = { trained: 0, expiring: 0, expired: 0 };
    const setorStats: Record<string, number> = {};
    const filtered = selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);

    filtered.forEach(emp => {
      // Contador de setores
      const setorNome = emp.setor || 'Geral';
      setorStats[setorNome] = (setorStats[setorNome] || 0) + 1;

      // Contador de treinamentos
      Object.entries(emp.trainings || {}).forEach(([_, t]) => {
        const record = t as TrainingRecord;
        if (record.status === 'VALID') s.trained++;
        else if (record.status === 'EXPIRING') s.expiring++;
        else if (record.status === 'EXPIRED') s.expired++;
      });
    });

    return { 
      s, 
      setorData: Object.entries(setorStats).map(([name, value]) => ({ name, value })),
      statusData: [
        { name: 'Válidos', value: s.trained, color: '#10B981' },
        { name: 'Vencendo', value: s.expiring, color: '#F59E0B' },
        { name: 'Vencidos', value: s.expired, color: '#EF4444' }
      ],
      filteredCount: filtered.length
    };
  }, [employees, selectedCompany]);

  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  return (
    <div className="space-y-10 pb-20 animate-fadeIn">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-4xl font-black text-gray-800 tracking-tighter italic">
            Dashboard <span className="text-emerald-600">Analytics</span>
          </h2>
          <p className="text-gray-400 font-bold uppercase text-[10px] tracking-[0.2em] mt-1 italic">Gestão Inteligente de SST</p>
        </div>
        <div className="bg-white p-2 rounded-2xl border border-gray-100 shadow-sm">
          <select 
            value={selectedCompany} 
            onChange={(e) => setSelectedCompany(e.target.value)} 
            className="bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-xs font-black outline-none border-none"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        {[
          { label: 'Cursos Válidos', val: stats.s.trained, color: 'text-emerald-600', bg: 'bg-emerald-50', icon: '✅' },
          { label: 'Em Reciclagem', val: stats.s.expiring, color: 'text-amber-500', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Cursos Vencidos', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Colaboradores Ativos', val: stats.filteredCount, color: 'text-blue-600', bg: 'bg-blue-50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 transition-all hover:scale-105">
            <div className="flex justify-between items-start">
              <span className={`text-2xl p-4 rounded-2xl ${item.bg}`}>{item.icon}</span>
              <span className={`text-5xl font-black tracking-tighter ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-5 text-[10px] font-black text-gray-400 uppercase tracking-widest">{item.label}</p>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-gray-100">
           <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-6 text-center">Status Global dos Treinamentos</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.statusData} cx="50%" cy="50%" innerRadius={60} outerRadius={100} paddingAngle={5} dataKey="value">
                  {stats.statusData.map((e, i) => <Cell key={i} fill={e.color} />)}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
              </PieChart>
            </ResponsiveContainer>
           </div>
        </div>
        <div className="bg-white p-8 rounded-[3.5rem] shadow-sm border border-gray-100">
           <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest mb-6 text-center">Colaboradores por Setor</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.setorData} cx="50%" cy="50%" innerRadius={60} outerRadius={100} paddingAngle={5} dataKey="value" nameKey="name">
                  {stats.setorData.map((e, i) => <Cell key={i} fill={getDeptColor(e.name)} />)}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
              </PieChart>
            </ResponsiveContainer>
           </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { calculateTrainingStatus, getExpiryDate } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSetor, setSelectedSetor] = useState('Todos');
  const [selectedCompany, setSelectedCompany] = useState('Todas');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const setores = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => e.setor)))], [employees]);
  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  const filtered = employees.filter(e => {
    const name = e.name || '';
    const registration = e.registration || '';
    const role = e.role || '';
    const matchesSearch = name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                         registration.includes(searchTerm) ||
                         role.toLowerCase().includes(searchTerm.toLowerCase());
    const matchesSetor = selectedSetor === 'Todos' || e.setor === selectedSetor;
    const matchesCompany = selectedCompany === 'Todas' || e.company === selectedCompany;
    return matchesSearch && matchesSetor && matchesCompany;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      onUpdate();
    } catch (err) {
      alert("Erro ao salvar. Verifique sua conexão.");
    }
  };

  const createNewEmployee = () => {
    if (!isAdmin) return;
    const newEmp: Employee = {
      id: `emp-${Date.now()}`,
      name: '',
      registration: '',
      role: '',
      setor: '',
      company: '',
      photoUrl: '',
      trainings: {}
    };
    setEditingEmp(newEmp);
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;
    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);
    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800 italic tracking-tighter">Gestão de <span className="text-emerald-600">Equipe</span></h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mt-1 italic">Controle Multi-Empresa ControlSST</p>
        </div>
        {isAdmin && (
          <button 
            onClick={createNewEmployee}
            className="bg-[#064E3B] text-emerald-400 px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest shadow-2xl shadow-emerald-900/20 hover:scale-105 transition-all flex items-center gap-3"
          >
            <span>➕ Novo Colaborador</span>
          </button>
        )}
      </div>

      <div className="bg-white p-6 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col md:flex-row gap-6">
        <div className="flex-1 min-w-[200px]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Empresa</label>
          <select value={selectedCompany} onChange={(e) => setSelectedCompany(e.target.value)} className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none shadow-inner">
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="flex-1 min-w-[200px]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Setor</label>
          <select value={selectedSetor} onChange={(e) => setSelectedSetor(e.target.value)} className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none shadow-inner">
            {setores.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div className="flex-[2] min-w-[300px]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Filtro Rápido</label>
          <input type="text" placeholder="Nome, RE ou Função..." className="w-full px-5 py-3 bg-emerald-50/50 border-2 border-transparent rounded-2xl text-xs font-bold shadow-inner outline-none focus:bg-white focus:border-emerald-500 transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-5">
        {filtered.map(emp => (
          <div key={emp.id} className="bg-white rounded-[2.5rem] border border-gray-100 hover:border-emerald-300 transition-all shadow-sm group">
            <div className="p-6 flex flex-col md:flex-row md:items-center justify-between gap-6">
              <div className="flex items-center gap-5 flex-1 min-w-0">
                <div className="w-16 h-16 text-white rounded-[1.8rem] flex items-center justify-center font-black text-xl shadow-lg relative overflow-hidden bg-emerald-50 flex-shrink-0 border border-emerald-100">
                  {emp.photoUrl ? (
                    <img src={emp.photoUrl} alt={emp.name} className="w-full h-full object-cover" />
                  ) : (
                    <span className="relative z-10 text-emerald-600 opacity-30">{emp.name?.charAt(0) || '?'}</span>
                  )}
                </div>

                <div className="min-w-0">
                  <h3 className="text-lg font-black text-gray-800 leading-none mb-1 uppercase tracking-tight truncate">{emp.name}</h3>
                  <div className="flex flex-col gap-1">
                    <div className="flex items-center gap-2">
                      <span className="text-[9px] font-black bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full uppercase tracking-tighter">{emp.company}</span>
                      <p className="text-[10px] text-gray-400 font-bold uppercase tracking-tight">Matrícula: <span className="text-gray-900">{emp.registration}</span></p>
                    </div>
                    <p className="text-[10px] text-gray-500 font-black uppercase tracking-tight truncate">
                      Função: <span className="text-emerald-700">{emp.role}</span> • Setor: <span className="text-emerald-500">{emp.setor}</span>
                    </p>
                  </div>
                </div>
              </div>

              <div className="flex flex-wrap gap-1.5 md:justify-end max-w-xs">
                {NR_COURSES.map(course => {
                  const training = emp.trainings[course.id];
                  const status = training?.status || 'NOT_TRAINED';
                  return (
                    <div 
                      key={course.id} 
                      title={`${course.name}: ${STATUS_CONFIG[status].label}`}
                      className={`w-5 h-5 rounded-full flex items-center justify-center text-[7px] font-black text-white shadow-sm transition-transform hover:scale-125 cursor-help ${STATUS_CONFIG[status].color}`}
                    >
                      {course.id.replace('NR', '')}
                    </div>
                  );
                })}
              </div>

              <div className="flex gap-3 flex-shrink-0">
                <button onClick={() => setEditingEmp(emp)} className="bg-emerald-50 text-emerald-700 px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-[0.1em] hover:bg-emerald-600 hover:text-white transition-all shadow-sm">
                  {isAdmin ? 'Editar Cadastro 📝' : 'Visualizar Ficha 👁️'}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {editingEmp && (
        <div className="fixed inset-0 bg-emerald-950/60 backdrop-blur-xl z-[9999] flex items-start justify-center p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-4xl max-h-[92vh] rounded-[3.5rem] shadow-[0_0_100px_rgba(0,0,0,0.4)] overflow-hidden flex flex-col animate-fadeIn border border-white/20 mt-4 md:mt-10 mb-10">
            <header className="p-10 border-b flex justify-between items-center bg-emerald-50/20">
              <div>
                <h3 className="text-2xl font-black text-emerald-900">Configuração de <span className="text-emerald-600 italic">Prontuário</span></h3>
                <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1">Gestão Individual ControlSST</p>
              </div>
              <button onClick={() => setEditingEmp(null)} className="w-12 h-12 flex items-center justify-center bg-white rounded-full hover:bg-red-50 hover:text-red-500 transition-all font-black border border-emerald-50 shadow-sm">✕</button>
            </header>

            <form onSubmit={handleSaveEdit} className="flex-1 overflow-y-auto p-10 space-y-10 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-2 italic">Nome Completo</label>
                  <input required disabled={!isAdmin} type="text" className="w-full bg-emerald-50/30 border-2 border-emerald-50 rounded-[1.5rem] p-4 font-black text-sm outline-none shadow-inner" value={editingEmp.name} onChange={e => setEditingEmp({...editingEmp, name: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-2 italic">Matrícula</label>
                  <input required disabled={!isAdmin} type="text" className="w-full bg-emerald-50/30 border-2 border-emerald-50 rounded-[1.5rem] p-4 font-black text-sm outline-none shadow-inner" value={editingEmp.registration} onChange={e => setEditingEmp({...editingEmp, registration: e.target.value})} />
                </div>
                {/* NOVO CAMPO DE FOTO */}
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-2 italic">Link da Foto (URL)</label>
                  <input disabled={!isAdmin} type="text" placeholder="https://exemplo.com/foto.jpg" className="w-full bg-emerald-50/30 border-2 border-emerald-50 rounded-[1.5rem] p-4 font-black text-sm outline-none shadow-inner" value={editingEmp.photoUrl || ''} onChange={e => setEditingEmp({...editingEmp, photoUrl: e.target.value})} />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-2 italic">Empresa / Unidade</label>
                  <input required disabled={!isAdmin} type="text" className="w-full bg-emerald-50/30 border-2 border-emerald-50 rounded-[1.5rem] p-4 font-black text-sm outline-none shadow-inner" value={editingEmp.company} onChange={e => setEditingEmp({...editingEmp, company: e.target.value})} />
