export default Layout;

import React, { useMemo, useState } from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { Employee, TrainingRecord } from '../types';
import { getDaysRemaining } from '../utils/calculations';

interface DashboardProps {
  employees: Employee[];
  isAdmin: boolean;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-gray-100 min-w-[180px] animate-fadeIn">
        <p className="font-black text-gray-900 mb-2 text-[10px] uppercase tracking-wider">{label || payload[0].name}</p>
        <div className="space-y-1">
          {payload.map((p: any, i: number) => (
            <div key={i} className="flex justify-between items-center gap-4">
              <span className="font-bold text-gray-500 text-[9px] uppercase">{p.name}</span>
              <span className="font-black text-emerald-600 text-sm" style={{ color: p.color || p.fill }}>{p.value}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees, isAdmin }) => {
  const [selectedCompany, setSelectedCompany] = useState<string>('Todas');

  const stats = useMemo(() => {
    const s = { 
      trained: 0, 
      expiring: 0, 
      expired: 0,
      expiring15: 0,
      expiring60: 0,
      recentTrainings: 0
    };

    const sectorMap: Record<string, { total: number, compliant: number }> = {};
    const filtered = selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);

    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    filtered.forEach(emp => {
      const sectorName = (emp.setor || 'Geral').trim();
      if (!sectorMap[sectorName]) sectorMap[sectorName] = { total: 0, compliant: 0 };
      sectorMap[sectorName].total++;

      let hasValidTraining = false;

      Object.entries(emp.trainings || {}).forEach(([_, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (record.status === 'VALID') {
          s.trained++;
          hasValidTraining = true;
        } else if (record.status === 'EXPIRING') {
          s.expiring++;
          hasValidTraining = true;
          if (days !== null && days <= 15) s.expiring15++;
          if (days !== null && days <= 60) s.expiring60++;
        } else if (record.status === 'EXPIRED') {
          s.expired++;
        }

        if (record.completionDate) {
          const compDate = new Date(record.completionDate);
          if (compDate >= thirtyDaysAgo) s.recentTrainings++;
        }
      });

      if (hasValidTraining) {
        sectorMap[sectorName].compliant++;
      }
    });

    return { 
      s, 
      sectorData: Object.entries(sectorMap).map(([name, data]) => ({ 
        name, 
        Total: data.total, 
        Capacitados: data.compliant 
      })).sort((a, b) => b.Total - a.Total),
      statusData: [
        { name: 'Válidos', value: s.trained, color: '#10B981' },
        { name: 'Vencendo', value: s.expiring, color: '#F59E0B' },
        { name: 'Vencidos', value: s.expired, color: '#EF4444' }
      ],
      filteredCount: filtered.length
    };
  }, [employees, selectedCompany]);

  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  return (
    <div className="space-y-8 pb-20 animate-fadeIn overflow-hidden">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-2xl md:text-4xl font-black text-gray-800 tracking-tighter italic">
            Dashboard <span className="text-emerald-600">Analytics</span>
          </h2>
          <p className="text-gray-400 font-bold uppercase text-[8px] md:text-[10px] tracking-[0.2em] mt-1 italic">Gestão Inteligente de SST</p>
        </div>
        <div className="bg-white p-2 rounded-2xl border border-gray-100 shadow-sm w-full md:w-auto">
          <select 
            value={selectedCompany} 
            onChange={(e) => setSelectedCompany(e.target.value)} 
            className="w-full bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-xs font-black outline-none border-none cursor-pointer"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </header>

      {/* CARDS DE INDICADORES PRINCIPAIS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-red-100 flex items-center gap-6 group hover:scale-[1.02] transition-all">
          <div className="w-14 h-14 bg-red-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-red-500 group-hover:text-white transition-colors">🚨</div>
          <div>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Crítico (15 dias)</p>
            <h4 className="text-3xl font-black text-red-600 tracking-tighter">{stats.s.expiring15}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-amber-100 flex items-center gap-6 group hover:scale-[1.02] transition-all">
          <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-amber-500 group-hover:text-white transition-colors">⏳</div>
          <div>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Alerta (60 dias)</p>
            <h4 className="text-3xl font-black text-amber-500 tracking-tighter">{stats.s.expiring60}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-emerald-100 flex items-center gap-6 group hover:scale-[1.02] transition-all">
          <div className="w-14 h-14 bg-emerald-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-emerald-500 group-hover:text-white transition-colors">🔥</div>
          <div>
            <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Realizados (30 dias)</p>
            <h4 className="text-3xl font-black text-emerald-600 tracking-tighter">{stats.s.recentTrainings}</h4>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* GRÁFICO DE STATUS GLOBAL */}
        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-gray-100 overflow-hidden">
           <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6 text-center">Saúde Normativa Global</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.statusData} cx="50%" cy="50%" innerRadius={70} outerRadius={100} paddingAngle={8} dataKey="value">
                  {stats.statusData.map((e, i) => <Cell key={i} fill={e.color} stroke="none" />)}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
                <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{ fontSize: '9px', fontWeight: '900', textTransform: 'uppercase' }} />
              </PieChart>
            </ResponsiveContainer>
           </div>
        </div>

        {/* GRÁFICO DE CONFORMIDADE POR SETOR - AGORA HORIZONTAL */}
        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-gray-100 overflow-hidden">
           <h3 className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-6 text-center">Efetivo Capacitado por Setor</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart layout="vertical" data={stats.sectorData} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{ fontSize: 9, fontWeight: 900, fill: '#64748b' }} width={80} />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: '#f8fafc' }} />
                <Legend verticalAlign="top" align="right" wrapperStyle={{ fontSize: '9px', fontWeight: '900', textTransform: 'uppercase', paddingBottom: '20px' }} />
                <Bar dataKey="Total" fill="#e2e8f0" radius={[0, 10, 10, 0]} barSize={12} name="Total Equipe" />
                <Bar dataKey="Capacitados" fill="#10b981" radius={[0, 10, 10, 0]} barSize={12} name="Com Curso Válido" />
              </BarChart>
            </ResponsiveContainer>
           </div>
        </div>
      </div>

      {/* RESUMO DE CARDS INFERIORES - LABELS ATUALIZADAS */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        {[
          { label: 'Total Cursos Ativos', val: stats.s.trained, color: 'text-emerald-600', bg: 'bg-emerald-50', icon: '✅' },
          { label: 'Total Em Vencimento', val: stats.s.expiring, color: 'text-amber-500', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Total Cursos Expirados', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Total Efetivo', val: stats.filteredCount, color: 'text-blue-600', bg: 'bg-blue-50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100 hover:shadow-md transition-all">
            <div className="flex justify-between items-center">
              <span className={`text-xl p-3 rounded-2xl ${item.bg}`}>{item.icon}</span>
              <span className={`text-3xl font-black tracking-tighter ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-4 text-[9px] font-black text-gray-400 uppercase tracking-widest leading-none">{item.label}</p>
          </div>
        ))}
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { calculateTrainingStatus, getExpiryDate, getDaysRemaining } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSetor, setSelectedSetor] = useState('Todos');
  const [selectedCompany, setSelectedCompany] = useState('Todas');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  const setores = useMemo(() => ['Todos', ...Array.from(new Set(employees.map(e => (e.setor || 'Geral').trim())))], [employees]);
  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  const filtered = employees.filter(e => {
    const name = e.name || '';
    const reg = e.registration || '';
    const role = e.role || '';
    const search = searchTerm.toLowerCase();

    const matchesSearch = name.toLowerCase().includes(search) || 
                         reg.includes(search) ||
                         role.toLowerCase().includes(search);
    const matchesSetor = selectedSetor === 'Todos' || e.setor === selectedSetor;
    const matchesCompany = selectedCompany === 'Todas' || e.company === selectedCompany;
    return matchesSearch && matchesSetor && matchesCompany;
  });

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      onUpdate();
    } catch (err) {
      alert("Erro ao salvar cadastro.");
    }
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;
    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);
    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-gray-800 italic tracking-tighter">Gestão de <span className="text-emerald-600">Equipe</span></h2>
          <p className="text-[10px] font-bold text-gray-400 uppercase tracking-[0.2em] mt-1 italic">Controle Multi-Empresa ControlSST</p>
        </div>
        {isAdmin && (
          <button 
            onClick={() => setEditingEmp({ id: `emp-${Date.now()}`, name: '', registration: '', role: '', setor: '', company: '', trainings: {} })}
            className="w-full md:w-auto bg-[#064E3B] text-emerald-400 px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-105 transition-all flex items-center justify-center gap-3"
          >
            <span>➕ Novo Colaborador</span>
          </button>
        )}
      </div>

      <div className="bg-white p-6 rounded-[2.5rem] border border-gray-100 shadow-sm flex flex-col md:flex-row gap-6">
        <div className="flex-1">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Empresa</label>
          <select value={selectedCompany} onChange={(e) => setSelectedCompany(e.target.value)} className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none shadow-inner">
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="flex-1">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Setor</label>
          <select value={selectedSetor} onChange={(e) => setSelectedSetor(e.target.value)} className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none shadow-inner">
            {setores.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div className="flex-[2]">
          <label className="text-[9px] font-black text-gray-400 uppercase ml-1 mb-2 block tracking-widest italic">Filtro Rápido</label>
          <input type="text" placeholder="Pesquisar por Nome ou RE..." className="w-full px-5 py-3 bg-emerald-50/50 border-2 border-transparent rounded-2xl text-xs font-bold shadow-inner outline-none focus:bg-white focus:border-emerald-500 transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filtered.map(emp => (
          <div key={emp.id} className="bg-white rounded-[2.5rem] border border-gray-100 hover:border-emerald-300 transition-all shadow-sm group">
            <div className="p-6 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
              <div className="flex items-center gap-5 flex-1 min-w-0">
                <div className="w-14 h-14 md:w-16 md:h-16 text-white rounded-[1.8rem] flex items-center justify-center font-black text-xl shadow-lg relative overflow-hidden bg-emerald-50 flex-shrink-0 border border-emerald-100">
                  {emp.photoUrl ? (
                    <img src={emp.photoUrl} alt={emp.name} className="w-full h-full object-cover" />
                  ) : (
                    <span className="relative z-10 text-emerald-600 opacity-30">{emp.name?.charAt(0) || '?'}</span>
                  )}
                </div>

                <div className="min-w-0 flex-1">
                  <h3 className="text-md md:text-lg font-black text-gray-800 leading-none mb-1 uppercase tracking-tight truncate">{emp.name}</h3>
                  <div className="flex flex-col gap-1">
                    <div className="flex flex-wrap items-center gap-2">
                      <span className="text-[8px] font-black bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full uppercase">{emp.company}</span>
                      <p className="text-[9px] text-gray-400 font-bold uppercase tracking-tight">RE: <span className="text-gray-900">{emp.registration}</span></p>
                    </div>
                    <p className="text-[9px] text-gray-500 font-black uppercase tracking-tight truncate">
                      <span className="text-emerald-700">{emp.role}</span> • <span className="text-emerald-500">{emp.setor}</span>
                    </p>
                  </div>
                </div>
              </div>

              {/* Bolinhas de Status com Tooltip Enriquecido */}
              <div className="flex flex-wrap gap-1.5 lg:justify-end max-w-full lg:max-w-xs">
                {NR_COURSES.map(course => {
                  const training = emp.trainings[course.id];
                  const status = training?.status || 'NOT_TRAINED';
                  const days = getDaysRemaining(training?.expiryDate);
                  const complDate = training?.completionDate ? new Date(training.completionDate).toLocaleDateString('pt-BR') : 'Não Realizado';
                  const expDate = training?.expiryDate ? new Date(training.expiryDate).toLocaleDateString('pt-BR') : 'N/A';

                  // Texto do Tooltip solicitado
                  const tooltipText = `CURSO: ${course.name}
REALIZAÇÃO: ${complDate}
VALIDADE: ${expDate}
STATUS: ${STATUS_CONFIG[status].label}
DIAS RESTANTES: ${days !== null ? (days < 0 ? `Expirado há ${Math.abs(days)} dias` : `${days} dias`) : 'N/A'}`;

                  return (
                    <div 
                      key={course.id} 
                      title={tooltipText}
                      className={`w-5 h-5 rounded-full flex items-center justify-center text-[7px] font-black text-white shadow-sm transition-transform hover:scale-125 cursor-help ${STATUS_CONFIG[status].color}`}
                    >
                      {course.id.replace('NR', '')}
                    </div>
                  );
                })}
              </div>

              <div className="flex gap-2 w-full lg:w-auto">
                <button onClick={() => setEditingEmp(emp)} className="flex-1 lg:flex-none bg-emerald-50 text-emerald-700 px-6 py-3 rounded-2xl text-[9px] font-black uppercase tracking-[0.1em] hover:bg-emerald-600 hover:text-white transition-all">
                  {isAdmin ? 'Editar 📝' : 'Ficha 👁️'}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {/* Modal de Edição */}
      {editingEmp && (
        <div className="fixed inset-0 bg-emerald-950/60 backdrop-blur-md z-[9999] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl max-h-[90vh] rounded-[2.5rem] md:rounded-[3.5rem] shadow-2xl overflow-hidden flex flex-col animate-fadeIn">
            <header className="p-6 md:p-10 border-b flex justify-between items-center bg-emerald-50/20">
              <div>
                <h3 className="text-xl md:text-2xl font-black text-emerald-900">Configuração de <span className="text-emerald-600 italic">Prontuário</span></h3>
                <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-1">Gestão Individual ControlSST</p>
              </div>
              <button onClick={() => setEditingEmp(null)} className="w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-white rounded-full border border-emerald-50 shadow-sm text-lg">✕</button>
            </header>

            <form onSubmit={handleSaveEdit} className="flex-1 overflow-y-auto p-6 md:p-10 space-y-8 custom-scrollbar">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {[
                  { label: 'Nome Completo', key: 'name' },
                  { label: 'Matrícula', key: 'registration' },
                  { label: 'Link da Foto', key: 'photoUrl' },
                  { label: 'Empresa', key: 'company' },
                  { label: 'Setor', key: 'setor' },
                  { label: 'Função', key: 'role' }
                ].map(field => (
                  <div key={field.key} className="space-y-2">
                    <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-2">{field.label}</label>
                    <input 
                      disabled={!isAdmin} required={field.key !== 'photoUrl'} type="text" 
                      className="w-full bg-emerald-50/30 border-2 border-emerald-50 rounded-2xl p-4 font-black text-sm outline-none" 
                      value={(editingEmp as any)[field.key] || ''} 
                      onChange={e => setEditingEmp({...editingEmp, [field.key]: e.target.value})} 
                    />
                  </div>
                ))}
              </div>

              <div className="pt-8 border-t border-emerald-50">
                <h4 className="text-[10px] font-black text-emerald-900 uppercase tracking-[0.3em] mb-6 italic">Cursos Realizados</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                  {NR_COURSES.map(course => (
                    <div key={course.id} className="bg-emerald-50/20 p-4 rounded-2xl border border-emerald-50">
                      <label className="block text-[8px] font-black text-emerald-700 uppercase mb-2">{course.name}</label>
                      <input 
                        disabled={!isAdmin} type="date" 
                        className="w-full bg-white border border-emerald-100 rounded-xl p-2 text-xs font-black outline-none" 
                        value={editingEmp.trainings[course.id]?.completionDate || ''} 
                        onChange={e => updateTrainingDate(course.id, e.target.value)} 
                      />
                    </div>
                  ))}
                </div>
              </div>
            </form>

            <footer className="p-6 md:p-10 border-t bg-emerald-50/30 flex gap-4">
              <button type="button" onClick={() => setEditingEmp(null)} className="flex-1 py-4 text-gray-400 font-black uppercase text-[10px] tracking-widest">Cancelar</button>
              {isAdmin && (
                <button onClick={handleSaveEdit} className="flex-[2] py-4 bg-[#064E3B] text-emerald-400 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-xl">SALVAR ALTERAÇÕES 💾</button>
              )}
            </footer>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeView;

import React, { useState, useEffect } from 'react';
import { StorageService } from '../services/storage';
import { CompanyProfile, AdminProfile } from '../types';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  setActiveTab: (tab: string) => void;
  userRole: 'admin' | 'visitor';
  onLogout: () => void;
  onRefreshData?: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, activeTab, setActiveTab, userRole, onLogout, onRefreshData }) => {
  const isAdmin = userRole === 'admin';
  const [config, setConfig] = useState<{company: CompanyProfile, admin: AdminProfile} | null>(null);
  const [isSyncing, setIsSyncing] = useState(false);
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const hasSheetsUrl = !!StorageService.getSheetsUrl();

  useEffect(() => {
    StorageService.getAppSettings().then(setConfig);
  }, []);

  const handleSync = async () => {
    setIsSyncing(true);
    const success = await StorageService.syncWithSheets();
    if (success && onRefreshData) {
      onRefreshData();
    }
    setIsSyncing(false);
  };

  const handleTabChange = (tabId: string) => {
    setActiveTab(tabId);
    setIsMobileMenuOpen(false);
  };

  if (!config) return null;

  const allTabs = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', adminOnly: false },
    { id: 'employees', label: 'Funcionários', icon: '👷', adminOnly: false },
    { id: 'reports', label: 'Relatórios', icon: '📋', adminOnly: false },
    { id: 'matrix', label: 'Matriz de Cursos', icon: '📜', adminOnly: false },
    { id: 'import', label: 'Importação', icon: '📥', adminOnly: true },
