           <h3 className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest mb-6 text-center">Saúde Normativa Global</h3>
           <p className="absolute top-14 left-1/2 -translate-x-1/2 text-[8px] font-black text-emerald-400 uppercase tracking-tighter opacity-50">Clique nas fatias para detalhes</p>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie 
                  data={stats.statusData} 
