              </PieChart>
            </ResponsiveContainer>
           </div>
        </div>

        {/* GRÁFICO DE CONFORMIDADE POR SETOR */}
        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-emerald-100 overflow-hidden hover:shadow-xl transition-shadow">
