                   {detailModal.status === 'EXPIRED' ? '🚨' : detailModal.status === 'EXPIRING' ? '⏳' : '✅'}
                </div>
                <div>
                  <h3 className="text-xl md:text-2xl font-black text-emerald-900 italic tracking-tighter">
                    Pendências: <span className={STATUS_CONFIG[detailModal.status]?.text || ''}>{STATUS_CONFIG[detailModal.status]?.label || 'Lista'}</span>
                  </h3>
                  <p className="text-[9px] font-bold text-emerald-700/40 uppercase tracking-widest">Relatório Analítico por Setor</p>
                </div>
              </div>
              <div className="flex gap-4">
                <button 
                  onClick={() => window.print()}
                  className="bg-emerald-100 text-emerald-700 px-6 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-700 hover:text-white transition-all shadow-sm"
                >
                  Imprimir 🖨️
                </button>
                <button 
                  onClick={() => setDetailModal(null)}
                  className="w-12 h-12 flex items-center justify-center bg-red-50 text-red-500 rounded-full hover:bg-red-500 hover:text-white transition-all text-xl"
                >
                  ✕
                </button>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-8 custom-scrollbar">
              {detailModal.data.length > 0 ? (
                <div className="space-y-8">
                  {detailModal.data.map((sec, idx) => (
                    <div key={idx} className="space-y-4">
                      <div className="flex items-center gap-3">
                         <span className="w-10 h-0.5 bg-emerald-200 rounded-full"></span>
                         <h4 className="text-[11px] font-black text-emerald-600 uppercase tracking-[0.2em] italic">{sec.sector}</h4>
                         <span className="bg-emerald-50 text-emerald-700 px-2 py-0.5 rounded-full text-[8px] font-black">{sec.list.length}</span>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        {sec.list.map((item: any, i: number) => (
                          <div key={i} className="bg-emerald-50/30 border border-emerald-50 p-5 rounded-[1.8rem] flex justify-between items-center group hover:border-emerald-200 transition-colors">
                            <div>
                               <p className="text-sm font-black text-emerald-950 uppercase leading-none mb-1">{item.name}</p>
                               <div className="flex items-center gap-3">
                                  <span className="text-[9px] font-bold text-emerald-700/40 uppercase tracking-tighter">RE: {item.reg}</span>
                                  <span className="text-[10px] font-black text-emerald-600 italic">| {item.course}</span>
                               </div>
                            </div>
                            <div className="text-right">
                               <p className="text-[10px] font-black text-emerald-900 leading-none">
                                 {item.expiry ? new Date(item.expiry).toLocaleDateString('pt-BR') : '--/--/--'}
                               </p>
                               <p className={`text-[8px] font-black uppercase mt-1 ${item.days < 0 ? 'text-red-500' : 'text-amber-500'}`}>
                                 {item.days < 0 ? `Expirado (${Math.abs(item.days)}d)` : `${item.days} dias restantes`}
                               </p>
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="h-full flex flex-col items-center justify-center text-center py-20">
                   <span className="text-6xl opacity-20 mb-6">🏜️</span>
                   <p className="text-emerald-800/40 font-black uppercase text-xs tracking-widest">Nenhuma pendência encontrada para este status.</p>
                </div>
              )}
            </div>

            <footer className="p-6 text-center border-t border-emerald-50 bg-emerald-50/20">
               <p className="text-[8px] font-black text-emerald-800/20 uppercase tracking-[0.4em]">Controle de Auditoria Interna ControlSST</p>
            </footer>
          </div>
        </div>
      )}

      {/* ÁREA DE IMPRESSÃO OCULTA PARA O MODAL (PRINT-ONLY) */}
      <div className="hidden print:block fixed inset-0 bg-white p-12 text-black z-[99999]">
         <div className="border-b-4 border-emerald-900 pb-8 mb-8 flex justify-between items-end">
            <div>
              <h1 className="text-4xl font-black tracking-tighter italic">Relatório de <span className="text-emerald-600">Convocação</span></h1>
              <p className="text-sm font-bold text-gray-400 uppercase tracking-widest mt-2">Gestão de Treinamentos ControlSST</p>
            </div>
            <div className="text-right">
               <p className="text-xs font-black uppercase">Status: {detailModal?.status}</p>
               <p className="text-[10px] font-bold">Gerado em: {new Date().toLocaleString()}</p>
            </div>
         </div>

         {detailModal?.data.map((sec, idx) => (
           <div key={idx} className="mb-8 break-inside-avoid">
             <h2 className="text-xl font-black uppercase bg-gray-100 p-3 mb-4 border-l-8 border-emerald-600">{sec.sector}</h2>
