    </div>
  );
};

export default Dashboard;

import React, { useState, useMemo } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { calculateTrainingStatus, getExpiryDate, getDaysRemaining } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSetor, setSelectedSetor] = useState('Todos');
  const [selectedCompany, setSelectedCompany] = useState('Todas');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);

  // Normalização de string para comparação robusta
  const normalize = (val: any) => String(val || '').trim();

  // Filtro de Empresas (Sempre baseado na lista total)
  const companies = useMemo(() => {
    const c = new Set(employees.map(e => normalize(e.company || 'Empresa Padrão')));
    return ['Todas', ...Array.from(c)].sort();
  }, [employees]);

  // Filtro de Setores Dinâmico (Cascata: só mostra setores da empresa selecionada)
  const setores = useMemo(() => {
    const employeesInCompany = selectedCompany === 'Todas' 
      ? employees 
      : employees.filter(e => normalize(e.company) === selectedCompany);

    const s = new Set(employeesInCompany.map(e => normalize(e.setor || 'Geral')));
    return ['Todos', ...Array.from(s)].sort();
  }, [employees, selectedCompany]);

  // Lógica de filtragem principal
  const filtered = useMemo(() => {
    return employees.filter(e => {
      // 1. Filtro de Empresa
      const matchesCompany = selectedCompany === 'Todas' || normalize(e.company) === selectedCompany;
      if (!matchesCompany) return false;

      // 2. Filtro de Setor
      const matchesSetor = selectedSetor === 'Todos' || normalize(e.setor) === selectedSetor;
      if (!matchesSetor) return false;

      // 3. Filtro Rápido (Busca)
      const search = searchTerm.toLowerCase().trim();
      if (!search) return true;

      const name = normalize(e.name).toLowerCase();
      const reg = normalize(e.registration).toLowerCase();
      const role = normalize(e.role).toLowerCase();

      return name.includes(search) || reg.includes(search) || role.includes(search);
    });
  }, [employees, searchTerm, selectedSetor, selectedCompany]);

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      onUpdate();
    } catch (err) {
      alert("Erro ao salvar cadastro.");
    }
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;
    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);
    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  const clearFilters = () => {
    setSearchTerm('');
    setSelectedSetor('Todos');
    setSelectedCompany('Todas');
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-emerald-900 italic tracking-tighter">Gestão de <span className="text-emerald-600">Equipe</span></h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="text-[10px] font-bold text-emerald-700/60 uppercase tracking-[0.2em] italic">ControlSST</span>
            <span className="w-1 h-1 bg-emerald-300 rounded-full"></span>
            <span className="text-[10px] font-black text-emerald-500 uppercase">{filtered.length} Funcionários Encontrados</span>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
           <button 
            onClick={clearFilters}
            className="flex-1 md:flex-none bg-white border-2 border-emerald-100 text-emerald-600 px-6 py-4 rounded-2xl font-black text-[9px] uppercase tracking-widest hover:bg-emerald-50 transition-all active:scale-95"
          >
            Limpar Filtros 🧹
          </button>
          {isAdmin && (
            <button 
              onClick={() => setEditingEmp({ id: `emp-${Date.now()}`, name: '', registration: '', role: '', setor: '', company: '', trainings: {} })}
              className="flex-[2] md:flex-none bg-[#064E3B] text-emerald-400 px-8 py-4 rounded-[1.5rem] font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-3"
            >
              <span>➕ Novo Colaborador</span>
            </button>
          )}
        </div>
      </div>

      <div className="bg-white p-6 rounded-[2.5rem] border border-emerald-100 shadow-sm flex flex-col md:flex-row gap-6">
        <div className="flex-1">
          <label className="text-[9px] font-black text-emerald-800/40 uppercase ml-1 mb-2 block tracking-widest italic">Empresa</label>
          <select 
            value={selectedCompany} 
            onChange={(e) => {
              setSelectedCompany(e.target.value);
              setSelectedSetor('Todos'); // Resetar setor ao mudar empresa para evitar inconsistência
            }} 
            className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none shadow-inner focus:border-emerald-500 transition-colors"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="flex-1">
          <label className="text-[9px] font-black text-emerald-800/40 uppercase ml-1 mb-2 block tracking-widest italic">Setor</label>
          <select 
            value={selectedSetor} 
            onChange={(e) => setSelectedSetor(e.target.value)} 
            className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none shadow-inner focus:border-emerald-500 transition-colors"
          >
            {setores.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div className="flex-[2]">
          <label className="text-[9px] font-black text-emerald-800/40 uppercase ml-1 mb-2 block tracking-widest italic">Filtro Rápido (Nome, RE, Função)</label>
          <div className="relative">
            <input 
              type="text" 
              placeholder="Digite para pesquisar..." 
              className="w-full px-5 py-3 pr-12 bg-emerald-50/50 border-2 border-transparent rounded-2xl text-xs font-bold shadow-inner outline-none focus:bg-white focus:border-emerald-500 transition-all" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
            />
            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-emerald-300">🔍</span>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 gap-4">
        {filtered.length > 0 ? filtered.map(emp => (
          <div key={emp.id} className="bg-white rounded-[2.5rem] border border-emerald-100 hover:border-emerald-300 transition-all shadow-sm group active:scale-[0.98]">
            <div className="p-6 flex flex-col lg:flex-row lg:items-center justify-between gap-6">
              <div className="flex items-center gap-5 flex-1 min-w-0">
                <div className="w-14 h-14 md:w-16 md:h-16 text-white rounded-[1.8rem] flex items-center justify-center font-black text-xl shadow-lg relative overflow-hidden bg-emerald-50 flex-shrink-0 border border-emerald-200">
                  {emp.photoUrl ? (
                    <img src={emp.photoUrl} alt={emp.name} className="w-full h-full object-cover" />
                  ) : (
                    <span className="relative z-10 text-emerald-600 opacity-30 font-black uppercase tracking-widest">{emp.name?.charAt(0) || '?'}</span>
                  )}
                </div>

                <div className="min-w-0 flex-1">
                  <h3 className="text-md md:text-lg font-black text-emerald-900 leading-none mb-1 uppercase tracking-tight truncate">{emp.name}</h3>
                  <div className="flex flex-col gap-1">
                    <div className="flex flex-wrap items-center gap-2">
                      <span className="text-[8px] font-black bg-emerald-100 text-emerald-700 px-2 py-0.5 rounded-full uppercase">{emp.company}</span>
                      <p className="text-[9px] text-emerald-800/40 font-bold uppercase tracking-tight">RE: <span className="text-emerald-900">{emp.registration}</span></p>
                    </div>
                    <p className="text-[9px] text-emerald-600 font-black uppercase tracking-tight truncate">
                      <span className="text-emerald-700">{emp.role}</span> • <span className="text-emerald-500">{emp.setor}</span>
                    </p>
                  </div>
                </div>
              </div>

              <div className="flex flex-wrap gap-1.5 lg:justify-end max-w-full lg:max-w-xs">
                {NR_COURSES.map(course => {
                  const training = emp.trainings[course.id];
                  const status = training?.status || 'NOT_TRAINED';
                  const days = getDaysRemaining(training?.expiryDate);
                  const complDate = training?.completionDate ? new Date(training.completionDate).toLocaleDateString('pt-BR') : 'Não Realizado';
                  const expDate = training?.expiryDate ? new Date(training.expiryDate).toLocaleDateString('pt-BR') : 'N/A';

                  const tooltipText = `CURSO: ${course.name}\nREALIZAÇÃO: ${complDate}\nVALIDADE: ${expDate}\nSTATUS: ${STATUS_CONFIG[status].label}\nDIAS RESTANTES: ${days !== null ? (days < 0 ? `Expirado há ${Math.abs(days)} dias` : `${days} dias`) : 'N/A'}`;

                  return (
                    <div 
                      key={course.id} 
                      title={tooltipText}
                      className={`w-5 h-5 rounded-full flex items-center justify-center text-[7px] font-black text-white shadow-sm transition-transform hover:scale-125 cursor-help ${STATUS_CONFIG[status].color}`}
                    >
                      {course.id.replace('NR', '')}
                    </div>
                  );
                })}
              </div>

              <div className="flex gap-2 w-full lg:w-auto mt-2 lg:mt-0">
                <button onClick={() => setEditingEmp(emp)} className="flex-1 lg:flex-none bg-emerald-100 text-emerald-700 px-6 py-4 rounded-2xl text-[9px] font-black uppercase tracking-[0.1em] hover:bg-emerald-600 hover:text-white transition-all active:scale-90">
                  {isAdmin ? 'Editar 📝' : 'Ficha 👁️'}
                </button>
              </div>
            </div>
          </div>
        )) : (
          <div className="bg-white p-20 rounded-[2.5rem] border-2 border-dashed border-emerald-100 text-center animate-fadeIn">
            <span className="text-4xl mb-4 block">🔍</span>
            <p className="text-emerald-800/40 font-black uppercase text-xs tracking-widest mb-4">Nenhum colaborador encontrado com estes filtros.</p>
            <button onClick={clearFilters} className="text-emerald-600 font-black text-[10px] uppercase underline hover:text-emerald-800">Limpar todos os filtros</button>
          </div>
        )}
      </div>

      {editingEmp && (
        <div className="fixed inset-0 bg-emerald-950/70 backdrop-blur-md z-[1000] flex items-start justify-center overflow-y-auto px-4 py-8 md:py-16">
          <div className="bg-white w-full max-w-4xl rounded-[2.5rem] md:rounded-[3.5rem] shadow-[0_35px_60px_-15px_rgba(0,0,0,0.5)] overflow-hidden flex flex-col animate-fadeIn relative">
            <header className="p-6 md:p-10 border-b flex justify-between items-center bg-emerald-50/40 sticky top-0 z-10 backdrop-blur-sm border-emerald-100">
              <div>
                <h3 className="text-xl md:text-2xl font-black text-emerald-900 leading-none">Configuração de <span className="text-emerald-600 italic">Prontuário</span></h3>
                <p className="text-[9px] font-bold text-emerald-700/60 uppercase tracking-widest mt-2">Gestão Individual ControlSST</p>
              </div>
              <button 
                onClick={() => setEditingEmp(null)} 
                className="w-10 h-10 md:w-12 md:h-12 flex items-center justify-center bg-white rounded-full border border-emerald-100 shadow-sm text-lg hover:bg-red-50 hover:text-red-500 transition-colors active:scale-90"
              >
                ✕
              </button>
            </header>

            <form onSubmit={handleSaveEdit} className="p-6 md:p-10 space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                {[
                  { label: 'Nome Completo', key: 'name' },
                  { label: 'Matrícula', key: 'registration' },
                  { label: 'Link da Foto', key: 'photoUrl' },
                  { label: 'Empresa', key: 'company' },
                  { label: 'Setor', key: 'setor' },
                  { label: 'Função', key: 'role' }
                ].map(field => (
                  <div key={field.key} className="space-y-2">
                    <label className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest ml-2">{field.label}</label>
                    <input 
                      disabled={!isAdmin} required={field.key !== 'photoUrl'} type="text" 
                      className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-black text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner" 
                      value={(editingEmp as any)[field.key] || ''} 
                      onChange={e => setEditingEmp({...editingEmp, [field.key]: e.target.value})} 
                    />
                  </div>
                ))}
              </div>

              <div className="pt-10 border-t border-emerald-100">
                <h4 className="text-[10px] font-black text-emerald-900 uppercase tracking-[0.3em] mb-8 italic flex items-center gap-2">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  Datas de Treinamentos
                </h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {NR_COURSES.map(course => (
                    <div key={course.id} className="bg-emerald-50/40 p-5 rounded-3xl border border-emerald-100 hover:border-emerald-300 transition-colors shadow-inner">
                      <label className="block text-[8px] font-black text-emerald-700 uppercase mb-3 tracking-tighter">{course.name}</label>
                      <input 
                        disabled={!isAdmin} type="date" 
                        className="w-full bg-white border border-emerald-200 rounded-xl p-3 text-xs font-black outline-none focus:border-emerald-500 transition-all shadow-sm" 
                        value={editingEmp.trainings[course.id]?.completionDate || ''} 
                        onChange={e => updateTrainingDate(course.id, e.target.value)} 
                      />
                    </div>
                  ))}
                </div>
              </div>

              <footer className="pt-10 border-t border-emerald-100 flex flex-col md:flex-row gap-4">
                <button type="button" onClick={() => setEditingEmp(null)} className="flex-1 py-5 text-emerald-800/40 font-black uppercase text-[10px] tracking-widest hover:text-red-500 transition-colors order-2 md:order-1">Cancelar</button>
                {isAdmin && (
                  <button onClick={handleSaveEdit} className="flex-[2] py-5 bg-[#064E3B] text-emerald-400 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all order-1 md:order-2">
                    CONSOLIDAR ALTERAÇÕES 💾
                  </button>
                )}
              </footer>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeView;

import React, { useMemo, useState } from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { Employee, TrainingRecord, TrainingStatus } from '../types';
import { getDaysRemaining } from '../utils/calculations';
import { STATUS_CONFIG, NR_COURSES } from '../constants';

interface DashboardProps {
  employees: Employee[];
  isAdmin: boolean;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-emerald-100 min-w-[180px] animate-fadeIn">
        <p className="font-black text-emerald-900 mb-2 text-[10px] uppercase tracking-wider">{label || payload[0].name}</p>
        <div className="space-y-1">
          {payload.map((p: any, i: number) => (
            <div key={i} className="flex justify-between items-center gap-4">
              <span className="font-bold text-emerald-800/40 text-[9px] uppercase">{p.name}</span>
              <span className="font-black text-emerald-600 text-sm" style={{ color: p.color || p.fill }}>{p.value}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees, isAdmin }) => {
  const [selectedCompany, setSelectedCompany] = useState<string>('Todas');
  const [detailModal, setDetailModal] = useState<{ status: TrainingStatus | 'PENDING', data: any[] } | null>(null);

  const stats = useMemo(() => {
    const s = { 
      trained: 0, 
      expiring: 0, 
      expired: 0,
      expiring15: 0,
      expiring60: 0,
      recentTrainings: 0
    };

    const sectorMap: Record<string, { total: number, compliant: number }> = {};
    const filtered = selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);

    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    filtered.forEach(emp => {
      const sectorName = (emp.setor || 'Geral').trim();
      if (!sectorMap[sectorName]) sectorMap[sectorName] = { total: 0, compliant: 0 };
      sectorMap[sectorName].total++;

      let hasValidTraining = false;

      Object.entries(emp.trainings || {}).forEach(([_, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (record.status === 'VALID') {
          s.trained++;
          hasValidTraining = true;
        } else if (record.status === 'EXPIRING') {
          s.expiring++;
          hasValidTraining = true;
          if (days !== null && days <= 15) s.expiring15++;
          if (days !== null && days <= 60) s.expiring60++;
        } else if (record.status === 'EXPIRED') {
          s.expired++;
        }

        if (record.completionDate) {
          const compDate = new Date(record.completionDate);
          if (compDate >= thirtyDaysAgo) s.recentTrainings++;
        }
      });

      if (hasValidTraining) {
        sectorMap[sectorName].compliant++;
      }
    });

    return { 
      s, 
      sectorData: Object.entries(sectorMap).map(([name, data]) => ({ 
        name, 
        Total: data.total, 
        Capacitados: data.compliant 
      })).sort((a, b) => b.Total - a.Total),
      statusData: [
        { name: 'Válidos', value: s.trained, color: '#10B981', status: 'VALID' },
        { name: 'Vencendo', value: s.expiring, color: '#F59E0B', status: 'EXPIRING' },
        { name: 'Vencidos', value: s.expired, color: '#EF4444', status: 'EXPIRED' }
      ],
      filteredCount: filtered.length
    };
  }, [employees, selectedCompany]);

  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  const handlePieClick = (data: any) => {
    // Pegar o status da fatia clicada
    const status = data.status || data.payload?.status;
    if (!status) return;

    // Coletar pendências agrupadas por setor
    const issuesBySector: Record<string, any[]> = {};
    const filtered = selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);

    filtered.forEach(emp => {
      Object.entries(emp.trainings).forEach(([cid, r]) => {
        const record = r as TrainingRecord;
        if (record.status === status) {
          const sec = (emp.setor || 'Geral').trim();
          if (!issuesBySector[sec]) issuesBySector[sec] = [];

          // Buscar o nome amigável do curso
          const courseInfo = NR_COURSES.find(c => c.id === cid);

          issuesBySector[sec].push({
            name: emp.name,
            reg: emp.registration,
            courseId: cid,
            courseName: courseInfo?.name || cid,
            expiry: record.expiryDate,
            days: getDaysRemaining(record.expiryDate)
          });
        }
      });
    });

    setDetailModal({ 
      status, 
      data: Object.entries(issuesBySector).map(([sector, list]) => ({ sector, list })) 
    });
  };

  return (
    <div className="space-y-8 pb-20 animate-fadeIn overflow-hidden">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-2xl md:text-4xl font-black text-emerald-900 tracking-tighter italic">
            Dashboard <span className="text-emerald-600">Analytics</span>
          </h2>
          <p className="text-emerald-800/40 font-bold uppercase text-[8px] md:text-[10px] tracking-[0.2em] mt-1 italic">Gestão Inteligente de SST</p>
        </div>
        <div className="bg-white p-2 rounded-2xl border border-emerald-100 shadow-sm w-full md:w-auto">
          <select 
            value={selectedCompany} 
            onChange={(e) => setSelectedCompany(e.target.value)} 
            className="w-full bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-xs font-black outline-none border-none cursor-pointer hover:bg-emerald-100 transition-colors"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </header>

      {/* CARDS DE INDICADORES PRINCIPAIS */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-red-100 flex items-center gap-6 group hover:shadow-lg hover:-translate-y-1 transition-all active:scale-95 cursor-default">
          <div className="w-14 h-14 bg-red-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-red-500 group-hover:text-white transition-colors">🚨</div>
          <div>
            <p className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest">Crítico (15 dias)</p>
            <h4 className="text-3xl font-black text-red-600 tracking-tighter">{stats.s.expiring15}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-amber-100 flex items-center gap-6 group hover:shadow-lg hover:-translate-y-1 transition-all active:scale-95 cursor-default">
          <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-amber-500 group-hover:text-white transition-colors">⏳</div>
          <div>
            <p className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest">Alerta (60 dias)</p>
            <h4 className="text-3xl font-black text-amber-500 tracking-tighter">{stats.s.expiring60}</h4>
          </div>
        </div>
        <div className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-emerald-100 flex items-center gap-6 group hover:shadow-lg hover:-translate-y-1 transition-all active:scale-95 cursor-default">
          <div className="w-14 h-14 bg-emerald-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-emerald-500 group-hover:text-white transition-colors">🔥</div>
          <div>
            <p className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest">Realizados (30 dias)</p>
            <h4 className="text-3xl font-black text-emerald-600 tracking-tighter">{stats.s.recentTrainings}</h4>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* GRÁFICO DE STATUS GLOBAL COM CLIQUE */}
        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-emerald-100 overflow-hidden hover:shadow-xl transition-shadow relative group">
           <h3 className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest mb-6 text-center">Saúde Normativa Global</h3>
           <div className="absolute top-14 left-1/2 -translate-x-1/2 bg-emerald-900 text-white text-[7px] font-black px-3 py-1 rounded-full uppercase tracking-tighter opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none">
             Clique em uma cor para detalhes
           </div>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie 
                  data={stats.statusData} 
                  cx="50%" 
                  cy="50%" 
                  innerRadius={70} 
                  outerRadius={100} 
                  paddingAngle={8} 
                  dataKey="value"
                  onClick={(data) => handlePieClick(data)}
                  className="cursor-pointer"
                >
                  {stats.statusData.map((e, i) => <Cell key={i} fill={e.color} stroke="#fff" strokeWidth={4} className="hover:opacity-80 transition-opacity" />)}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
                <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{ fontSize: '9px', fontWeight: '900', textTransform: 'uppercase' }} />
              </PieChart>
            </ResponsiveContainer>
           </div>
        </div>

        {/* GRÁFICO DE CONFORMIDADE POR SETOR */}
        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-emerald-100 overflow-hidden hover:shadow-xl transition-shadow">
           <h3 className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest mb-6 text-center">Efetivo Capacitado por Setor</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart layout="vertical" data={stats.sectorData} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{ fontSize: 9, fontWeight: 900, fill: '#1e293b' }} width={80} />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(16, 185, 129, 0.05)' }} />
                <Legend verticalAlign="top" align="right" wrapperStyle={{ fontSize: '9px', fontWeight: '900', textTransform: 'uppercase', paddingBottom: '20px' }} />
                <Bar dataKey="Total" fill="#e2e8f0" radius={[0, 10, 10, 0]} barSize={12} name="Total Equipe" />
                <Bar dataKey="Capacitados" fill="#10b981" radius={[0, 10, 10, 0]} barSize={12} name="Com Curso Válido" />
              </BarChart>
            </ResponsiveContainer>
           </div>
        </div>
      </div>

      {/* RESUMO DE CARDS INFERIORES */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
        {[
          { label: 'Total Cursos Ativos', val: stats.s.trained, color: 'text-emerald-600', bg: 'bg-emerald-50', icon: '✅' },
          { label: 'Total Em Vencimento', val: stats.s.expiring, color: 'text-amber-500', bg: 'bg-amber-50', icon: '⏳' },
          { label: 'Total Cursos Expirados', val: stats.s.expired, color: 'text-red-600', bg: 'bg-red-50', icon: '🚨' },
          { label: 'Total Efetivo', val: stats.filteredCount, color: 'text-emerald-700', bg: 'bg-emerald-100/50', icon: '👷' },
        ].map((item, i) => (
          <div key={i} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-emerald-100 hover:shadow-xl hover:-translate-y-1 transition-all active:scale-95">
            <div className="flex justify-between items-center">
              <span className={`text-xl p-3 rounded-2xl ${item.bg} shadow-inner`}>{item.icon}</span>
              <span className={`text-3xl font-black tracking-tighter ${item.color}`}>{item.val}</span>
            </div>
            <p className="mt-4 text-[9px] font-black text-emerald-800/40 uppercase tracking-widest leading-none">{item.label}</p>
          </div>
        ))}
      </div>

      {/* MODAL DE DETALHES DE PENDÊNCIAS (BALÃO INFORMATIVO) */}
      {detailModal && (
        <div className="fixed inset-0 bg-emerald-950/80 backdrop-blur-xl z-[1200] flex items-center justify-center p-4 md:p-8 overflow-y-auto no-print">
          <div className="bg-white w-full max-w-5xl rounded-[3rem] shadow-2xl flex flex-col max-h-[90vh] animate-fadeIn border border-emerald-100">
            <header className="p-8 border-b border-emerald-50 flex justify-between items-center sticky top-0 bg-white/80 backdrop-blur-md z-10 rounded-t-[3rem]">
              <div className="flex items-center gap-4">
                <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl shadow-lg ${STATUS_CONFIG[detailModal.status]?.bg || 'bg-gray-100'}`}>
                   {detailModal.status === 'EXPIRED' ? '🚨' : detailModal.status === 'EXPIRING' ? '⏳' : '✅'}
                </div>
                <div>
                  <h3 className="text-xl md:text-2xl font-black text-emerald-900 italic tracking-tighter leading-none">
                    Relatório de <span className={STATUS_CONFIG[detailModal.status]?.text || ''}>{STATUS_CONFIG[detailModal.status]?.label || 'Lista'}</span>
                  </h3>
                  <p className="text-[9px] font-bold text-emerald-700/40 uppercase tracking-widest mt-2 flex items-center gap-2">
                    <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full"></span>
                    Auditando Pendências por Setor
                  </p>
                </div>
              </div>
              <div className="flex gap-4">
                <button 
                  onClick={() => window.print()}
                  className="bg-emerald-900 text-emerald-400 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] hover:bg-emerald-800 transition-all shadow-xl active:scale-95 flex items-center gap-2"
                >
                  <span>IMPRIMIR CONVOCAÇÃO</span>
                  <span>🖨️</span>
                </button>
                <button 
                  onClick={() => setDetailModal(null)}
                  className="w-12 h-12 flex items-center justify-center bg-red-50 text-red-500 rounded-full hover:bg-red-500 hover:text-white transition-all text-xl active:scale-90"
                >
                  ✕
                </button>
              </div>
            </header>

            <div className="flex-1 overflow-y-auto p-8 custom-scrollbar space-y-10">
              {detailModal.data.length > 0 ? (
                <div className="grid grid-cols-1 gap-10">
                  {detailModal.data.map((sec, idx) => (
                    <div key={idx} className="space-y-4">
                      <div className="flex items-center gap-4">
                         <h4 className="text-[12px] font-black text-emerald-800 uppercase tracking-[0.2em] italic border-l-4 border-emerald-500 pl-4">{sec.sector}</h4>
                         <span className="bg-emerald-50 text-emerald-700 px-3 py-1 rounded-full text-[9px] font-black shadow-sm">{sec.list.length} registros</span>
                      </div>
                      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
                        {sec.list.map((item: any, i: number) => (
                          <div key={i} className="bg-emerald-50/20 border border-emerald-100 p-6 rounded-[2rem] flex flex-col justify-between group hover:bg-white hover:shadow-xl hover:border-emerald-300 transition-all cursor-default">
                            <div className="mb-4">
                               <p className="text-sm font-black text-emerald-950 uppercase leading-tight mb-2">{item.name}</p>
                               <p className="text-[9px] font-bold text-emerald-700/40 uppercase tracking-widest">Matrícula: {item.reg}</p>
                            </div>
