            </button>
          )}
        </div>

        {/* Footer Sidebar */}
        <div className="p-6 border-t border-green-800/50 space-y-4 bg-green-950/20">
          <div className="bg-green-900/40 p-4 rounded-3xl border border-green-700/30 flex items-center gap-4">
            <div className="w-10 h-10 bg-emerald-500 rounded-xl flex items-center justify-center text-xl shadow-lg shadow-emerald-900/40">
              {isAdmin ? config.admin.icon : '👀'}
            </div>
            <div className="flex-1 overflow-hidden">
              <p className="text-[10px] font-black uppercase text-emerald-400 truncate tracking-widest">
                {isAdmin ? config.admin.username : 'Visitante'}
              </p>
              <p className="text-[8px] font-bold text-emerald-300/40 uppercase tracking-tighter truncate">
                {isAdmin ? 'Controle Total' : 'Modo Consulta'}
              </p>
            </div>
          </div>

          <button 
            onClick={onLogout} 
            className="w-full py-4 bg-red-500/10 hover:bg-red-500 text-red-500 hover:text-white rounded-2xl text-[10px] font-black uppercase tracking-[0.2em] transition-all border border-red-500/20 flex items-center justify-center gap-2 group active:scale-95"
          >
            <span>SAIR DO SISTEMA</span>
            <span className="group-hover:translate-x-1 transition-transform">🚪</span>
          </button>
        </div>
      </nav>

      <main className="flex-1 overflow-x-hidden h-screen flex flex-col relative z-0">
        <div className="flex-1 p-4 md:p-12 max-w-7xl mx-auto w-full">
          {children}
        </div>
      </main>
    </div>
  );
};

export default Layout;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import VisitorSearchView from './components/VisitorSearchView';
import Reports from './components/Reports';
import MatrixView from './components/MatrixView';
import ImportData from './components/ImportData';
import ConfigView from './components/ConfigView';
import AuthView from './components/AuthView';
import { Employee, UserRole } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [userRole, setUserRole] = useState<UserRole>(null); 

  const isAdmin = userRole === 'admin';

  // Define aba padrão ao logar
  useEffect(() => {
    if (userRole === 'visitor') {
      setActiveTab('visitor_search');
    } else if (userRole === 'admin') {
      setActiveTab('dashboard');
    }
  }, [userRole]);

  const loadData = async (forceSync = false) => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (userRole) {
      loadData();
    }
  }, [userRole]);

  const handleImport = async (data: Employee[]) => {
    if (!isAdmin) return;
    setIsLoading(true);
    try {
      await StorageService.saveEmployees(data);
      setEmployees(data);
      setActiveTab('dashboard');
    } catch (error) {
      console.warn("Erro ao salvar importação, mantendo em memória.");
      setEmployees(data);
      setActiveTab('dashboard');
    } finally {
      setIsLoading(false);
    }
  };

  if (!userRole) {
    return <AuthView onLogin={(role) => setUserRole(role)} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4">
          <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest italic">Sincronizando com Base de Dados...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} isAdmin={isAdmin} />;
      case 'employees': return isAdmin ? <EmployeeView employees={employees} onUpdate={loadData} isAdmin={isAdmin} /> : null;
      case 'visitor_search': return <VisitorSearchView employees={employees} />;
      case 'reports': return <Reports employees={employees} />;
      case 'matrix': return <MatrixView />;
      case 'import': return isAdmin ? <ImportData onImport={handleImport} /> : null;
      case 'config': return isAdmin ? <ConfigView onUpdate={loadData} /> : null;
      default: return <Dashboard employees={employees} isAdmin={isAdmin} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={userRole} 
      onLogout={() => setUserRole(null)}
      onRefreshData={() => loadData(true)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { getDaysRemaining } from '../utils/calculations';

interface VisitorSearchViewProps {
  employees: Employee[];
}

const VisitorSearchView: React.FC<VisitorSearchViewProps> = ({ employees }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedEmployee, setSelectedEmployee] = useState<Employee | null>(null);

  const normalize = (text: string) => 
    text.toLowerCase()
        .trim()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "");

  const searchResults = useMemo(() => {
    const term = normalize(searchTerm);
    if (term.length < 2) return [];

    return employees.filter(emp => {
      const name = normalize(emp.name || '');
      const reg = normalize(emp.registration || '');
      return name.includes(term) || reg.includes(term);
    }).slice(0, 5); // Limita resultados na busca rápida
  }, [employees, searchTerm]);

  const handleSelect = (emp: Employee) => {
    setSelectedEmployee(emp);
    setSearchTerm('');
  };

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      <div className="no-print">
        <h2 className="text-3xl font-black text-emerald-900 tracking-tighter italic">Consulta <span className="text-emerald-600">Colaborador</span></h2>
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1 italic">Verificação de Conformidade Normativa</p>
      </div>

      {/* Caixa de Pesquisa Central */}
      <div className="max-w-2xl mx-auto space-y-4 no-print">
        <div className="relative group">
          <input 
            type="text" 
            placeholder="Digite Nome ou RE do colaborador..." 
            className="w-full px-8 py-6 bg-white border-2 border-emerald-100 rounded-[2.5rem] text-sm font-bold shadow-xl outline-none focus:border-emerald-500 transition-all text-center"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <span className="absolute left-6 top-1/2 -translate-y-1/2 text-2xl">🔍</span>

          {/* Resultados Suspensos */}
          {searchResults.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-4 bg-white rounded-[2rem] shadow-2xl border border-emerald-50 overflow-hidden z-50">
              {searchResults.map(emp => (
                <button 
                  key={emp.id}
                  onClick={() => handleSelect(emp)}
                  className="w-full p-4 flex items-center gap-4 hover:bg-emerald-50 transition-colors border-b border-emerald-50 last:border-0"
                >
                  <div className="w-10 h-10 bg-emerald-100 rounded-full flex items-center justify-center font-black text-emerald-700">
                    {emp.name.charAt(0)}
                  </div>
                  <div className="text-left">
                    <p className="text-xs font-black text-emerald-950 uppercase">{emp.name}</p>
                    <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">RE: {emp.registration} • {emp.setor}</p>
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
        <p className="text-center text-[10px] font-black text-emerald-800/20 uppercase tracking-widest italic">Pesquise para visualizar a ficha completa</p>
      </div>

      {/* Ficha do Colaborador */}
      {selectedEmployee ? (
        <div className="animate-fadeIn space-y-6">
          <div className="bg-white rounded-[3rem] shadow-xl border border-emerald-100 overflow-hidden print:shadow-none print:border-none">
            {/* Header Ficha */}
            <div className="p-8 md:p-12 bg-emerald-50/50 flex flex-col md:flex-row items-center gap-8 border-b border-emerald-100">
              <div className="w-32 h-32 md:w-40 md:h-40 rounded-[2.5rem] bg-white border-4 border-white shadow-xl overflow-hidden flex-shrink-0">
                {selectedEmployee.photoUrl ? (
                  <img src={selectedEmployee.photoUrl} alt={selectedEmployee.name} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-4xl text-emerald-200 font-black">
                    {selectedEmployee.name.charAt(0)}
                  </div>
                )}
              </div>

              <div className="flex-1 text-center md:text-left">
                <div className="flex flex-col md:flex-row md:items-center gap-2 md:gap-4 mb-3">
                  <h3 className="text-2xl md:text-3xl font-black text-emerald-950 uppercase tracking-tighter">{selectedEmployee.name}</h3>
                  <span className="bg-emerald-900 text-emerald-400 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest w-fit mx-auto md:mx-0">RE: {selectedEmployee.registration}</span>
                </div>

