                  <div>
                    <p className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest">Empresa / Unidade</p>
                    <p className="text-sm font-black text-emerald-800 uppercase italic">{selectedEmployee.company}</p>
                  </div>
