  // Normalização para busca
  const normalize = (text: any) => 
    String(text || '')
      .toLowerCase()
      .trim()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

  const companies = useMemo(() => {
    const c = new Set(employees.map(e => (e.company || 'Empresa Padrão').trim()));
    return ['Todas', ...Array.from(c)].sort();
  }, [employees]);

  const setores = useMemo(() => {
    const pool = selectedCompany === 'Todas' 
      ? employees 
      : employees.filter(e => (e.company || 'Empresa Padrão').trim() === selectedCompany);

    const s = new Set(pool.map(e => (e.setor || 'Geral').trim()));
    return ['Todos', ...Array.from(s)].sort();
  }, [employees, selectedCompany]);

  const filtered = useMemo(() => {
    const term = normalize(searchTerm);
    return employees.filter(emp => {
      const empComp = (emp.company || 'Empresa Padrão').trim();
      const matchComp = selectedCompany === 'Todas' || empComp === selectedCompany;
      if (!matchComp) return false;

      const empSet = (emp.setor || 'Geral').trim();
      const matchSet = selectedSetor === 'Todos' || empSet === selectedSetor;
      if (!matchSet) return false;

      if (!term) return true;
      const name = normalize(emp.name);
      const reg = normalize(emp.registration);
      const role = normalize(emp.role);

      return name.includes(term) || reg.includes(term) || role.includes(term);
    });
  }, [employees, searchTerm, selectedSetor, selectedCompany]);

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      setViewingSheetEmp(null); // Fecha a ficha se estiver aberta
      onUpdate();
    } catch (err) {
      alert("Erro ao salvar prontuário.");
    }
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;
    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);
    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-6 pb-20 animate-fadeIn relative">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-3xl font-black text-emerald-900 italic tracking-tighter uppercase">Gestão <span className="text-emerald-600">Administrativa</span></h2>
          <div className="flex items-center gap-2 mt-1">
            <span className="text-[10px] font-bold text-emerald-700/60 uppercase tracking-[0.2em] italic">Pesquisa e Controle de Prontuários</span>
            <span className="w-1.5 h-1.5 bg-emerald-400 rounded-full"></span>
            <span className="text-[10px] font-black text-emerald-600 uppercase">{filtered.length} Colaboradores Encontrados</span>
          </div>
        </div>
        <button 
          onClick={() => setEditingEmp({ id: `emp-${Date.now()}`, name: '', registration: '', role: '', setor: '', company: '', trainings: {} })}
          className="bg-[#064E3B] text-emerald-400 px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-[1.03] active:scale-95 transition-all flex items-center justify-center gap-3 w-full md:w-auto"
        >
          <span>➕ Novo Cadastro</span>
        </button>
      </div>

      {/* Painel de Filtros */}
      <div className="bg-white p-6 md:p-8 rounded-[2.5rem] border border-emerald-100 shadow-sm flex flex-col md:flex-row gap-6">
        <div className="flex-1">
          <label className="text-[9px] font-black text-emerald-800/40 uppercase ml-1 mb-2 block tracking-widest italic">Empresa</label>
          <select value={selectedCompany} onChange={(e) => { setSelectedCompany(e.target.value); setSelectedSetor('Todos'); }} className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none focus:border-emerald-500 cursor-pointer">
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="flex-1">
          <label className="text-[9px] font-black text-emerald-800/40 uppercase ml-1 mb-2 block tracking-widest italic">Setor</label>
          <select value={selectedSetor} onChange={(e) => setSelectedSetor(e.target.value)} className="w-full bg-emerald-50/50 border-2 border-transparent px-4 py-3 rounded-2xl text-xs font-black text-emerald-700 outline-none focus:border-emerald-500 cursor-pointer">
            {setores.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div className="flex-[2]">
          <label className="text-[9px] font-black text-emerald-800/40 uppercase ml-1 mb-2 block tracking-widest italic">Busca por Nome ou RE</label>
          <div className="relative">
            <input type="text" placeholder="Pesquisar..." className="w-full px-5 py-3 pr-12 bg-emerald-50/50 border-2 border-transparent rounded-2xl text-xs font-bold shadow-inner outline-none focus:bg-white focus:border-emerald-500 transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-emerald-300 pointer-events-none text-xl">🔍</span>
          </div>
        </div>
      </div>

      {/* Listagem em Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filtered.map(emp => (
          <div key={emp.id} className="bg-white p-6 rounded-[2.5rem] border border-emerald-100 hover:border-emerald-300 transition-all shadow-sm flex flex-col justify-between">
            <div className="flex items-center gap-4 mb-6">
              <div className="w-16 h-16 bg-emerald-50 rounded-2xl overflow-hidden border border-emerald-100 flex-shrink-0">
                {emp.photoUrl ? <img src={emp.photoUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-emerald-200 font-black text-2xl">{emp.name.charAt(0)}</div>}
              </div>
              <div className="min-w-0">
                <h3 className="text-sm font-black text-emerald-950 uppercase truncate leading-tight">{emp.name}</h3>
                <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-1">RE: {emp.registration} • {emp.setor}</p>
                <div className="flex gap-1 mt-2">
                   {NR_COURSES.slice(0, 5).map(nr => (
                     <div key={nr.id} className={`w-4 h-4 rounded-full ${STATUS_CONFIG[emp.trainings[nr.id]?.status || 'NOT_TRAINED'].color} border border-white shadow-sm`} />
                   ))}
                </div>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <button 
                onClick={() => setViewingSheetEmp(emp)}
                className="py-3 bg-emerald-50 text-emerald-700 rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-emerald-100 transition-colors"
              >
                📜 Ficha
              </button>
              <button 
                onClick={() => setEditingEmp(emp)}
                className="py-3 bg-emerald-700 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-emerald-800 transition-colors"
              >
                ✏️ Editar
              </button>
            </div>
          </div>
        ))}
      </div>

      {/* MODAL: FICHA TÉCNICA (ADMIN) */}
      {viewingSheetEmp && (
        <div className="fixed inset-0 bg-emerald-950/80 backdrop-blur-md z-[1100] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-5xl rounded-[3rem] shadow-2xl flex flex-col max-h-[90vh] overflow-hidden animate-fadeIn">
            <header className="p-8 border-b flex justify-between items-center sticky top-0 bg-white z-10">
               <div>
                  <h3 className="text-xl font-black text-emerald-900 uppercase italic">Ficha de <span className="text-emerald-600">Treinamento</span></h3>
                  <p className="text-[9px] font-bold text-gray-400 uppercase tracking-[0.2em] mt-1">Visualização Administrativa ControlSST</p>
               </div>
               <div className="flex gap-3">
                  <button onClick={() => setEditingEmp(viewingSheetEmp)} className="px-6 py-3 bg-emerald-700 text-white rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-800">Editar Dados ✏️</button>
                  <button onClick={() => setViewingSheetEmp(null)} className="w-12 h-12 bg-red-50 text-red-500 rounded-full flex items-center justify-center text-xl hover:bg-red-500 hover:text-white transition-all">✕</button>
               </div>
            </header>

            <div className="flex-1 overflow-y-auto p-10 space-y-8">
              <div className="flex flex-col md:flex-row gap-8 items-center bg-emerald-50/50 p-8 rounded-[2rem] border border-emerald-100">
                <div className="w-32 h-32 bg-white rounded-3xl border-4 border-white shadow-xl overflow-hidden">
                  {viewingSheetEmp.photoUrl ? <img src={viewingSheetEmp.photoUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-4xl text-emerald-100 font-black">{viewingSheetEmp.name.charAt(0)}</div>}
                </div>
                <div className="text-center md:text-left space-y-2">
                  <h4 className="text-2xl font-black text-emerald-950 uppercase">{viewingSheetEmp.name}</h4>
                  <div className="flex flex-wrap gap-4 justify-center md:justify-start">
                    <span className="text-[10px] font-black bg-emerald-900 text-emerald-400 px-3 py-1 rounded-full uppercase">RE: {viewingSheetEmp.registration}</span>
                    <span className="text-[10px] font-black bg-white text-emerald-700 px-3 py-1 rounded-full border border-emerald-100 uppercase">{viewingSheetEmp.role}</span>
                    <span className="text-[10px] font-black bg-white text-emerald-700 px-3 py-1 rounded-full border border-emerald-100 uppercase">{viewingSheetEmp.setor}</span>
                  </div>
                </div>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="border-b-2 border-emerald-100 text-[10px] font-black uppercase text-emerald-800/40">
                      <th className="pb-4 pr-4">Treinamento</th>
                      <th className="pb-4 px-4 text-center">Conclusão</th>
                      <th className="pb-4 px-4 text-center">Validade</th>
                      <th className="pb-4 px-4 text-center">Dias Restantes</th>
                      <th className="pb-4 pl-4 text-right">Status</th>
                    </tr>
                  </thead>
                  <tbody>
                    {NR_COURSES.map(nr => {
                      const t = viewingSheetEmp.trainings[nr.id];
                      const days = getDaysRemaining(t?.expiryDate);
                      return (
                        <tr key={nr.id} className="border-b border-emerald-50/50 group hover:bg-emerald-50 transition-colors">
                          <td className="py-5 pr-4">
                            <p className="text-xs font-black text-emerald-950 uppercase">{nr.id}</p>
                            <p className="text-[9px] font-bold text-gray-400 uppercase mt-1">{nr.name}</p>
                          </td>
                          <td className="py-5 px-4 text-center text-[10px] font-black text-emerald-800">{t?.completionDate ? new Date(t.completionDate).toLocaleDateString('pt-BR') : '-'}</td>
                          <td className="py-5 px-4 text-center text-[10px] font-black text-emerald-800">{t?.expiryDate ? new Date(t.expiryDate).toLocaleDateString('pt-BR') : '-'}</td>
                          <td className="py-5 px-4 text-center">
                            {days !== null ? <span className={`text-[10px] font-black uppercase ${days < 0 ? 'text-red-500' : 'text-emerald-600'}`}>{days < 0 ? `Vencido (${Math.abs(days)}d)` : `${days} dias`}</span> : '-'}
                          </td>
                          <td className="py-5 pl-4 text-right">
                            <span className={`px-4 py-2 rounded-xl text-[8px] font-black uppercase tracking-widest ${STATUS_CONFIG[t?.status || 'NOT_TRAINED'].bg} ${STATUS_CONFIG[t?.status || 'NOT_TRAINED'].text}`}>
                              {STATUS_CONFIG[t?.status || 'NOT_TRAINED'].label}
                            </span>
                          </td>
                        </tr>
                      );
                    })}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL: EDIÇÃO DE DADOS (ADMIN) */}
      {editingEmp && (
        <div className="fixed inset-0 bg-emerald-950/90 backdrop-blur-xl z-[1200] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-4xl rounded-[3.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-fadeIn">
            <header className="p-10 border-b flex justify-between items-center bg-emerald-50/40">
              <div>
                <h3 className="text-2xl font-black text-emerald-900 leading-none uppercase tracking-tighter italic">Editar <span className="text-emerald-600">Prontuário</span></h3>
                <p className="text-[9px] font-bold text-emerald-700/60 uppercase tracking-widest mt-2">Controle Total de Informações</p>
              </div>
              <button onClick={() => setEditingEmp(null)} className="w-12 h-12 flex items-center justify-center bg-white rounded-full border border-emerald-100 shadow-sm text-lg hover:bg-red-500 hover:text-white transition-all">✕</button>
            </header>

            <form onSubmit={handleSaveEdit} className="p-10 overflow-y-auto space-y-10">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {[
                  { label: 'Nome Completo', key: 'name' },
                  { label: 'Matrícula / RE', key: 'registration' },
                  { label: 'Link da Foto', key: 'photoUrl' },
                  { label: 'Empresa / Unidade', key: 'company' },
                  { label: 'Setor', key: 'setor' },
                  { label: 'Função / Cargo', key: 'role' }
                ].map(field => (
                  <div key={field.key} className="space-y-2">
                    <label className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest ml-2">{field.label}</label>
                    <input 
                      required={field.key !== 'photoUrl'} 
                      type="text" 
                      className="w-full bg-emerald-50/50 border-2 border-emerald-100 rounded-2xl p-4 font-black text-sm outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner" 
                      value={(editingEmp as any)[field.key] || ''} 
                      onChange={e => setEditingEmp({...editingEmp, [field.key]: e.target.value})} 
                    />
                  </div>
                ))}
              </div>

              <div className="pt-10 border-t border-emerald-100">
                <h4 className="text-[10px] font-black text-emerald-900 uppercase tracking-[0.3em] mb-8 italic flex items-center gap-2">
                  <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
                  Datas de Treinamentos Normativos
                </h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {NR_COURSES.map(course => (
                    <div key={course.id} className="bg-emerald-50/40 p-5 rounded-3xl border border-emerald-100 hover:border-emerald-300 transition-colors shadow-inner">
                      <label className="block text-[8px] font-black text-emerald-700 uppercase mb-3 tracking-tighter">{course.name}</label>
                      <input 
                        type="date" 
                        className="w-full bg-white border border-emerald-200 rounded-xl p-3 text-xs font-black outline-none focus:border-emerald-500 transition-all shadow-sm" 
                        value={editingEmp.trainings[course.id]?.completionDate || ''} 
                        onChange={e => updateTrainingDate(course.id, e.target.value)} 
                      />
                    </div>
                  ))}
                </div>
              </div>

              <footer className="pt-10 border-t border-emerald-100 flex gap-4">
                <button type="button" onClick={() => setEditingEmp(null)} className="flex-1 py-5 text-emerald-800/40 font-black uppercase text-[10px] tracking-widest hover:text-red-500 transition-colors">CANCELAR</button>
                <button type="submit" className="flex-[2] py-5 bg-emerald-900 text-emerald-400 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">SALVAR ALTERAÇÕES 💾</button>
              </footer>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default EmployeeView;

import React, { useState, useMemo } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { calculateTrainingStatus, getExpiryDate, getDaysRemaining } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSetor, setSelectedSetor] = useState('TODOS');
  const [selectedCompany, setSelectedCompany] = useState('TODAS');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);
  const [viewingSheetEmp, setViewingSheetEmp] = useState<Employee | null>(null);

  // Função de normalização rigorosa para comparação infalível
  const simplify = (text: any) => 
    String(text || '')
      .toUpperCase()
      .trim()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

  // Extração de opções únicas para os filtros
  const companies = useMemo(() => {
    const set = new Set(employees.map(e => simplify(e.company || 'EMPRESA PADRÃO')));
    return ['TODAS', ...Array.from(set)].sort();
  }, [employees]);

  const setores = useMemo(() => {
    const pool = selectedCompany === 'TODAS' 
      ? employees 
      : employees.filter(e => simplify(e.company) === selectedCompany);

    const set = new Set(pool.map(e => simplify(e.setor || 'GERAL')));
    return ['TODOS', ...Array.from(set)].sort();
  }, [employees, selectedCompany]);

  // Lógica de Filtragem Corrigida
  const filteredEmployees = useMemo(() => {
    const term = simplify(searchTerm);

    return employees.filter(emp => {
      const empComp = simplify(emp.company || 'EMPRESA PADRÃO');
      const empSet = simplify(emp.setor || 'GERAL');
      const empName = simplify(emp.name);
      const empReg = simplify(emp.registration);
      const empRole = simplify(emp.role);

      const matchesCompany = selectedCompany === 'TODAS' || empComp === selectedCompany;
      const matchesSetor = selectedSetor === 'TODOS' || empSet === selectedSetor;
      const matchesSearch = !term || 
                           empName.includes(term) || 
                           empReg.includes(term) || 
                           empRole.includes(term);

      return matchesCompany && matchesSetor && matchesSearch;
    });
  }, [employees, searchTerm, selectedSetor, selectedCompany]);

  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      setViewingSheetEmp(null);
      onUpdate();
      alert("Cadastro atualizado com sucesso!");
    } catch (err) {
      alert("Erro ao salvar dados no servidor.");
    }
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;

    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);

    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: {
        courseId,
        completionDate: date || undefined,
        expiryDate: newExpiry,
        status: newStatus
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-8 pb-24 animate-fadeIn">
      {/* Cabeçalho de Ação */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-emerald-900 tracking-tighter uppercase italic">
            Cadastro de <span className="text-emerald-600">Funcionários</span>
          </h2>
          <p className="text-[10px] font-bold text-emerald-800/40 uppercase tracking-[0.2em] mt-1">Controle de Acesso e Prontuários Individuais</p>
        </div>
        <button 
          onClick={() => setEditingEmp({ id: `NEW-${Date.now()}`, name: '', registration: '', role: '', setor: '', company: '', trainings: {} })}
          className="bg-[#064E3B] text-emerald-400 px-10 py-5 rounded-2xl font-black text-xs uppercase tracking-widest shadow-2xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3 w-full md:w-auto"
        >
          <span>➕ NOVO COLABORADOR</span>
        </button>
      </div>

      {/* Barra de Filtros Inteligente */}
      <div className="bg-white p-8 rounded-[3rem] border border-emerald-100 shadow-sm grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="space-y-2">
          <label className="text-[9px] font-black text-emerald-800/30 uppercase tracking-widest ml-2">Unidade / Empresa</label>
          <select 
            value={selectedCompany} 
            onChange={(e) => { setSelectedCompany(e.target.value); setSelectedSetor('TODOS'); }}
            className="w-full bg-emerald-50/50 border-2 border-transparent px-5 py-4 rounded-2xl text-xs font-black text-emerald-700 focus:border-emerald-500 outline-none transition-all cursor-pointer"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[9px] font-black text-emerald-800/30 uppercase tracking-widest ml-2">Setor</label>
          <select 
            value={selectedSetor} 
            onChange={(e) => setSelectedSetor(e.target.value)}
            className="w-full bg-emerald-50/50 border-2 border-transparent px-5 py-4 rounded-2xl text-xs font-black text-emerald-700 focus:border-emerald-500 outline-none transition-all cursor-pointer"
          >
            {setores.map(s => <option key={s} value={s}>{s}</option>)}
          </select>
        </div>
        <div className="space-y-2">
          <label className="text-[9px] font-black text-emerald-800/30 uppercase tracking-widest ml-2">Busca Nome ou RE</label>
          <div className="relative">
            <input 
              type="text" 
              placeholder="Digite para filtrar..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full px-6 py-4 pr-12 bg-emerald-50/50 border-2 border-transparent rounded-2xl text-xs font-bold outline-none focus:bg-white focus:border-emerald-500 transition-all shadow-inner" 
            />
            <span className="absolute right-4 top-1/2 -translate-y-1/2 text-xl opacity-20">🔍</span>
          </div>
        </div>
      </div>

      {/* Grid de Resultados */}
      {filteredEmployees.length > 0 ? (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredEmployees.map(emp => (
            <div key={emp.id} className="bg-white p-6 rounded-[2.5rem] border border-emerald-100 hover:border-emerald-400 hover:shadow-xl transition-all group flex flex-col justify-between">
              <div className="flex items-center gap-5 mb-6">
                <div className="w-16 h-16 bg-emerald-50 rounded-2xl overflow-hidden border border-emerald-100 shadow-inner flex-shrink-0">
                  {emp.photoUrl ? (
                    <img src={emp.photoUrl} alt={emp.name} className="w-full h-full object-cover" />
                  ) : (
                    <div className="w-full h-full flex items-center justify-center text-emerald-200 font-black text-2xl bg-gradient-to-br from-emerald-50 to-white">{emp.name.charAt(0)}</div>
                  )}
