import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import Dashboard from './components/Dashboard';
import EmployeeView from './components/EmployeeView';
import VisitorSearchView from './components/VisitorSearchView';
import Reports from './components/Reports';
import MatrixView from './components/MatrixView';
import ConfigView from './components/ConfigView';
import AuthView from './components/AuthView';
import { Employee, UserRole } from './types';
import { StorageService } from './services/storage';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [employees, setEmployees] = useState<Employee[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [userRole, setUserRole] = useState<UserRole>(null); 

  const isAdmin = userRole === 'admin';

  useEffect(() => {
    if (userRole === 'visitor') {
      setActiveTab('visitor_search');
    } else if (userRole === 'admin') {
      setActiveTab('dashboard');
    }
  }, [userRole]);

  const loadData = async (forceSync = false) => {
    setIsLoading(true);
    try {
      const data = await StorageService.getEmployees();
      setEmployees(data);
    } catch (error) {
      console.error("Erro ao carregar dados:", error);
    } finally {
      setIsLoading(false);
    }
  };

  useEffect(() => {
    if (userRole) {
      loadData();
    }
  }, [userRole]);

  if (!userRole) {
    return <AuthView onLogin={(role) => setUserRole(role)} />;
  }

  const renderContent = () => {
    if (isLoading) {
      return (
        <div className="flex flex-col items-center justify-center h-[60vh] space-y-4">
          <div className="w-12 h-12 border-4 border-emerald-100 border-t-emerald-600 rounded-full animate-spin"></div>
          <p className="text-gray-400 font-black uppercase text-[10px] tracking-widest italic">Sincronizando com Base de Dados...</p>
        </div>
      );
    }

    switch (activeTab) {
      case 'dashboard': return <Dashboard employees={employees} isAdmin={isAdmin} />;
      case 'employees': return isAdmin ? <EmployeeView employees={employees} onUpdate={loadData} isAdmin={isAdmin} /> : null;
      case 'visitor_search': return <VisitorSearchView employees={employees} />;
      case 'reports': return <Reports employees={employees} />;
      case 'matrix': return <MatrixView />;
      case 'config': return isAdmin ? <ConfigView onUpdate={loadData} /> : null;
      default: return <Dashboard employees={employees} isAdmin={isAdmin} />;
    }
  };

  return (
    <Layout 
      activeTab={activeTab} 
      setActiveTab={setActiveTab} 
      userRole={userRole} 
      onLogout={() => setUserRole(null)}
      onRefreshData={() => loadData(true)}
    >
      {renderContent()}
    </Layout>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { calculateTrainingStatus, getExpiryDate, getDaysRemaining, formatEmployeeData } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSetor, setSelectedSetor] = useState('TODOS');
  const [selectedCompany, setSelectedCompany] = useState('TODAS');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);
  const [viewingSheetEmp, setViewingSheetEmp] = useState<Employee | null>(null);
  const [showBulkImport, setShowBulkImport] = useState(false);

  // Estados para Importação em Massa
  const [importText, setImportText] = useState('');
  const [importPreview, setImportPreview] = useState<Employee[]>([]);
  const [isImporting, setIsImporting] = useState(false);

  // Normalização para busca
  const simplify = (text: any) => 
    String(text || '')
      .toUpperCase()
      .trim()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

  // Opções de Filtros
  const companies = useMemo(() => {
    const set = new Set(employees.map(e => simplify(e.company || 'EMPRESA PADRÃO')));
    return ['TODAS', ...Array.from(set)].sort();
  }, [employees]);

  const setores = useMemo(() => {
    const pool = selectedCompany === 'TODAS' 
      ? employees 
      : employees.filter(e => simplify(e.company) === selectedCompany);

    const set = new Set(pool.map(e => simplify(e.setor || 'GERAL')));
    return ['TODOS', ...Array.from(set)].sort();
  }, [employees, selectedCompany]);

  // Lógica de Filtragem (Busca Premium)
  const filteredEmployees = useMemo(() => {
    const term = simplify(searchTerm);
    return employees.filter(emp => {
      const empComp = simplify(emp.company || 'EMPRESA PADRÃO');
      const empSet = simplify(emp.setor || 'GERAL');
      const empName = simplify(emp.name);
      const empReg = simplify(emp.registration);
      const empRole = simplify(emp.role);

      const matchesCompany = selectedCompany === 'TODAS' || empComp === selectedCompany;
      const matchesSetor = selectedSetor === 'TODOS' || empSet === selectedSetor;
      const matchesSearch = !term || empName.includes(term) || empReg.includes(term) || empRole.includes(term);

      return matchesCompany && matchesSetor && matchesSearch;
    });
  }, [employees, searchTerm, selectedSetor, selectedCompany]);

  // Salvar Edição Individual
  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      setViewingSheetEmp(null);
      onUpdate();
      alert("Prontuário salvo com sucesso!");
    } catch (err) {
      alert("Erro ao salvar dados.");
    }
  };

  // Processar Importação em Massa
  const handleProcessBulk = () => {
    try {
      const trimmed = importText.trim();
      if (!trimmed) return alert("Cole os dados da planilha primeiro.");
      const lines = trimmed.split(/\r?\n/);
      const separator = lines[0].includes('\t') ? '\t' : (lines[0].includes(';') ? ';' : ',');
      const headers = lines[0].split(separator).map(h => h.trim());
      const rawData = lines.slice(1).map(line => {
        const values = line.split(separator).map(v => v.trim());
        const obj: any = {};
        headers.forEach((h, i) => { obj[h] = values[i] || undefined; });
        return obj;
      });
      const formatted = formatEmployeeData(rawData);
      setImportPreview(formatted);
    } catch (err) {
      alert("Erro ao processar texto da planilha.");
    }
  };

  // Salvar Importação em Massa
  const handleSaveBulk = async () => {
    if (!importPreview.length) return;
    setIsImporting(true);
    try {
      await StorageService.saveEmployees(importPreview);
      setImportPreview([]);
      setImportText('');
      setShowBulkImport(false);
      onUpdate();
      alert(`Sucesso! ${importPreview.length} registros sincronizados.`);
    } catch (err) {
      alert("Erro na sincronização cloud.");
    } finally {
      setIsImporting(false);
    }
  };

  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;
    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);
    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: { courseId, completionDate: date || undefined, expiryDate: newExpiry, status: newStatus }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  return (
    <div className="space-y-10 pb-24 animate-fadeIn">
      {/* Cabeçalho de Comando */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-3xl font-black text-emerald-900 tracking-tighter uppercase italic">
            Cadastro de <span className="text-emerald-600">Funcionários</span>
          </h2>
          <p className="text-[10px] font-bold text-emerald-800/40 uppercase tracking-[0.2em] mt-1">Central de Prontuários e Controle Normativo</p>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <button 
            onClick={() => setShowBulkImport(true)}
            className="flex-1 md:flex-none bg-white text-emerald-700 border-2 border-emerald-100 px-6 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest hover:bg-emerald-50 transition-all shadow-sm"
          >
            📥 Importar Planilha
          </button>
          <button 
            onClick={() => setEditingEmp({ id: `NEW-${Date.now()}`, name: '', registration: '', role: '', setor: '', company: '', trainings: {} })}
            className="flex-[2] md:flex-none bg-emerald-900 text-emerald-400 px-8 py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center justify-center gap-2"
          >
            <span>➕ Novo Cadastro</span>
          </button>
        </div>
      </div>

      {/* Painel de Busca e Filtros (Igual ao de consulta, mas administrativo) */}
      <div className="bg-white p-8 rounded-[3.5rem] border border-emerald-100 shadow-sm space-y-8">
        <div className="max-w-3xl mx-auto">
          <label className="text-[10px] font-black text-emerald-800/30 uppercase tracking-[0.3em] mb-4 block text-center italic">Pesquisa Rápida por Nome ou RE</label>
          <div className="relative">
            <input 
              type="text" 
              placeholder="Digite para localizar colaborador..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full px-8 py-6 bg-emerald-50/50 border-2 border-transparent rounded-[2.5rem] text-sm font-black text-emerald-900 shadow-inner outline-none focus:bg-white focus:border-emerald-500 transition-all text-center" 
            />
            <span className="absolute left-8 top-1/2 -translate-y-1/2 text-2xl opacity-20">🔍</span>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest ml-4">Filtrar por Unidade</label>
            <select value={selectedCompany} onChange={(e) => { setSelectedCompany(e.target.value); setSelectedSetor('TODOS'); }} className="w-full bg-emerald-50/30 border-2 border-emerald-100 px-6 py-4 rounded-2xl text-xs font-black text-emerald-700 focus:border-emerald-500 outline-none transition-all">
              {companies.map(c => <option key={c} value={c}>{c}</option>)}
            </select>
          </div>
          <div className="space-y-2">
            <label className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest ml-4">Filtrar por Setor</label>
            <select value={selectedSetor} onChange={(e) => setSelectedSetor(e.target.value)} className="w-full bg-emerald-50/30 border-2 border-emerald-100 px-6 py-4 rounded-2xl text-xs font-black text-emerald-700 focus:border-emerald-500 outline-none transition-all">
              {setores.map(s => <option key={s} value={s}>{s}</option>)}
            </select>
          </div>
        </div>
      </div>

      {/* Grid de Funcionários */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredEmployees.map(emp => (
          <div key={emp.id} className="bg-white p-6 rounded-[2.5rem] border border-emerald-100 hover:border-emerald-400 hover:shadow-xl transition-all group flex flex-col justify-between">
            <div className="flex items-center gap-5 mb-6">
              <div className="w-16 h-16 bg-emerald-50 rounded-2xl overflow-hidden border border-emerald-100 shadow-inner flex-shrink-0">
                {emp.photoUrl ? <img src={emp.photoUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-emerald-200 font-black text-2xl bg-gradient-to-br from-emerald-50 to-white">{emp.name.charAt(0)}</div>}
