              <div className="min-w-0">
                <h3 className="text-sm font-black text-emerald-950 uppercase truncate leading-none mb-1">{emp.name}</h3>
                <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest truncate">RE: {emp.registration} • {emp.role}</p>
                <div className="flex gap-1 mt-2">
                  {NR_COURSES.slice(0, 8).map(nr => (
                    <div key={nr.id} title={nr.id} className={`w-3.5 h-3.5 rounded-full border border-white shadow-sm ${STATUS_CONFIG[emp.trainings[nr.id]?.status || 'NOT_TRAINED'].color}`} />
