      </div>

      {/* MODAL: IMPORTAÇÃO EM MASSA */}
      {showBulkImport && (
        <div className="fixed inset-0 bg-emerald-950/90 backdrop-blur-xl z-[1300] flex items-center justify-center p-4">
          <div className="bg-white w-full max-w-5xl rounded-[3.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] animate-fadeIn">
