                placeholder="Cole aqui os dados da sua planilha Excel..."
                value={importText}
                onChange={(e) => setImportText(e.target.value)}
              />
              <div className="flex justify-between items-center">
                <p className="text-[10px] font-black text-emerald-800/40 uppercase italic">{importPreview.length} Colaboradores Detectados</p>
                <div className="flex gap-4">
                  <button onClick={() => setImportText('')} className="px-6 py-4 text-red-500 font-black text-[10px] uppercase">Limpar</button>
                  <button onClick={handleProcessBulk} className="px-8 py-4 bg-emerald-100 text-emerald-700 rounded-2xl font-black text-[10px] uppercase tracking-widest">Processar Dados</button>
