                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* MODAL: EDIÇÃO INDIVIDUAL (100% PODER) */}
      {editingEmp && (
        <div className="fixed inset-0 bg-emerald-950/95 backdrop-blur-xl z-[1200] flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-4xl rounded-[3.5rem] shadow-2xl overflow-hidden my-auto animate-fadeIn">
            <header className="p-10 border-b flex justify-between items-center bg-emerald-50/40">
              <div>
