                <p className="text-[9px] font-bold text-emerald-700/60 uppercase tracking-widest mt-2">Controle Total de Informações Administrativas</p>
              </div>
              <button onClick={() => setEditingEmp(null)} className="w-12 h-12 flex items-center justify-center bg-white rounded-full text-lg hover:bg-red-500 hover:text-white transition-all">✕</button>
