              </div>
              <div className="pt-10 border-t border-emerald-100">
                <h4 className="text-[10px] font-black text-emerald-900 uppercase tracking-[0.3em] mb-8 italic flex items-center gap-2">Treinamentos e NRs</h4>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                  {NR_COURSES.map(course => (
                    <div key={course.id} className="bg-emerald-50/20 p-5 rounded-3xl border border-emerald-100 shadow-inner group hover:bg-white hover:border-emerald-400 transition-all">
                      <label className="block text-[8px] font-black text-emerald-700 uppercase mb-3">{course.name}</label>
                      <input type="date" className="w-full bg-white border border-emerald-100 rounded-xl p-3 text-xs font-black outline-none focus:border-emerald-500 transition-all" value={editingEmp.trainings[course.id]?.completionDate || ''} onChange={e => updateTrainingDate(course.id, e.target.value)} />
                    </div>
                  ))}
                </div>
              </div>
              <footer className="pt-10 border-t border-emerald-100 flex gap-4">
                <button type="button" onClick={() => setEditingEmp(null)} className="flex-1 py-5 text-emerald-800/40 font-black uppercase text-[10px] tracking-widest hover:text-red-500 transition-colors">DESCARTAR</button>
                <button type="submit" className="flex-[2] py-5 bg-emerald-900 text-emerald-400 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-2xl hover:scale-[1.02] active:scale-95 transition-all">SALVAR ALTERAÇÕES 💾</button>
              </footer>
            </form>
          </div>
        </div>
      )}

      {/* MODAL: FICHA TÉCNICA (ADMIN) */}
      {viewingSheetEmp && (
        <div className="fixed inset-0 bg-emerald-950/80 backdrop-blur-md z-[1100] flex items-center justify-center p-4 overflow-y-auto">
          <div className="bg-white w-full max-w-4xl rounded-[3.5rem] shadow-2xl overflow-hidden my-auto animate-fadeIn">
            <header className="p-8 border-b flex justify-between items-center bg-emerald-50/50">
              <div>
                <h3 className="text-xl font-black text-emerald-900 uppercase italic">Prontuário de <span className="text-emerald-600">Treinamento</span></h3>
                <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-1">Visão do Administrador</p>
              </div>
              <div className="flex gap-3">
                <button onClick={() => setEditingEmp(viewingSheetEmp)} className="px-6 py-3 bg-emerald-700 text-white rounded-xl font-black text-[10px] uppercase hover:bg-emerald-800 transition-all">Editar ✏️</button>
                <button onClick={() => setViewingSheetEmp(null)} className="w-12 h-12 bg-white rounded-full flex items-center justify-center text-xl shadow-sm hover:bg-red-500 hover:text-white transition-all">✕</button>
