                   {viewingSheetEmp.photoUrl ? <img src={viewingSheetEmp.photoUrl} className="w-full h-full object-cover" /> : <div className="w-full h-full flex items-center justify-center text-4xl text-emerald-100 font-black bg-emerald-50">{viewingSheetEmp.name.charAt(0)}</div>}
