                    <span className="bg-emerald-50 text-emerald-700 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest">{viewingSheetEmp.company}</span>
                    <span className="bg-emerald-50 text-emerald-700 px-3 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest">{viewingSheetEmp.setor}</span>
