import React, { useState, useMemo, useEffect } from 'react';
import { Employee } from '../types';
import { STATUS_CONFIG, NR_COURSES } from '../constants';
import { getDaysRemaining } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface VisitorSearchViewProps {
  employees: Employee[];
}

const VisitorSearchView: React.FC<VisitorSearchViewProps> = ({ employees }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedId, setSelectedId] = useState<string | null>(null);
  const [lastSync, setLastSync] = useState<string | null>(StorageService.getLastSyncTime());

  useEffect(() => {
    setLastSync(StorageService.getLastSyncTime());
  }, [employees]);

  const selectedEmployee = useMemo(() => {
    if (!selectedId) return null;
    return employees.find(e => e.id === selectedId) || null;
  }, [employees, selectedId]);

  const normalize = (text: string) => 
    text.toLowerCase()
        .trim()
        .normalize("NFD")
        .replace(/[\u0300-\u036f]/g, "");

  const searchResults = useMemo(() => {
    const term = normalize(searchTerm);
    if (term.length < 2) return [];

    return employees.filter(emp => {
      const name = normalize(emp.name || '');
      const reg = normalize(emp.registration || '');
      return name.includes(term) || reg.includes(term);
    }).slice(0, 5);
  }, [employees, searchTerm]);

  const handleSelect = (emp: Employee) => {
    setSelectedId(emp.id);
    setSearchTerm('');
  };

  const isCipero = (emp: Employee) => ['VALID', 'EXPIRING'].includes(emp.trainings['NR05']?.status);
  const isBrigadista = (emp: Employee) => ['VALID', 'EXPIRING'].includes(emp.trainings['NR23']?.status);

  return (
    <div className="space-y-8 animate-fadeIn pb-20">
      <div className="no-print">
        <h2 className="text-3xl font-black text-emerald-900 tracking-tighter italic">Consulta <span className="text-emerald-600">Colaborador</span></h2>
        <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-1 italic">Verificação de Conformidade Normativa em Tempo Real</p>
      </div>

      <div className="max-w-2xl mx-auto space-y-4 no-print">
        <div className="relative group">
          <input 
            type="text" 
            placeholder="Digite Nome ou RE do colaborador..." 
            className="w-full px-8 py-6 bg-white border-2 border-emerald-100 rounded-[2.5rem] text-sm font-bold shadow-xl outline-none focus:border-emerald-500 transition-all text-center"
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
          <span className="absolute left-6 top-1/2 -translate-y-1/2 text-2xl">🔍</span>

          {searchResults.length > 0 && (
            <div className="absolute top-full left-0 right-0 mt-4 bg-white rounded-[2rem] shadow-2xl border border-emerald-50 overflow-hidden z-50">
              {searchResults.map(emp => (
                <button 
                  key={emp.id}
                  onClick={() => handleSelect(emp)}
                  className="w-full p-6 flex items-center justify-between hover:bg-emerald-50 transition-colors border-b border-emerald-50 last:border-0"
                >
                  <div className="flex items-center gap-4">
                    <div className="w-10 h-10 bg-emerald-100 rounded-full flex items-center justify-center font-black text-emerald-700">
                      {emp.name.charAt(0)}
                    </div>
                    <div className="text-left">
                      <p className="text-xs font-black text-emerald-950 uppercase">{emp.name}</p>
                      <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">RE: {emp.registration} • {emp.setor}</p>
                    </div>
                  </div>
                  <div className="flex gap-2">
                    {isCipero(emp) && <span className="w-6 h-6 bg-emerald-500 text-white rounded flex items-center justify-center text-[10px] font-black shadow-sm">C</span>}
                    {isBrigadista(emp) && <span className="w-6 h-6 bg-red-500 text-white rounded flex items-center justify-center text-[10px] font-black shadow-sm">B</span>}
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>
      </div>

      {selectedEmployee ? (
        <div className="animate-fadeIn space-y-6">
          <div className="bg-white rounded-[3rem] shadow-xl border border-emerald-100 overflow-hidden print:shadow-none print:border-none print:m-0 print:p-0">

            <div className="p-8 md:p-12 bg-emerald-50/50 flex flex-col md:flex-row items-center gap-8 border-b border-emerald-100 print:bg-white print:border-emerald-900 print:border-b-4 relative">

              <div className="absolute top-4 right-8 text-right no-print flex items-center gap-4">
                 <div className="flex gap-2">
                    {isCipero(selectedEmployee) && (
                      <div className="flex items-center gap-2 bg-emerald-100 px-3 py-1.5 rounded-xl border border-emerald-200">
                         <span className="w-5 h-5 bg-emerald-500 text-white rounded-md flex items-center justify-center text-[10px] font-black">C</span>
                         <span className="text-[8px] font-black text-emerald-700 uppercase tracking-widest">CIPEIRO</span>
                      </div>
                    )}
                    {isBrigadista(selectedEmployee) && (
                      <div className="flex items-center gap-2 bg-red-100 px-3 py-1.5 rounded-xl border border-red-200">
                         <span className="w-5 h-5 bg-red-500 text-white rounded-md flex items-center justify-center text-[10px] font-black">B</span>
                         <span className="text-[8px] font-black text-red-700 uppercase tracking-widest">BRIGADISTA</span>
                      </div>
                    )}
                 </div>
                 <div className="h-8 w-px bg-emerald-200"></div>
                 <div>
                    <p className="text-[7px] font-black text-emerald-800/20 uppercase tracking-[0.2em] leading-none">Dados Sincronizados em:</p>
                    <p className="text-[9px] font-black text-emerald-600/40 italic">{lastSync || 'Data não disponível'}</p>
                 </div>
              </div>

              <div className="w-32 h-32 md:w-40 md:h-40 rounded-[2.5rem] bg-white border-4 border-white shadow-xl overflow-hidden flex-shrink-0 print:shadow-none">
                {selectedEmployee.photoUrl ? (
                  <img src={selectedEmployee.photoUrl} alt={selectedEmployee.name} className="w-full h-full object-cover" />
                ) : (
                  <div className="w-full h-full flex items-center justify-center text-4xl text-emerald-200 font-black">
                    {selectedEmployee.name?.charAt(0) || '?'}
                  </div>
                )}
              </div>

              <div className="flex-1 text-center md:text-left">
                <div className="flex flex-col md:flex-row md:items-center gap-2 md:gap-4 mb-3">
                  <h3 className="text-2xl md:text-3xl font-black text-emerald-950 uppercase tracking-tighter flex items-center justify-center md:justify-start gap-3">
                    {selectedEmployee.name}
                    <div className="flex gap-1 print:hidden">
                       {isCipero(selectedEmployee) && <span className="w-8 h-8 bg-emerald-500 text-white rounded-xl flex items-center justify-center text-sm font-black shadow-lg">C</span>}
                       {isBrigadista(selectedEmployee) && <span className="w-8 h-8 bg-red-500 text-white rounded-xl flex items-center justify-center text-sm font-black shadow-lg">B</span>}
                    </div>
                  </h3>
                  <span className="bg-emerald-900 text-emerald-400 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest w-fit mx-auto md:mx-0 print:bg-black print:text-white">
                    RE: {selectedEmployee.registration}
                  </span>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div>
                    <p className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest">Empresa / Unidade</p>
                    <p className="text-sm font-black text-emerald-800 uppercase italic">{selectedEmployee.company || 'N/A'}</p>
                  </div>
                  <div>
                    <p className="text-[9px] font-black text-emerald-800/40 uppercase tracking-widest">Setor / Função</p>
                    <p className="text-sm font-black text-emerald-800 uppercase italic">{selectedEmployee.setor} • {selectedEmployee.role}</p>
                  </div>
                </div>
              </div>

              <div className="no-print">
                 <button 
                  onClick={() => window.print()}
                  className="bg-emerald-900 text-emerald-400 px-8 py-5 rounded-2xl font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:scale-105 active:scale-95 transition-all flex items-center gap-3"
                 >
                   IMPRIMIR FICHA 🖨️
                 </button>
              </div>
            </div>

            <div className="p-8 md:p-12 overflow-x-auto">
              <h4 className="text-[10px] font-black text-emerald-900 uppercase tracking-[0.3em] mb-8 italic flex items-center gap-2 print:text-sm">
                <span className="w-2 h-2 bg-emerald-500 rounded-full print:hidden"></span>
                Grade de Treinamentos Normativos (NRs)
              </h4>

              <table className="w-full text-left border-collapse">
                <thead>
                  <tr className="border-b-2 border-emerald-100 text-[10px] font-black uppercase text-emerald-800/40 print:border-emerald-900 print:text-black">
                    <th className="pb-4 pr-4">Treinamento</th>
                    <th className="pb-4 px-4">Conclusão</th>
                    <th className="pb-4 px-4">Validade</th>
                    <th className="pb-4 px-4 text-center">Dias Restantes</th>
                    <th className="pb-4 pl-4 text-right">Status</th>
                  </tr>
                </thead>
                <tbody>
                  {NR_COURSES.map(course => {
                    const training = selectedEmployee.trainings[course.id];
                    const status = training?.status || 'NOT_TRAINED';
                    const days = getDaysRemaining(training?.expiryDate);

                    return (
                      <tr key={course.id} className="border-b border-emerald-50/50 hover:bg-emerald-50/30 transition-colors group print:border-gray-200">
                        <td className="py-6 pr-4">
                          <p className="text-xs font-black text-emerald-950 uppercase">{course.id}</p>
                          <p className="text-[9px] font-bold text-gray-400 uppercase leading-none mt-1 print:text-[8px]">{course.name}</p>
                        </td>
                        <td className="py-6 px-4 text-xs font-black text-emerald-800">
                          {training?.completionDate ? new Date(training.completionDate).toLocaleDateString('pt-BR') : '-'}
                        </td>
                        <td className="py-6 px-4 text-xs font-black text-emerald-800">
                          {training?.expiryDate ? new Date(training.expiryDate).toLocaleDateString('pt-BR') : '-'}
                        </td>
                        <td className="py-6 px-4 text-center">
                          <span className={`text-[10px] font-black uppercase ${days !== null && days < 0 ? 'text-red-500' : 'text-emerald-600'} print:text-[8px]`}>
                            {days !== null ? (days < 0 ? `Vencido (${Math.abs(days)}d)` : `${days} dias`) : '-'}
                          </span>
                        </td>
                        <td className="py-6 pl-4 text-right">
                          <span className={`px-4 py-2 rounded-xl text-[8px] font-black uppercase tracking-widest ${STATUS_CONFIG[status].bg} ${STATUS_CONFIG[status].text} shadow-sm border border-current opacity-70 group-hover:opacity-100 transition-opacity print:opacity-100 print:border-gray-300`}>
                            {STATUS_CONFIG[status].label}
                          </span>
                        </td>
                      </tr>
                    );
                  })}
                </tbody>
              </table>

              <div className="mt-12 pt-8 border-t border-emerald-50 text-center opacity-0 print:opacity-100">
                 <p className="text-[9px] font-black text-gray-400 uppercase tracking-[0.5em]">Documento Gerado Via ControlSST Cloud • Autenticidade Garantida em {lastSync}</p>
              </div>
            </div>
          </div>
        </div>
      ) : (
        <div className="flex flex-col items-center justify-center py-24 text-center opacity-20 no-print">
           <div className="w-32 h-32 bg-emerald-100 rounded-full flex items-center justify-center text-6xl mb-6">👷‍♂️</div>
           <p className="text-emerald-900 font-black uppercase text-xs tracking-[0.3em]">Digite um termo para visualizar a ficha do trabalhador</p>
        </div>
      )}
    </div>
  );
};

export default VisitorSearchView;

import React, { useMemo, useState } from 'react';
import { PieChart, Pie, Cell, Tooltip, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, CartesianGrid, Legend } from 'recharts';
import { Employee, TrainingRecord, TrainingStatus } from '../types';
import { getDaysRemaining } from '../utils/calculations';
import { STATUS_CONFIG, NR_COURSES } from '../constants';

interface DashboardProps {
  employees: Employee[];
  isAdmin: boolean;
}

const CustomTooltip = ({ active, payload, label }: any) => {
  if (active && payload && payload.length) {
    return (
      <div className="bg-white/95 backdrop-blur-md p-4 rounded-2xl shadow-2xl border border-emerald-100 min-w-[180px] animate-fadeIn">
        <p className="font-black text-emerald-900 mb-2 text-[10px] uppercase tracking-wider">{label || payload[0].name}</p>
        <div className="space-y-1">
          {payload.map((p: any, i: number) => (
            <div key={i} className="flex justify-between items-center gap-4">
              <span className="font-bold text-emerald-800/40 text-[9px] uppercase">{p.name}</span>
              <span className="font-black text-emerald-600 text-sm" style={{ color: p.color || p.fill }}>{p.value}</span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  return null;
};

const Dashboard: React.FC<DashboardProps> = ({ employees, isAdmin }) => {
  const [selectedCompany, setSelectedCompany] = useState<string>('Todas');
  const [detailModal, setDetailModal] = useState<{ label: string, status?: TrainingStatus | 'PENDING' | 'RECENT', data: any[] } | null>(null);

  const stats = useMemo(() => {
    const s = { 
      trained: 0, 
      expiring: 0, 
      expired: 0,
      expiring15: 0,
      expiring60: 0,
      recentTrainings: 0
    };

    const sectorMap: Record<string, { total: number, compliant: number }> = {};
    const filtered = selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);

    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    filtered.forEach(emp => {
      const sectorName = (emp.setor || 'Geral').trim();
      if (!sectorMap[sectorName]) sectorMap[sectorName] = { total: 0, compliant: 0 };
      sectorMap[sectorName].total++;

      let hasValidTraining = false;

      Object.entries(emp.trainings || {}).forEach(([_, t]) => {
        const record = t as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);

        if (record.status === 'VALID') {
          s.trained++;
          hasValidTraining = true;
        } else if (record.status === 'EXPIRING') {
          s.expiring++;
          hasValidTraining = true;
          if (days !== null && days <= 15) s.expiring15++;
          if (days !== null && days <= 60) s.expiring60++;
        } else if (record.status === 'EXPIRED') {
          s.expired++;
        }

        if (record.completionDate) {
          const compDate = new Date(record.completionDate);
          if (compDate >= thirtyDaysAgo) s.recentTrainings++;
        }
      });

      if (hasValidTraining) {
        sectorMap[sectorName].compliant++;
      }
    });

    return { 
      s, 
      sectorData: Object.entries(sectorMap).map(([name, data]) => ({ 
        name, 
        Total: data.total, 
        Capacitados: data.compliant 
      })).sort((a, b) => b.Total - a.Total),
      statusData: [
        { name: 'Válidos', value: s.trained, color: '#10B981', status: 'VALID' },
        { name: 'Vencendo', value: s.expiring, color: '#F59E0B', status: 'EXPIRING' },
        { name: 'Vencidos', value: s.expired, color: '#EF4444', status: 'EXPIRED' }
      ],
      filteredCount: filtered.length
    };
  }, [employees, selectedCompany]);

  const companies = useMemo(() => ['Todas', ...Array.from(new Set(employees.map(e => e.company)))], [employees]);

  // Handler unificado para abrir o balão de detalhes
  const handleDetailView = (type: 'EXPIRED' | 'EXPIRING' | 'VALID' | 'CRITICAL_15' | 'ALERT_60' | 'RECENT_30') => {
    const issuesBySector: Record<string, any[]> = {};
    const filtered = selectedCompany === 'Todas' ? employees : employees.filter(e => e.company === selectedCompany);

    let modalLabel = '';
    const thirtyDaysAgo = new Date();
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30);

    filtered.forEach(emp => {
      Object.entries(emp.trainings).forEach(([cid, r]) => {
        const record = r as TrainingRecord;
        const days = getDaysRemaining(record.expiryDate);
        let match = false;

        switch(type) {
          case 'EXPIRED': if (record.status === 'EXPIRED') { match = true; modalLabel = 'Cursos Vencidos'; } break;
          case 'EXPIRING': if (record.status === 'EXPIRING') { match = true; modalLabel = 'Cursos em Vencimento'; } break;
          case 'VALID': if (record.status === 'VALID') { match = true; modalLabel = 'Cursos Válidos'; } break;
          case 'CRITICAL_15': if (record.status === 'EXPIRING' && days !== null && days <= 15) { match = true; modalLabel = 'Crítico (Até 15 dias)'; } break;
          case 'ALERT_60': if (record.status === 'EXPIRING' && days !== null && days <= 60) { match = true; modalLabel = 'Alerta (Até 60 dias)'; } break;
          case 'RECENT_30': 
            if (record.completionDate) {
              const compDate = new Date(record.completionDate);
              if (compDate >= thirtyDaysAgo) { match = true; modalLabel = 'Realizados (Últimos 30 dias)'; }
            }
            break;
        }

        if (match) {
          const sec = (emp.setor || 'Geral').trim();
          if (!issuesBySector[sec]) issuesBySector[sec] = [];

          const courseInfo = NR_COURSES.find(c => c.id === cid);
          issuesBySector[sec].push({
            name: emp.name,
            reg: emp.registration,
            role: emp.role || '-',
            courseId: cid,
            courseName: courseInfo?.name || cid,
            completion: record.completionDate,
            expiry: record.expiryDate,
            days: days,
            isCipero: ['VALID', 'EXPIRING'].includes(emp.trainings['NR05']?.status),
            isBrigadista: ['VALID', 'EXPIRING'].includes(emp.trainings['NR23']?.status)
          });
        }
      });
    });

    setDetailModal({ 
      label: modalLabel,
      status: type.includes('CRITICAL') || type.includes('ALERT') ? 'EXPIRING' : (type.includes('RECENT') ? 'VALID' : type as any),
      data: Object.entries(issuesBySector).map(([sector, list]) => ({ sector, list })) 
    });
  };

  const handlePieClick = (data: any) => {
    const status = data.status || data.payload?.status;
    if (status) handleDetailView(status);
  };

  return (
    <div className="space-y-8 pb-20 animate-fadeIn overflow-hidden">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
        <div>
          <h2 className="text-2xl md:text-4xl font-black text-emerald-900 tracking-tighter italic">
            Dashboard <span className="text-emerald-600">Analytics</span>
          </h2>
          <p className="text-emerald-800/40 font-bold uppercase text-[8px] md:text-[10px] tracking-[0.2em] mt-1 italic">Gestão Inteligente de SST</p>
        </div>
        <div className="bg-white p-2 rounded-2xl border border-emerald-100 shadow-sm w-full md:w-auto">
          <select 
            value={selectedCompany} 
            onChange={(e) => setSelectedCompany(e.target.value)} 
            className="w-full bg-emerald-50 text-emerald-700 px-4 py-2 rounded-xl text-xs font-black outline-none border-none cursor-pointer hover:bg-emerald-100 transition-colors"
          >
            {companies.map(c => <option key={c} value={c}>{c}</option>)}
          </select>
        </div>
      </header>

      {/* CARDS INDICADORES */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <button onClick={() => handleDetailView('CRITICAL_15')} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-red-100 flex items-center gap-6 group hover:shadow-xl hover:-translate-y-1 transition-all active:scale-95 text-left w-full">
          <div className="w-14 h-14 bg-red-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-red-500 group-hover:text-white transition-colors flex-shrink-0 shadow-inner">🚨</div>
          <div className="overflow-hidden"><p className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest truncate">Crítico (15 dias)</p><h4 className="text-3xl font-black text-red-600 tracking-tighter leading-none mt-1">{stats.s.expiring15}</h4></div>
        </button>
        <button onClick={() => handleDetailView('ALERT_60')} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-amber-100 flex items-center gap-6 group hover:shadow-xl hover:-translate-y-1 transition-all active:scale-95 text-left w-full">
          <div className="w-14 h-14 bg-amber-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-amber-500 group-hover:text-white transition-colors flex-shrink-0 shadow-inner">⏳</div>
          <div className="overflow-hidden"><p className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest truncate">Alerta (60 dias)</p><h4 className="text-3xl font-black text-amber-500 tracking-tighter leading-none mt-1">{stats.s.expiring60}</h4></div>
        </button>
        <button onClick={() => handleDetailView('RECENT_30')} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-emerald-100 flex items-center gap-6 group hover:shadow-xl hover:-translate-y-1 transition-all active:scale-95 text-left w-full">
          <div className="w-14 h-14 bg-emerald-50 rounded-2xl flex items-center justify-center text-xl group-hover:bg-emerald-500 group-hover:text-white transition-colors flex-shrink-0 shadow-inner">🔥</div>
          <div className="overflow-hidden"><p className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest truncate">Realizados (30 dias)</p><h4 className="text-3xl font-black text-emerald-600 tracking-tighter leading-none mt-1">{stats.s.recentTrainings}</h4></div>
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-emerald-100 overflow-hidden hover:shadow-xl transition-shadow relative group">
           <h3 className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest mb-6 text-center">Saúde Normativa Global</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie data={stats.statusData} cx="50%" cy="50%" innerRadius={70} outerRadius={100} paddingAngle={8} dataKey="value" onClick={(data) => handlePieClick(data)} className="cursor-pointer">
                  {stats.statusData.map((e, i) => <Cell key={i} fill={e.color} stroke="#fff" strokeWidth={4} className="hover:opacity-80 transition-opacity" />)}
                </Pie>
                <Tooltip content={<CustomTooltip />} />
                <Legend verticalAlign="bottom" height={36} iconType="circle" wrapperStyle={{ fontSize: '9px', fontWeight: '900', textTransform: 'uppercase' }} />
              </PieChart>
            </ResponsiveContainer>
           </div>
        </div>

        <div className="bg-white p-8 rounded-[2.5rem] md:rounded-[3.5rem] shadow-sm border border-emerald-100 overflow-hidden hover:shadow-xl transition-shadow">
           <h3 className="text-[10px] font-black text-emerald-800/40 uppercase tracking-widest mb-6 text-center">Efetivo Capacitado por Setor</h3>
           <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart layout="vertical" data={stats.sectorData} margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" axisLine={false} tickLine={false} tick={{ fontSize: 9, fontWeight: 900, fill: '#1e293b' }} width={80} />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: 'rgba(16, 185, 129, 0.05)' }} />
                <Legend verticalAlign="top" align="right" wrapperStyle={{ fontSize: '9px', fontWeight: '900', textTransform: 'uppercase', paddingBottom: '20px' }} />
                <Bar dataKey="Total" fill="#e2e8f0" radius={[0, 10, 10, 0]} barSize={12} name="Total Equipe" />
                <Bar dataKey="Capacitados" fill="#10b981" radius={[0, 10, 10, 0]} barSize={12} name="Com Curso Válido" />
              </BarChart>
            </ResponsiveContainer>
           </div>
        </div>
      </div>

