             <div className="hidden print:block p-10 border-b-2 border-emerald-900 mb-8">
                <h1 className="text-3xl font-black uppercase italic text-emerald-900">Relatório de Conformidade: {detailModal.label}</h1>
                <p className="text-xs font-bold text-gray-500 uppercase tracking-widest mt-2">Documento Gerado em {new Date().toLocaleString()}</p>
             </div>

             <div className="flex-1 overflow-y-auto p-8 space-y-10 custom-scrollbar print:overflow-visible print:p-0">
                {detailModal.data.map((sec, idx) => (
                  <div key={idx} className="space-y-4 print:break-inside-avoid mb-12">
                    <div className="border-b dark:border-emerald-800 pb-2 flex items-center justify-between print:border-emerald-900">
                      <h4 className="font-black text-emerald-800 dark:text-emerald-400 uppercase tracking-widest italic print:text-emerald-900">{sec.sector}</h4>
                      <span className="text-[10px] font-black text-emerald-500 opacity-50">{sec.list.length} Registros</span>
                    </div>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-4 print:grid-cols-1">
                      {sec.list.map((item: any, i: number) => (
                        <div key={i} className="bg-emerald-50/20 dark:bg-emerald-900/10 border dark:border-emerald-800/30 p-5 rounded-3xl flex justify-between items-center group hover:bg-white dark:hover:bg-emerald-800/20 transition-all print:border-gray-200 print:bg-white">
                          <div>
                            <p className="text-xs font-black text-emerald-950 dark:text-white uppercase leading-tight">{item.name}</p>
                            <p className="text-[9px] font-bold text-emerald-600/60 uppercase tracking-widest mt-1">RE: {item.reg} • {item.role}</p>
                            <div className="flex gap-1 mt-2">
                              {item.courses.map((c: any) => (
                                <span key={c.cid} className="text-[8px] font-black bg-emerald-100 dark:bg-emerald-800 text-emerald-700 dark:text-emerald-300 px-2 py-0.5 rounded uppercase">{c.cid} - {c.days !== null ? (c.days < 0 ? `Vencido` : `${c.days}d`) : 'OK'}</span>
                              ))}
                            </div>
                          </div>
                          <div className="flex gap-1">
                             {item.isCipero && <span className="w-6 h-6 bg-emerald-500 text-white rounded flex items-center justify-center text-[10px] font-black shadow-sm">C</span>}
                             {item.isBrigadista && <span className="w-6 h-6 bg-red-500 text-white rounded flex items-center justify-center text-[10px] font-black shadow-sm">B</span>}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
             </div>

             <footer className="hidden print:block p-8 border-t text-center text-[9px] font-black text-gray-400 uppercase tracking-widest">
                Controle Gerencial SST Cloud - Sistema de Gestão Normativa
             </footer>
          </div>
        </div>
      )}
    </div>
  );
};

