export const DEPT_COLORS: string[] = [
  '#064E3B', '#10B981', '#3B82F6', '#6366F1', '#8B5CF6', 
  '#EC4899', '#F43F5E', '#F97316', '#EAB308', '#22C55E'
];

export const getDeptColor = (deptName: string) => {
  let hash = 0;
  for (let i = 0; i < deptName.length; i++) {
    hash = deptName.charCodeAt(i) + ((hash << 5) - hash);
  }
  return DEPT_COLORS[Math.abs(hash) % DEPT_COLORS.length];
};

import { TrainingStatus, TrainingRecord, Employee, EmployeeSituation } from '../types';
import { NR_COURSES } from '../constants';

const parseFlexibleDate = (dateStr: any): Date | null => {
  if (!dateStr || dateStr === '-' || String(dateStr).toLowerCase() === 'n/a' || dateStr === '') return null;
  if (dateStr instanceof Date) return isNaN(dateStr.getTime()) ? null : dateStr;
  const str = String(dateStr).trim();

  if (/^\d{4}-\d{2}-\d{2}/.test(str)) {
    const d = new Date(str);
    return isNaN(d.getTime()) ? null : d;
  }

  if (/^\d{1,2}\/\d{1,2}\/\d{4}/.test(str)) {
    const [day, month, year] = str.split('/').map(Number);
    const d = new Date(year, month - 1, day);
    return isNaN(d.getTime()) ? null : d;
  }

  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
};

export const getDaysRemaining = (expiryDate: string | undefined): number | null => {
  if (!expiryDate) return null;
  const today = new Date();
  today.setHours(0, 0, 0, 0);
  const expiry = new Date(expiryDate);
  expiry.setHours(0, 0, 0, 0);
  const diffTime = expiry.getTime() - today.getTime();
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

export const getExpiryDate = (completionDate: string | undefined, validityYears: number | null): string | undefined => {
  const dateObj = parseFlexibleDate(completionDate);
  if (!dateObj || validityYears === null) return undefined;
  const expiry = new Date(dateObj);
  expiry.setFullYear(expiry.getFullYear() + validityYears);
  return expiry.toISOString().split('T')[0];
};

export const calculateTrainingStatus = (completionDate: string | undefined, validityYears: number | null): TrainingStatus => {
  const dateObj = parseFlexibleDate(completionDate);
  if (!dateObj) return 'NOT_TRAINED';
  if (validityYears === null) return 'VALID';
  const expiryStr = getExpiryDate(completionDate, validityYears);
  const daysRemaining = getDaysRemaining(expiryStr);
  if (daysRemaining === null) return 'VALID';
  if (daysRemaining < 0) return 'EXPIRED';
  if (daysRemaining <= 60) return 'EXPIRING';
  return 'VALID';
};

const normalizeKey = (key: string) => 
  String(key || '').toUpperCase()
     .normalize("NFD")
     .replace(/[\u0300-\u036f]/g, "") 
     .replace(/[-_\s.]/g, ""); 

export const formatEmployeeData = (rawData: any[]): Employee[] => {
  if (!Array.isArray(rawData)) return [];
  return rawData.map((row, idx) => {
    const trainings: Record<string, TrainingRecord> = {};
    const normalizedRow: any = {};

    Object.keys(row).forEach(k => {
      normalizedRow[normalizeKey(k)] = row[k];
    });

    NR_COURSES.forEach(course => {
      const courseKey = normalizeKey(course.id);
      const completionValue = normalizedRow[courseKey];
      const status = calculateTrainingStatus(completionValue, course.validityYears);
      const expiryDate = getExpiryDate(completionValue, course.validityYears);
      const parsedDate = parseFlexibleDate(completionValue);

      trainings[course.id] = {
        courseId: course.id,
        completionDate: parsedDate ? parsedDate.toISOString().split('T')[0] : undefined,
        expiryDate,
        status,
      };
    });

    const registration = String(normalizedRow['MATRICULA'] || normalizedRow['REGISTRO'] || normalizedRow['RE'] || `ID-${idx}`).trim();
    const id = row.id || registration; 

    // Mapeamento da Situação
    let situation: EmployeeSituation = 'ATIVO';
    const sitValue = String(normalizedRow['SITUACAO'] || normalizedRow['STATUS'] || '').toUpperCase().trim();
    if (sitValue === 'DEMITIDO' || sitValue === 'DEMITIDA' || sitValue === 'DESLIGADO' || sitValue === 'DESLIGADA') situation = 'DEMITIDO';
    else if (sitValue === 'AFASTADO' || sitValue === 'AFASTADA' || sitValue === 'LICENCA') situation = 'AFASTADO';
    // Se vazio ou qualquer outro valor não reconhecido, assume ATIVO conforme regra 2

    return {
      id: id,
      name: normalizedRow['NOMECOMPLETO'] || normalizedRow['NOME'] || 'Sem Nome',
      registration: registration,
      role: normalizedRow['FUNCAO'] || normalizedRow['CARGO'] || '-',
      setor: normalizedRow['SETOR'] || normalizedRow['DEPARTAMENTO'] || '-',
      company: normalizedRow['EMPRESA'] || normalizedRow['UNIDADE'] || 'Empresa Padrão',
      photoUrl: normalizedRow['FOTO'] || normalizedRow['URLFOTO'] || undefined,
      situation: situation,
      trainings,
    };
  });
};

import React, { useState, useMemo } from 'react';
import { Employee, EmployeeSituation } from '../types';
import { STATUS_CONFIG, NR_COURSES, SITUATION_CONFIG } from '../constants';
import { calculateTrainingStatus, getExpiryDate, getDaysRemaining, formatEmployeeData } from '../utils/calculations';
import { StorageService } from '../services/storage';

interface EmployeeViewProps {
  employees: Employee[];
  onUpdate: () => void;
  isAdmin: boolean;
}

const EmployeeView: React.FC<EmployeeViewProps> = ({ employees, onUpdate, isAdmin }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedSetor, setSelectedSetor] = useState('TODOS');
  const [selectedCompany, setSelectedCompany] = useState('TODAS');
  const [selectedSituation, setSelectedSituation] = useState<'TODAS' | EmployeeSituation>('TODAS');
  const [editingEmp, setEditingEmp] = useState<Employee | null>(null);
  const [showBulkImport, setShowBulkImport] = useState(false);

  // Estados para Importação em Massa
  const [importText, setImportText] = useState('');
  const [importPreview, setImportPreview] = useState<Employee[]>([]);
  const [isImporting, setIsImporting] = useState(false);

  // Normalização para buscas e filtros
  const simplify = (text: any) => 
    String(text || '')
      .toUpperCase()
      .trim()
      .normalize("NFD")
      .replace(/[\u0300-\u036f]/g, "");

  // Listas para os filtros
  const companies = useMemo(() => {
    const set = new Set(employees.map(e => simplify(e.company || 'EMPRESA PADRÃO')));
    return ['TODAS', ...Array.from(set)].sort();
  }, [employees]);

  const setores = useMemo(() => {
    const pool = selectedCompany === 'TODAS' 
      ? employees 
      : employees.filter(e => simplify(e.company) === selectedCompany);

    const set = new Set(pool.map(e => simplify(e.setor || 'GERAL')));
    return ['TODOS', ...Array.from(set)].sort();
  }, [employees, selectedCompany]);

  // Lógica de Filtragem e Ordenação Alfabética
  const filteredEmployees = useMemo(() => {
    const term = simplify(searchTerm);
    return employees
      .filter(emp => {
        const empComp = simplify(emp.company || 'EMPRESA PADRÃO');
        const empSet = simplify(emp.setor || 'GERAL');
        const empName = simplify(emp.name);
        const empReg = simplify(emp.registration);

        const matchesCompany = selectedCompany === 'TODAS' || empComp === selectedCompany;
        const matchesSetor = selectedSetor === 'TODOS' || empSet === selectedSetor;
        const matchesSituation = selectedSituation === 'TODAS' || emp.situation === selectedSituation;
        const matchesSearch = !term || empName.includes(term) || empReg.includes(term);

        return matchesCompany && matchesSetor && matchesSearch && matchesSituation;
      })
      .sort((a, b) => a.name.localeCompare(b.name));
  }, [employees, searchTerm, selectedSetor, selectedCompany, selectedSituation]);

  // Função para salvar edição
  const handleSaveEdit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!editingEmp || !isAdmin) return;
    try {
      await StorageService.updateEmployee(editingEmp);
      setEditingEmp(null);
      onUpdate();
      alert("Alterações salvas com sucesso!");
    } catch (err) {
      alert("Erro ao salvar no banco de dados.");
    }
  };

  // Lógica de Datas para o Formulário
  const updateTrainingDate = (courseId: string, date: string) => {
    if (!editingEmp || !isAdmin) return;
    const course = NR_COURSES.find(c => c.id === courseId);
    if (!course) return;

    const newStatus = calculateTrainingStatus(date, course.validityYears);
    const newExpiry = getExpiryDate(date, course.validityYears);

    const updatedTrainings = {
      ...editingEmp.trainings,
      [courseId]: { 
        courseId, 
        completionDate: date || undefined, 
        expiryDate: newExpiry, 
        status: newStatus 
      }
    };
    setEditingEmp({ ...editingEmp, trainings: updatedTrainings });
  };

  const isCipero = (emp: Employee) => ['VALID', 'EXPIRING'].includes(emp.trainings['NR05']?.status);
  const isBrigadista = (emp: Employee) => ['VALID', 'EXPIRING'].includes(emp.trainings['NR23']?.status);

